const LANE_A_THETA_KTRACE_REL_TOL = 1e-6;

const ensureRequiredYorkViews = (
  views: HullScientificRenderView[],
): HullScientificRenderView[] => {
  const deduped = Array.from(new Set(views));
  for (const requiredView of REQUIRED_YORK_VIEWS) {
    if (!deduped.includes(requiredView)) deduped.push(requiredView);
  }
  return deduped;
};

const readArgValue = (name: string, argv = process.argv.slice(2)): string | undefined => {
  const index = argv.findIndex((value) => value === name || value.startsWith(`${name}=`));
  if (index < 0) return undefined;
  if (argv[index].includes("=")) return argv[index].split("=", 2)[1];
  return argv[index + 1];
};

const hasArg = (name: string, argv = process.argv.slice(2)): boolean =>
  argv.some((value) => value === name || value.startsWith(`${name}=`));

const parseYorkViews = (value: string | undefined): HullScientificRenderView[] => {
  if (!value || value.trim().length === 0) return [...DEFAULT_YORK_VIEWS];
  const parsed = value
    .split(",")
    .map((entry) => entry.trim() as HullScientificRenderView)
    .filter((entry) => entry.length > 0);
  if (parsed.length === 0) return [...DEFAULT_YORK_VIEWS];
  const deduped = Array.from(new Set(parsed));
  const invalid = deduped.filter((entry) => !VALID_YORK_VIEW_SET.has(entry));
  if (invalid.length > 0) {
    throw new Error(
      `invalid_york_views: ${invalid.join(", ")} | valid=${Array.from(VALID_YORK_VIEW_SET).join(",")}`,
    );
  }
  return ensureRequiredYorkViews(deduped);
};

const toFiniteNumber = (value: unknown): number | null => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const parsePositiveInt = (value: string | undefined, fallback: number): number => {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  const rounded = Math.floor(parsed);
  return rounded > 0 ? rounded : fallback;
};

const parseBooleanArg = (value: string | undefined, fallback = false): boolean => {
  if (typeof value !== "string") return fallback;
  const normalized = value.trim().toLowerCase();
  if (normalized.length === 0) return fallback;
  if (["1", "true", "yes", "on"].includes(normalized)) return true;
  if (["0", "false", "no", "off"].includes(normalized)) return false;
  return fallback;
};

const asRecord = (value: unknown): Record<string, unknown> =>
  value && typeof value === "object" && !Array.isArray(value) ? (value as Record<string, unknown>) : {};

const asText = (value: unknown): string | null => {
  if (typeof value === "string") {
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }
  if (typeof value === "number" || typeof value === "bigint") return String(value);
  return null;
};

const normalizePath = (filePath: string): string => filePath.replace(/\\/g, "/");

const ensureDirForFile = (filePath: string): void => {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
};

const readJsonArtifact = <T>(filePath: string, expectedArtifactType?: string): T => {
  const parsed = JSON.parse(fs.readFileSync(filePath, "utf8")) as T;
  if (!expectedArtifactType) return parsed;
  const artifactType = asText(asRecord(parsed).artifactType);
  if (artifactType !== expectedArtifactType) {
    throw new Error(
      `unexpected_artifact_type:${normalizePath(filePath)}:${artifactType ?? "null"}:${expectedArtifactType}`,
    );
  }
  return parsed;
};

const readJsonArtifactIfPresent = <T>(
  filePath: string,
  expectedArtifactType?: string,
): T | null => {
  if (!fs.existsSync(filePath)) {
    return null;
  }
  return readJsonArtifact<T>(filePath, expectedArtifactType);
};

const writeJsonArtifact = (filePath: string, value: unknown): void => {
  ensureDirForFile(filePath);
  fs.writeFileSync(filePath, `${JSON.stringify(value, null, 2)}\n`);
};

const writeMarkdownArtifact = (filePath: string, markdown: string): void => {
  ensureDirForFile(filePath);
  fs.writeFileSync(filePath, `${markdown}\n`);
};

const writePublishedArtifactSurface = <T>(args: {
  artifact: T;
  markdown: string;
  outJsonPath: string;
  latestJsonPath: string;
  outMdPath: string;
  latestMdPath: string;
}): {
  outJsonPath: string;
  latestJsonPath: string;
  outMdPath: string;
  latestMdPath: string;
  artifact: T;
} => {
  writeJsonArtifact(args.outJsonPath, args.artifact);
  writeJsonArtifact(args.latestJsonPath, args.artifact);
  writeMarkdownArtifact(args.outMdPath, args.markdown);
  writeMarkdownArtifact(args.latestMdPath, args.markdown);
  return {
    outJsonPath: args.outJsonPath,
    latestJsonPath: args.latestJsonPath,
    outMdPath: args.outMdPath,
    latestMdPath: args.latestMdPath,
    artifact: args.artifact,
  };
};

const matchesPublicationRoot = (
  candidatePath: string,
  expectedPath: string,
): boolean => path.resolve(candidatePath) === path.resolve(expectedPath);

const shouldPublishSelectedShiftLapseDedicatedResearchSurface = (args: {
  artifactRootDir: string;
  auditRootDir: string;
  shiftLapseProfileId: string;
}): boolean =>
  matchesPublicationRoot(args.artifactRootDir, SELECTED_FAMILY_FULL_SOLVE_DIR) &&
  matchesPublicationRoot(args.auditRootDir, SELECTED_FAMILY_DOC_AUDIT_DIR) &&
  args.shiftLapseProfileId === DEFAULT_SELECTED_SHIFT_LAPSE_PROFILE_ID;

const shouldPublishSelectedShiftLapseEnvelopeDedicatedResearchSurface = (args: {
  selectedFamilyArtifactRootDir: string;
  selectedFamilyAuditRootDir: string;
  artifactRootDir: string;
  auditRootDir: string;
  shiftLapseProfileId: string | null;
}): boolean =>
  matchesPublicationRoot(
    args.selectedFamilyArtifactRootDir,
    SELECTED_FAMILY_FULL_SOLVE_DIR,
  ) &&
  matchesPublicationRoot(
    args.selectedFamilyAuditRootDir,
    SELECTED_FAMILY_DOC_AUDIT_DIR,
  ) &&
  matchesPublicationRoot(
    args.artifactRootDir,
    SELECTED_SHIFT_LAPSE_ENVELOPE_ARTIFACT_DIR,
  ) &&
  matchesPublicationRoot(
    args.auditRootDir,
    SELECTED_SHIFT_LAPSE_ENVELOPE_AUDIT_DIR,
  ) &&
  args.shiftLapseProfileId === DEFAULT_SELECTED_SHIFT_LAPSE_PROFILE_ID;

const computeArtifactJsonChecksum = (value: unknown): string | null => {
  const checksum = asText(asRecord(value).checksum);
  if (checksum && /^[a-f0-9]{64}$/i.test(checksum)) {
    return checksum.toLowerCase();
  }
  try {
    return crypto
      .createHash("sha256")
      .update(`${JSON.stringify(value, null, 2)}\n`)
      .digest("hex");
  } catch {
    return null;
  }
};

const computeJsonFileChecksum = (filePath: string): string | null => {
  try {
    return crypto.createHash("sha256").update(fs.readFileSync(filePath)).digest("hex");
  } catch {
    return null;
  }
};

const isGitIgnored = (
  filePath: string,
  gitRepoRootPath: string = process.cwd(),
): boolean => {
  try {
    execFileSync("git", ["check-ignore", "-q", "--no-index", "--", normalizePath(filePath)], {
      cwd: gitRepoRootPath,
      stdio: "ignore",
    });
    return true;
  } catch (error) {
    if (error && typeof error === "object" && "status" in error) {
      return Number((error as { status?: number }).status) === 0;
    }
    return false;
  }
};

const getGitTrackedState = (
  filePath: string,
  gitRepoRootPath: string = process.cwd(),
): "tracked" | "untracked" | "unknown" => {
  try {
    execFileSync("git", ["ls-files", "--error-unmatch", "--", normalizePath(filePath)], {
      cwd: gitRepoRootPath,
      stdio: "ignore",
    });
    return "tracked";
  } catch (error) {
    if (error && typeof error === "object" && "status" in error) {
      const status = Number((error as { status?: number }).status);
      if (status === 1) {
        return "untracked";
      }
    }
    return "unknown";
  }
};

const getGitCleanLandingState = (
  filePaths: string[],
  gitRepoRootPath: string = process.cwd(),
): "clean" | "dirty" | "unknown" => {
  const normalizedPaths = Array.from(
    new Set(filePaths.map((entry) => normalizePath(entry)).filter((entry) => entry.length > 0)),
  );
  if (normalizedPaths.length === 0) {
    return "unknown";
  }
  try {
    const output = execFileSync(
      "git",
      ["status", "--porcelain", "--untracked-files=all", "--", ...normalizedPaths],
      {
        cwd: gitRepoRootPath,
        encoding: "utf8",
        stdio: ["ignore", "pipe", "ignore"],
      },
    );
    return output.trim().length === 0 ? "clean" : "dirty";
  } catch {
    return "unknown";
  }
};

let activeProofSurfacePublicationLock:
  | {
      lockPath: string;
      fd: number;
      depth: number;
    }
  | null = null;

const withProofSurfacePublicationLock = async <T>(args: {
  lockPath?: string;
  operation: string;
  fn: () => Promise<T>;
}): Promise<T> => {
  const resolvedLockPath = path.resolve(
    args.lockPath ?? DEFAULT_PROOF_SURFACE_PUBLICATION_LOCK_PATH,
  );
  if (activeProofSurfacePublicationLock?.lockPath === resolvedLockPath) {
    activeProofSurfacePublicationLock.depth += 1;
    try {
      return await args.fn();
    } finally {
      activeProofSurfacePublicationLock.depth -= 1;
    }
  }
  ensureDirForFile(resolvedLockPath);
  let fd: number;
  try {
    fd = fs.openSync(resolvedLockPath, "wx");
  } catch (error) {
    if ((error as NodeJS.ErrnoException | null)?.code === "EEXIST") {
      throw new Error(
        `proof_surface_publication_locked:${normalizePath(resolvedLockPath)}:${args.operation}`,
      );
    }
    throw error;
  }
  const lockPayload = {
    operation: args.operation,
    pid: process.pid,
    acquiredAt: new Date().toISOString(),
  };
  fs.writeFileSync(fd, `${JSON.stringify(lockPayload, null, 2)}\n`);
  activeProofSurfacePublicationLock = {
    lockPath: resolvedLockPath,
    fd,
    depth: 1,
  };
  try {
    return await args.fn();
  } finally {
    const handle = activeProofSurfacePublicationLock;
    activeProofSurfacePublicationLock = null;
    try {
      if (handle) fs.closeSync(handle.fd);
    } finally {
      if (fs.existsSync(resolvedLockPath)) {
        fs.unlinkSync(resolvedLockPath);
      }
    }
  }
};

const syncLegacyAliasFile = (sourcePath: string, aliasPath: string): void => {
  if (path.resolve(sourcePath) === path.resolve(aliasPath)) return;
  ensureDirForFile(aliasPath);
  fs.copyFileSync(sourcePath, aliasPath);
};

const syncLegacyAliasDirectory = (sourceDir: string, aliasDir: string): void => {
  if (path.resolve(sourceDir) === path.resolve(aliasDir)) return;
  const resolvedSourceDir = path.resolve(sourceDir);
  const resolvedAliasDir = path.resolve(aliasDir);
  if (!resolvedAliasDir.startsWith(path.resolve(FULL_SOLVE_DIR))) {
    throw new Error(`Refusing to sync alias directory outside ${FULL_SOLVE_DIR}: ${aliasDir}`);
  }
  if (fs.existsSync(resolvedAliasDir)) {
    fs.rmSync(resolvedAliasDir, { recursive: true, force: true });
  }
  fs.mkdirSync(path.dirname(resolvedAliasDir), { recursive: true });
  fs.cpSync(resolvedSourceDir, resolvedAliasDir, { recursive: true, force: true });
};

