const computeDeterministicHash = (value: unknown): string =>
  crypto.createHash("sha256").update(stableStringify(value)).digest("hex");

const resolveLatestG4FirstDivergencePath = (
  explicitPath?: string,
): string | null => {
  const candidate = explicitPath ?? DEFAULT_G4_FIRST_DIVERGENCE_PATH;
  const resolvedCandidate = resolveArtifactPath(candidate);
  if (resolvedCandidate && fs.existsSync(resolvedCandidate)) {
    return resolvedCandidate;
  }
  if (!fs.existsSync(FULL_SOLVE_DIR)) return null;
  const files = fs
    .readdirSync(FULL_SOLVE_DIR, { withFileTypes: true })
    .filter((entry) => entry.isFile())
    .map((entry) => entry.name)
    .filter((name) => /^g4-first-divergence-\d{4}-\d{2}-\d{2}\.json$/u.test(name))
    .sort((a, b) => b.localeCompare(a));
  if (files.length === 0) return null;
  return path.resolve(path.join(FULL_SOLVE_DIR, files[0]));
};

const buildSourceHash = (value: unknown): string | null => {
  if (value == null) return null;
  try {
    return computeDeterministicHash(value);
  } catch {
    return null;
  }
};

const determineSourceStageStatus = (
  canonicalValue: unknown,
  recoveryValue: unknown,
  authorityValue?: unknown,
): SourceStageComponentStatus => {
  const canonicalPresent = canonicalValue != null;
  const recoveryPresent = recoveryValue != null;
  const authorityPresent = authorityValue != null;
  if (!canonicalPresent && !recoveryPresent) {
    return authorityPresent ? "inferred" : "missing";
  }
  if (canonicalPresent && recoveryPresent) {
    return valuesEquivalent(canonicalValue, recoveryValue) ? "matched" : "drifted";
  }
  if (!authorityPresent) return "missing";
  if (canonicalPresent && valuesEquivalent(canonicalValue, authorityValue)) return "inferred";
  if (recoveryPresent && valuesEquivalent(recoveryValue, authorityValue)) return "inferred";
  return "drifted";
};

const determineAuthorityAlignmentStatus = (
  authoritativeValue: unknown,
  authorityValue: unknown,
): SourceStageComponentStatus => {
  const authoritativePresent = authoritativeValue != null;
  const authorityPresent = authorityValue != null;
  if (!authoritativePresent && !authorityPresent) return "missing";
  if (authoritativePresent && authorityPresent) {
    return valuesEquivalent(authoritativeValue, authorityValue) ? "matched" : "drifted";
  }
  return "inferred";
};

const resolveMetricFamilyFromSourceRef = (value: string | null): string | null => {
  const text = value?.toLowerCase() ?? "";
  if (!text) return null;
  if (text.includes(".natario_sdf.")) return "natario_sdf";
  if (text.includes(".natario.") || text.includes(".irrotational.")) return "natario";
  if (text.includes(".alcubierre.")) return "alcubierre";
  if (text.includes(".vdb.")) return "vdb";
  return null;
};

const detectMixedSourceAuthority = (authorities: SourceStageAuthorityRecord[]): boolean => {
  const readinessRelevant = authorities.filter(
    (entry) =>
      entry.current_role === "authoritative" &&
      entry.authoritative_for.includes("metricT00Si_Jm3"),
  );
  return readinessRelevant.length > 1;
};

const asBooleanOrNull = (value: unknown): boolean | null => {
  if (typeof value === "boolean") return value;
  return null;
};

const parseIsoToEpochMs = (value: string | null): number | null => {
  if (!value) return null;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const numericallyEqual = (
  a: number | null,
  b: number | null,
  relTol: number,
  absTol: number,
): boolean => {
  if (a == null || b == null) return false;
  const delta = Math.abs(a - b);
  const denom = Math.max(Math.abs(a), Math.abs(b), 1);
  return delta <= Math.max(absTol, relTol * denom);
};

const computeComparisonDelta = (
  directValue: unknown,
  reconstructedValue: unknown,
): { delta: number | null; relativeDelta: number | null } => {
  const direct = toFiniteNumber(directValue);
  const reconstructed = toFiniteNumber(reconstructedValue);
  if (direct == null || reconstructed == null) {
    return { delta: null, relativeDelta: null };
  }
  const delta = reconstructed - direct;
  const relativeDelta = delta / Math.max(Math.abs(direct), Math.abs(reconstructed), 1);
  return { delta, relativeDelta };
};

const classifySourceFormulaComparisonEntryStatus = (
  directValue: unknown,
  reconstructedValue: unknown,
): SourceFormulaComparisonEntryStatus => {
  if (directValue == null && reconstructedValue == null) return "not_comparable";
  if (directValue == null) return "missing_direct_input";
  if (reconstructedValue == null) return "missing_reconstructed_input";
  return valuesEquivalent(directValue, reconstructedValue) ? "matched" : "mismatched";
};

const buildSourceFormulaComparisonEntry = (args: {
  id: string;
  directValue: unknown;
  reconstructedValue: unknown;
  units?: string | null;
  note?: string | null;
}): SourceFormulaResolvedInputComparison => {
  const { delta, relativeDelta } = computeComparisonDelta(
    args.directValue,
    args.reconstructedValue,
  );
  return {
    inputId: args.id,
    directValue: args.directValue ?? null,
    reconstructedValue: args.reconstructedValue ?? null,
    delta,
    relativeDelta,
    units: args.units ?? null,
    status: classifySourceFormulaComparisonEntryStatus(
      args.directValue,
      args.reconstructedValue,
    ),
    note: args.note ?? null,
  };
};

const buildSourceFormulaTermComparison = (args: {
  termId: string;
  directValue: unknown;
  reconstructedValue: unknown;
  units?: string | null;
  note?: string | null;
}): SourceFormulaTermComparison => {
  const { delta, relativeDelta } = computeComparisonDelta(
    args.directValue,
    args.reconstructedValue,
  );
  return {
    termId: args.termId,
    directValue: args.directValue ?? null,
    reconstructedValue: args.reconstructedValue ?? null,
    delta,
    relativeDelta,
    units: args.units ?? null,
    status: classifySourceFormulaComparisonEntryStatus(
      args.directValue,
      args.reconstructedValue,
    ),
    note: args.note ?? null,
  };
};

const resolveSourceFormulaClass = (
  metricT00GeomSource: string | null,
  metricT00Derivation: string | null,
): SourceFormulaClass => {
  const geom = (metricT00GeomSource ?? "").trim().toLowerCase();
  const derivation = (metricT00Derivation ?? "").trim().toLowerCase();
  if (geom.includes("direct_metric_pipeline")) return "direct_metric_pipeline";
  if (geom.includes("derived_metric_family")) return "derived_metric_family";
  if (derivation.includes("forward_shift_to_k_to_rho_e")) {
    return "forward_shift_to_K_to_rho_E";
  }
  if (derivation.includes("reconstruct") || derivation.includes("decomposition")) {
    return "reconstructed_from_decomposition";
  }
  if (derivation.length > 0) return "reconstructed_from_decomposition";
  return "unknown";
};

const resolveSourceFormulaDerivationMode = (args: {
  formulaClass: SourceFormulaClass;
  metricT00Derivation: string | null;
  metricT00GeomSource: string | null;
}): SourceFormulaDerivationMode => {
  if (args.formulaClass === "direct_metric_pipeline") return "direct";
  if (args.formulaClass === "derived_metric_family") return "derived";
  if (
    args.formulaClass === "forward_shift_to_K_to_rho_E" ||
    args.formulaClass === "reconstructed_from_decomposition"
  ) {
    return "reconstructed";
  }
  if ((args.metricT00GeomSource ?? "").trim().length > 0) return "derived";
  if ((args.metricT00Derivation ?? "").trim().length > 0) return "reconstructed";
  return "unknown";
};

const computeSourceFormulaAuditChecksum = (
  payload: Nhm2SourceFormulaAuditArtifact,
): string => {
  const copy = JSON.parse(JSON.stringify(payload)) as Record<string, unknown>;
  delete copy.generatedAt;
  delete copy.checksum;
  return crypto.createHash("sha256").update(stableStringify(copy)).digest("hex");
};

const buildSourceStageNumericGapDecomposition = (args: {
  canonicalRecord: Record<string, unknown>;
  recoveryRecord: Record<string, unknown>;
  recoveryRoot: Record<string, unknown>;
  relTol: number;
  absTol: number;
  authorityNormalization: string | null;
  authorityUnit: string | null;
  familyCanonicalFromRef: string | null;
  familyRecoveryFromRef: string | null;
  familyAuthority: string | null;
  metricSelectorStatus: SourceStageComponentStatus;
}): SourceStageNumericGapDecomposition => {
  const canonicalMetricT00Si = parseMetricT00Si([
    args.canonicalRecord.metricT00Si_Jm3,
    args.canonicalRecord.metricT00SiFromGeom_Jm3,
    args.canonicalRecord.metricT00SiFromGeom,
  ]);
  const recoveryMetricT00Si = parseMetricT00Si([
    args.recoveryRecord.metricT00Si_Jm3,
    args.recoveryRecord.metricT00SiFromGeom_Jm3,
    args.recoveryRecord.metricT00SiFromGeom,
    args.recoveryRecord.metricStressRhoSiMean_Jm3,
  ]);
  const numericGapPresent = (() => {
    if (canonicalMetricT00Si == null || recoveryMetricT00Si == null) return false;
    return !numericallyEqual(canonicalMetricT00Si, recoveryMetricT00Si, args.relTol, args.absTol);
  })();
  const deltaAbs =
    canonicalMetricT00Si != null && recoveryMetricT00Si != null
      ? Math.abs(canonicalMetricT00Si - recoveryMetricT00Si)
      : null;
  const deltaRel =
    canonicalMetricT00Si != null && recoveryMetricT00Si != null
      ? deltaAbs / Math.max(Math.abs(canonicalMetricT00Si), Math.abs(recoveryMetricT00Si), 1)
      : null;
  const ratioCanonicalOverRecovery =
    canonicalMetricT00Si != null &&
    recoveryMetricT00Si != null &&
    Math.abs(recoveryMetricT00Si) > 0
      ? canonicalMetricT00Si / recoveryMetricT00Si
      : null;

  const canonicalUnit =
    asText(args.canonicalRecord.metricT00UnitSystem) ??
    (canonicalMetricT00Si != null ? "SI_inferred_jm3" : null);
  const recoveryUnit =
    asText(args.recoveryRecord.metricT00UnitSystem) ??
    (recoveryMetricT00Si != null ? "SI_inferred_jm3" : null);
  const canonicalMetricNorm = asText(args.canonicalRecord.metricT00Normalization);
  const recoveryMetricNorm = asText(args.recoveryRecord.metricT00Normalization);
  const canonicalQeiNorm = asText(args.canonicalRecord.qeiSamplingNormalization);
  const recoveryQeiNorm = asText(args.recoveryRecord.qeiSamplingNormalization);
  const canonicalQeiRenorm = asText(args.canonicalRecord.qeiRenormalizationScheme);
  const recoveryQeiRenorm = asText(args.recoveryRecord.qeiRenormalizationScheme);
  const canonicalDerivation = asText(args.canonicalRecord.metricT00Derivation);
  const recoveryDerivation = asText(args.recoveryRecord.metricT00Derivation);
  const canonicalGeomSource = asText(args.canonicalRecord.metricT00GeomSource);
  const recoveryContractStatus = asText(args.recoveryRecord.metricT00ContractStatus);
  const canonicalTimestamp = parseIsoToEpochMs(asText(args.canonicalRecord.timestamp));
  const recoveryTimestamp = parseIsoToEpochMs(asText(args.recoveryRoot.generatedAt));
  const artifactAgeDeltaMs =
    canonicalTimestamp != null && recoveryTimestamp != null
      ? Math.abs(canonicalTimestamp - recoveryTimestamp)
      : null;
  const canonicalRhoMetric = parseMetricT00Si([
    args.canonicalRecord.rhoMetric_Jm3,
    args.canonicalRecord.metricStressRhoSiMean_Jm3,
  ]);
  const recoveryRhoMetric = parseMetricT00Si([
    args.recoveryRecord.rhoMetric_Jm3,
    args.recoveryRecord.metricStressRhoSiMean_Jm3,
  ]);
  const canonicalMatchesRhoMetric = numericallyEqual(
    canonicalMetricT00Si,
    canonicalRhoMetric,
    args.relTol,
    args.absTol,
  );
  const recoveryMatchesRhoMetric = numericallyEqual(
    recoveryMetricT00Si,
    recoveryRhoMetric,
    args.relTol,
    args.absTol,
  );

  const candidates: SourceStageNumericGapCandidate[] = [];
  const addCandidate = (
    candidate_id: SourceStageNumericGapCandidateId,
    status: SourceStageNumericGapCandidateStatus,
    estimated_explanatory_power: number,
    evidence: string[],
  ): void => {
    candidates.push({ candidate_id, status, estimated_explanatory_power, evidence });
  };

  const selectorFamilyMismatch =
    args.familyCanonicalFromRef != null &&
    args.familyAuthority != null &&
    args.familyCanonicalFromRef !== args.familyAuthority;
  addCandidate(
    "selector_family_mismatch",
    selectorFamilyMismatch
      ? "supported"
      : args.familyCanonicalFromRef != null && args.familyAuthority != null
        ? "ruled_out"
        : "insufficient_evidence",
    selectorFamilyMismatch ? 0.95 : 0.05,
    [
      `canonical.family=${args.familyCanonicalFromRef ?? "null"}`,
      `recovery.family=${args.familyRecoveryFromRef ?? "null"}`,
      `authority.family=${args.familyAuthority ?? "null"}`,
      `metric_selector_status=${args.metricSelectorStatus}`,
    ],
  );

  const unitMismatch =
    canonicalUnit != null && recoveryUnit != null && canonicalUnit !== recoveryUnit;
  addCandidate(
    "unit_conversion_mismatch",
    unitMismatch
      ? "supported"
      : canonicalUnit == null || recoveryUnit == null
        ? "insufficient_evidence"
        : "ruled_out",
    unitMismatch ? 0.85 : 0.1,
    [
      `canonical.unit=${canonicalUnit ?? "null"}`,
      `recovery.unit=${recoveryUnit ?? "null"}`,
      `authority.unit=${args.authorityUnit ?? "null"}`,
    ],
  );

  const normalizationMismatch =
    (canonicalMetricNorm != null &&
      recoveryMetricNorm != null &&
      canonicalMetricNorm !== recoveryMetricNorm) ||
    (canonicalQeiNorm != null && recoveryQeiNorm != null && canonicalQeiNorm !== recoveryQeiNorm) ||
    (canonicalQeiRenorm != null &&
      recoveryQeiRenorm != null &&
      canonicalQeiRenorm !== recoveryQeiRenorm);
  addCandidate(
    "normalization_scale_mismatch",
    normalizationMismatch
      ? "supported"
      : canonicalMetricNorm == null &&
          recoveryMetricNorm == null &&
          canonicalQeiNorm == recoveryQeiNorm &&
          canonicalQeiRenorm == recoveryQeiRenorm
        ? "ruled_out"
        : "insufficient_evidence",
    normalizationMismatch ? 0.8 : 0.12,
    [
      `canonical.metricNormalization=${canonicalMetricNorm ?? "null"}`,
      `recovery.metricNormalization=${recoveryMetricNorm ?? "null"}`,
      `authority.metricNormalization=${args.authorityNormalization ?? "null"}`,
      `canonical.qeiSamplingNormalization=${canonicalQeiNorm ?? "null"}`,
      `recovery.qeiSamplingNormalization=${recoveryQeiNorm ?? "null"}`,
      `canonical.qeiRenormalizationScheme=${canonicalQeiRenorm ?? "null"}`,
      `recovery.qeiRenormalizationScheme=${recoveryQeiRenorm ?? "null"}`,
    ],
  );

  const floorClampMismatch =
    asBooleanOrNull(args.canonicalRecord.boundFloorApplied) !==
      asBooleanOrNull(args.recoveryRecord.boundFloorApplied) ||
    asBooleanOrNull(args.canonicalRecord.g4FloorDominated) !==
      asBooleanOrNull(args.recoveryRecord.g4FloorDominated) ||
    !valuesEquivalent(args.canonicalRecord.marginRatioClamped, args.recoveryRecord.marginRatioClamped);
  addCandidate(
    "hidden_policy_or_floor_mismatch",
    floorClampMismatch ? "supported" : "ruled_out",
    floorClampMismatch ? 0.55 : 0.05,
    [
      `canonical.boundFloorApplied=${String(asBooleanOrNull(args.canonicalRecord.boundFloorApplied))}`,
      `recovery.boundFloorApplied=${String(asBooleanOrNull(args.recoveryRecord.boundFloorApplied))}`,
      `canonical.g4FloorDominated=${String(asBooleanOrNull(args.canonicalRecord.g4FloorDominated))}`,
      `recovery.g4FloorDominated=${String(asBooleanOrNull(args.recoveryRecord.g4FloorDominated))}`,
      `canonical.marginRatioClamped=${String(toFiniteNumber(args.canonicalRecord.marginRatioClamped))}`,
      `recovery.marginRatioClamped=${String(toFiniteNumber(args.recoveryRecord.marginRatioClamped))}`,
    ],
  );

  const staleMismatch =
    artifactAgeDeltaMs != null && artifactAgeDeltaMs > 1000 * 60 * 60 * 24;
  addCandidate(
    "artifact_staleness_mismatch",
    staleMismatch
      ? "supported"
      : artifactAgeDeltaMs == null
        ? "insufficient_evidence"
        : "ruled_out",
    staleMismatch ? 0.5 : 0.08,
    [
      `canonical.timestamp=${asText(args.canonicalRecord.timestamp) ?? "null"}`,
      `recovery.generatedAt=${asText(args.recoveryRoot.generatedAt) ?? "null"}`,
      `artifact_age_delta_ms=${artifactAgeDeltaMs ?? "null"}`,
    ],
  );

  const reconstructionMismatch =
    numericGapPresent &&
    ((recoveryDerivation != null && recoveryDerivation.length > 0) ||
      (recoveryMetricT00Si != null &&
        recoveryRhoMetric != null &&
        recoveryMatchesRhoMetric &&
        canonicalMatchesRhoMetric === false));
  addCandidate(
    "recovery_reconstruction_mismatch",
    reconstructionMismatch
      ? "supported"
      : recoveryDerivation != null
        ? "possible"
        : "ruled_out",
    reconstructionMismatch ? 0.88 : recoveryDerivation != null ? 0.45 : 0.05,
    [
      `canonical.metricT00Derivation=${canonicalDerivation ?? "null"}`,
      `recovery.metricT00Derivation=${recoveryDerivation ?? "null"}`,
      `canonical.metricT00GeomSource=${canonicalGeomSource ?? "null"}`,
      `recovery.metricT00ContractStatus=${recoveryContractStatus ?? "null"}`,
      `canonical.metricT00Si_matches_rhoMetric=${String(canonicalMatchesRhoMetric)}`,
      `recovery.metricT00Si_matches_rhoMetric=${String(recoveryMatchesRhoMetric)}`,
    ],
  );

  const sourceFormulaMismatch =
    numericGapPresent &&
    args.metricSelectorStatus === "matched" &&
    (canonicalGeomSource === "direct_metric_pipeline" ||
      ((canonicalDerivation ?? "").length > 0 &&
        (canonicalDerivation ?? "") !== (recoveryDerivation ?? "")));
  addCandidate(
    "source_formula_mismatch",
    sourceFormulaMismatch
      ? "supported"
      : numericGapPresent
        ? "possible"
        : "ruled_out",
    sourceFormulaMismatch ? 0.93 : numericGapPresent ? 0.35 : 0.05,
    [
      `numeric_gap_present=${String(numericGapPresent)}`,
      `metric_selector_status=${args.metricSelectorStatus}`,
      `canonical.metricT00Derivation=${canonicalDerivation ?? "null"}`,
      `recovery.metricT00Derivation=${recoveryDerivation ?? "null"}`,
      `canonical.metricT00GeomSource=${canonicalGeomSource ?? "null"}`,
      `canonical.metricT00Si=${canonicalMetricT00Si ?? "null"}`,
      `recovery.metricT00Si=${recoveryMetricT00Si ?? "null"}`,
      `canonical_over_recovery_ratio=${ratioCanonicalOverRecovery ?? "null"}`,
    ],
  );

  const hasStrongCandidate = candidates.some(
    (entry) =>
      entry.candidate_id !== "unexplained_numeric_gap" &&
      entry.status === "supported" &&
      entry.estimated_explanatory_power >= 0.6,
  );
  addCandidate(
    "unexplained_numeric_gap",
    numericGapPresent && !hasStrongCandidate ? "supported" : numericGapPresent ? "possible" : "ruled_out",
    numericGapPresent && !hasStrongCandidate ? 0.7 : numericGapPresent ? 0.2 : 0.05,
    [
      `numeric_gap_present=${String(numericGapPresent)}`,
      `has_strong_candidate=${String(hasStrongCandidate)}`,
      `delta_abs=${deltaAbs ?? "null"}`,
      `delta_rel=${deltaRel ?? "null"}`,
    ],
  );

  const primaryCandidate =
    candidates
      .filter((entry) => entry.status === "supported")
      .sort((a, b) => b.estimated_explanatory_power - a.estimated_explanatory_power)[0]
      ?.candidate_id ?? null;

  return {
    canonical_metricT00Si_Jm3: canonicalMetricT00Si,
    recovery_metricT00Si_Jm3: recoveryMetricT00Si,
    delta_abs: deltaAbs,
    delta_rel: deltaRel,
    ratio_canonical_over_recovery: ratioCanonicalOverRecovery,
    detected_unit_labels: {
      canonical: canonicalUnit,
      recovery: recoveryUnit,
      authority: args.authorityUnit,
    },
    detected_normalization_labels: {
      canonical_metric: canonicalMetricNorm,
      recovery_metric: recoveryMetricNorm,
      canonical_qei: canonicalQeiNorm,
      recovery_qei: recoveryQeiNorm,
      canonical_qei_renorm: canonicalQeiRenorm,
      recovery_qei_renorm: recoveryQeiRenorm,
      authority_metric: args.authorityNormalization,
    },
    metric_family_labels: {
      canonical: args.familyCanonicalFromRef,
      recovery: args.familyRecoveryFromRef,
      authority: args.familyAuthority,
    },
    source_derivation_labels: {
      canonical_metricT00Derivation: canonicalDerivation,
      recovery_metricT00Derivation: recoveryDerivation,
      canonical_metricT00GeomSource: canonicalGeomSource,
      recovery_metricT00ContractStatus: recoveryContractStatus,
      canonical_source_formula_path: canonicalGeomSource,
      recovery_source_formula_path:
        recoveryDerivation ?? (recoveryMatchesRhoMetric ? "metricStressRhoSiMean_Jm3" : null),
    },
    floor_clamp_signals: {
      canonical_boundFloorApplied: asBooleanOrNull(args.canonicalRecord.boundFloorApplied),
      recovery_boundFloorApplied: asBooleanOrNull(args.recoveryRecord.boundFloorApplied),
      canonical_g4FloorDominated: asBooleanOrNull(args.canonicalRecord.g4FloorDominated),
      recovery_g4FloorDominated: asBooleanOrNull(args.recoveryRecord.g4FloorDominated),
      canonical_marginRatioClamped: toFiniteNumber(args.canonicalRecord.marginRatioClamped),
      recovery_marginRatioClamped: toFiniteNumber(args.recoveryRecord.marginRatioClamped),
    },
    calibration_multipliers: {
      canonical_couplingAlpha: toFiniteNumber(args.canonicalRecord.couplingAlpha),
      recovery_couplingAlpha: toFiniteNumber(args.recoveryRecord.couplingAlpha),
      canonical_metricT00SiRelError: toFiniteNumber(args.canonicalRecord.metricT00SiRelError),
      recovery_metricT00SiRelError: toFiniteNumber(args.recoveryRecord.metricT00SiRelError),
    },
    numericGapCandidates: candidates,
    primaryCandidate,
  };
};

const compareSourceStageField = (args: {
  field: string;
  canonicalRecord: Record<string, unknown>;
  recoveryRecord: Record<string, unknown>;
  aliases?: string[];
  relTol: number;
  absTol: number;
}): SourceStageComparedField => {
  const keys = [args.field, ...(args.aliases ?? [])];
  const readValue = (record: Record<string, unknown>): unknown => {
    for (const key of keys) {
      if (key in record) return record[key];
    }
    return null;
  };
  const canonicalValue = readValue(args.canonicalRecord);
  const recoveryValue = readValue(args.recoveryRecord);
  const canonicalNum = toFiniteNumber(canonicalValue);
  const recoveryNum = toFiniteNumber(recoveryValue);
  if (canonicalNum != null && recoveryNum != null) {
    const deltaAbs = Math.abs(canonicalNum - recoveryNum);
    const denom = Math.max(Math.abs(canonicalNum), Math.abs(recoveryNum), 1);
    const deltaRel = deltaAbs / denom;
    const threshold = Math.max(args.absTol, args.relTol * denom);
    const equal = deltaAbs <= threshold;
    return {
      field: args.field,
      canonical_value: canonicalValue,
      recovery_value: recoveryValue,
      comparator: "numeric_tolerance",
      equal,
      delta_abs: deltaAbs,
      delta_rel: deltaRel,
      status: determineSourceStageStatus(canonicalValue, recoveryValue),
      reason: equal ? null : `|Δ|=${deltaAbs} > tol=${threshold}`,
    };
  }
  const equal = valuesEquivalent(canonicalValue, recoveryValue);
  return {
    field: args.field,
    canonical_value: canonicalValue,
    recovery_value: recoveryValue,
    comparator: "exact",
    equal,
    delta_abs: null,
    delta_rel: null,
    status: determineSourceStageStatus(canonicalValue, recoveryValue),
    reason: equal ? null : "exact_mismatch",
  };
};

const mapNumericCandidateToSourceCause = (
  candidate: SourceStageNumericGapCandidateId | null,
): SourceStageCause => {
  switch (candidate) {
    case "unit_conversion_mismatch":
      return "unit_system_drift";
    case "normalization_scale_mismatch":
      return "normalization_scale_mismatch";
    case "selector_family_mismatch":
      return "metric_selector_drift";
    case "source_formula_mismatch":
      return "source_formula_mismatch";
    case "artifact_staleness_mismatch":
      return "artifact_staleness_mismatch";
    case "hidden_policy_or_floor_mismatch":
      return "policy_floor_or_clamp_mismatch";
    case "recovery_reconstruction_mismatch":
      return "recovery_reconstruction_mismatch";
    case "unexplained_numeric_gap":
      return "unresolved_numeric_source_gap";
    default:
      return "none";
  }
};

const mapFormulaMismatchClassToSourceCause = (
  mismatchClass: SourceFormulaMismatchClass | null,
): SourceStageCause => {
  switch (mismatchClass) {
    case "direct_vs_reconstructed":
      return "recovery_reconstruction_mismatch";
    case "different_metric_source_formula":
      return "different_metric_source_formula";
    case "different_normalization_formula":
      return "different_normalization_formula";
    case "different_unit_formula":
      return "different_unit_formula";
    case "same_formula_numeric_drift":
      return "same_formula_numeric_drift";
    case "unresolved_formula_mismatch":
      return "source_formula_mismatch";
    default:
      return "none";
  }
};

const classifySourceStageCause = (args: {
  sourceFieldComparisons: SourceStageComparedField[];
  componentAudit: SourceStageComponentAudit[];
  snapshotSourceMismatch: boolean;
  mixedAuthorityDetected: boolean;
  numericGapDecomposition: SourceStageNumericGapDecomposition;
}): { primary: SourceStageCause; contributing: SourceStageCause[] } => {
  const componentStatusByName = new Map(
    args.componentAudit.map((entry) => [entry.component, entry.status]),
  );
  const hasFieldDrift = args.sourceFieldComparisons.some((entry) => !entry.equal);
  const sourceMetricField = args.sourceFieldComparisons.find(
    (entry) => entry.field === "metricT00Si_Jm3",
  );
  const contributing = new Set<SourceStageCause>();
  if (componentStatusByName.get("metric_selector") === "drifted") {
    contributing.add("metric_selector_drift");
  }
  if (componentStatusByName.get("normalization_mode") === "drifted") {
    contributing.add("normalization_drift");
  }
  if (componentStatusByName.get("unit_system") === "drifted") {
    contributing.add("unit_system_drift");
  }
  if (args.snapshotSourceMismatch) {
    contributing.add("snapshot_source_mismatch");
  }
  const numericPrimaryCause = mapNumericCandidateToSourceCause(
    args.numericGapDecomposition.primaryCandidate,
  );
  if (numericPrimaryCause !== "none") {
    contributing.add(numericPrimaryCause);
  }
  if (sourceMetricField && !sourceMetricField.equal) {
    if (numericPrimaryCause === "none") {
      contributing.add("unresolved_numeric_source_gap");
    }
  }
  if (args.mixedAuthorityDetected) {
    contributing.add("mixed_authority_source_path");
  }
  if (componentStatusByName.get("metric_selector") === "drifted") {
    return {
      primary: "metric_selector_drift",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "metric_selector_drift",
      ),
    };
  }
  if (componentStatusByName.get("normalization_mode") === "drifted") {
    return {
      primary: "normalization_drift",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "normalization_drift",
      ),
    };
  }
  if (componentStatusByName.get("unit_system") === "drifted") {
    return {
      primary: "unit_system_drift",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "unit_system_drift",
      ),
    };
  }
  if (args.snapshotSourceMismatch) {
    return {
      primary: "snapshot_source_mismatch",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "snapshot_source_mismatch",
      ),
    };
  }
  if (sourceMetricField && !sourceMetricField.equal) {
    if (args.mixedAuthorityDetected) {
      return {
        primary: "mixed_authority_source_path",
        contributing: Array.from(contributing).filter(
          (entry) => entry !== "mixed_authority_source_path",
        ),
      };
    }
    if (numericPrimaryCause !== "none") {
      return {
        primary: numericPrimaryCause,
        contributing: Array.from(contributing).filter(
          (entry) => entry !== numericPrimaryCause,
        ),
      };
    }
    return {
      primary: "unresolved_numeric_source_gap",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "unresolved_numeric_source_gap",
      ),
    };
  }
  if (args.mixedAuthorityDetected) {
    return {
      primary: "mixed_authority_source_path",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "mixed_authority_source_path",
      ),
    };
  }
  if (hasFieldDrift) {
    return {
      primary: "unresolved_numeric_source_gap",
      contributing: Array.from(contributing).filter(
        (entry) => entry !== "unresolved_numeric_source_gap",
      ),
    };
  }
  return { primary: "none", contributing: [] };
};

const refineSourceStageCauseFromFormula = (args: {
  base: { primary: SourceStageCause; contributing: SourceStageCause[] };
  sourceFormulaAudit?: Nhm2SourceFormulaAuditArtifact | null;
}): { primary: SourceStageCause; contributing: SourceStageCause[] } => {
  const formulaMismatchClass = args.sourceFormulaAudit?.formulaComparison.formulaMismatchClass ?? null;
  const formulaCause = mapFormulaMismatchClassToSourceCause(formulaMismatchClass);
  if (formulaCause === "none") return args.base;
  if (
    args.base.primary === "none" ||
    args.base.primary === "source_formula_mismatch" ||
    args.base.primary === "unresolved_numeric_source_gap" ||
    args.base.primary === "recovery_reconstruction_mismatch" ||
    args.base.primary === "different_metric_source_formula" ||
    args.base.primary === "different_normalization_formula" ||
    args.base.primary === "different_unit_formula" ||
    args.base.primary === "same_formula_numeric_drift"
  ) {
    const nextContrib = new Set(args.base.contributing);
    if (args.base.primary !== "none" && args.base.primary !== formulaCause) {
      nextContrib.add(args.base.primary);
    }
    nextContrib.delete(formulaCause);
    return {
      primary: formulaCause,
      contributing: Array.from(nextContrib),
    };
  }
  return args.base;
};

const isSourceStageCauseBlocking = (
  args: {
    cause: SourceStageCause;
    policy: SourceFormulaComparisonPolicy | null;
    sourceFormulaComparison: SourceFormulaComparison | null;
  },
): boolean => {
  if (args.cause === "none") return false;
  const reconstructionComparisonPolicyBlocking =
    args.policy?.comparison_path_blocks_readiness ?? true;
  if (args.cause === "recovery_reconstruction_mismatch") {
    return reconstructionComparisonPolicyBlocking;
  }
  if (
    args.cause === "source_formula_mismatch" &&
    reconstructionComparisonPolicyBlocking === false &&
    args.sourceFormulaComparison?.formulaMismatchClass === "direct_vs_reconstructed" &&
    args.sourceFormulaComparison.reconstructionOnlyComparison
  ) {
    return false;
  }
  return true;
};

const partitionSourceStageFindings = (args: {
  classified: { primary: SourceStageCause; contributing: SourceStageCause[] };
  policy: SourceFormulaComparisonPolicy | null;
  sourceFormulaComparison: SourceFormulaComparison | null;
}): { blockingFindings: SourceStageCause[]; advisoryFindings: SourceStageCause[] } => {
  const orderedFindings = [args.classified.primary, ...args.classified.contributing].filter(
    (entry): entry is SourceStageCause => entry !== "none",
  );
  const dedupedFindings = Array.from(new Set(orderedFindings));
  const blockingFindings = dedupedFindings.filter((entry) =>
    isSourceStageCauseBlocking({
      cause: entry,
      policy: args.policy,
      sourceFormulaComparison: args.sourceFormulaComparison,
    }),
  );
  const advisoryFindings = dedupedFindings.filter(
    (entry) =>
      !isSourceStageCauseBlocking({
        cause: entry,
        policy: args.policy,
        sourceFormulaComparison: args.sourceFormulaComparison,
      }),
  );
  return { blockingFindings, advisoryFindings };
};

const computeSourceStageAuditChecksum = (
  payload: Nhm2SourceStageAuditArtifact,
): string => {
  const copy = JSON.parse(JSON.stringify(payload)) as Record<string, unknown>;
  delete copy.generatedAt;
  delete copy.checksum;
  return crypto.createHash("sha256").update(stableStringify(copy)).digest("hex");
};

const resolveRecoveryCaseRecord = (
  recoveryRaw: Record<string, unknown> | null,
  recoveryCaseId: string | null,
): Record<string, unknown> => {
  if (!recoveryRaw) return {};
  const cases = Array.isArray(recoveryRaw.cases)
    ? recoveryRaw.cases.map((entry) => asRecord(entry))
    : [];
  if (recoveryCaseId) {
    const match = cases.find((entry) => asText(entry.id) === recoveryCaseId);
    if (match) return match;
  }
  const bestCandidate = asRecord(recoveryRaw.bestCandidate);
  if (Object.keys(bestCandidate).length > 0) return bestCandidate;
  return cases[0] ?? {};
};

export const buildNhm2SourceFormulaAuditArtifact = (args: {
  payload: ProofPackPayload;
  sourceToYork: SourceToYorkProvenanceArtifact;
  sourceAuditArtifactPath: string;
  sourceToYorkArtifactPath: string;
  firstDivergencePath?: string;
  comparisonPolicyOverride?: Partial<
    Omit<
      SourceFormulaComparisonPolicy,
      "authoritative_formula_path_id" | "comparison_formula_path_id" | "comparison_requires_formula_equivalence"
    >
  >;
}): Nhm2SourceFormulaAuditArtifact => {
  const firstDivergencePath = resolveLatestG4FirstDivergencePath(args.firstDivergencePath);
  const firstDivergenceRaw = firstDivergencePath ? readJsonIfExists(firstDivergencePath) : null;
  const canonicalPath = resolveArtifactPath(asText(asRecord(firstDivergenceRaw?.canonical).path));
  const recoveryPath = resolveArtifactPath(asText(asRecord(firstDivergenceRaw?.recovery).path));
  const recoveryCaseId =
    asText(asRecord(firstDivergenceRaw?.recovery).caseId) ??
    asText(firstDivergenceRaw?.recoveryCaseId);
  const canonicalRecord = canonicalPath ? readJsonIfExists(canonicalPath) ?? {} : {};
  const recoveryRaw = recoveryPath ? readJsonIfExists(recoveryPath) : null;
  const recoveryRecord = resolveRecoveryCaseRecord(recoveryRaw, recoveryCaseId);
  const tolerances = asRecord(firstDivergenceRaw?.tolerances);
  const relTol = toFiniteNumber(tolerances.relTol) ?? 1e-9;
  const absTol = toFiniteNumber(tolerances.absTol) ?? 1e-12;

  const canonicalMetricT00Si = parseMetricT00Si([
    canonicalRecord.metricT00Si_Jm3,
    canonicalRecord.metricT00SiFromGeom_Jm3,
    canonicalRecord.metricT00SiFromGeom,
  ]);
  const comparisonMetricT00Si = parseMetricT00Si([
    recoveryRecord.metricT00Si_Jm3,
    recoveryRecord.metricT00SiFromGeom_Jm3,
    recoveryRecord.metricT00SiFromGeom,
    recoveryRecord.metricStressRhoSiMean_Jm3,
  ]);

  const canonicalGeomSource = asText(canonicalRecord.metricT00GeomSource);
  const canonicalDerivation = asText(canonicalRecord.metricT00Derivation);
  const comparisonGeomSource = asText(recoveryRecord.metricT00GeomSource);
  const comparisonDerivation = asText(recoveryRecord.metricT00Derivation);
  const recoveryParams = asRecord(recoveryRecord.params);
  const canonicalClass = resolveSourceFormulaClass(canonicalGeomSource, canonicalDerivation);
  const comparisonClass = resolveSourceFormulaClass(comparisonGeomSource, comparisonDerivation);
  const canonicalDerivationMode = resolveSourceFormulaDerivationMode({
    formulaClass: canonicalClass,
    metricT00Derivation: canonicalDerivation,
    metricT00GeomSource: canonicalGeomSource,
  });
  const comparisonDerivationMode = resolveSourceFormulaDerivationMode({
    formulaClass: comparisonClass,
    metricT00Derivation: comparisonDerivation,
    metricT00GeomSource: comparisonGeomSource,
  });

  const canonicalUnit =
    asText(canonicalRecord.metricT00UnitSystem) ??
    (canonicalMetricT00Si != null ? "SI_inferred_jm3" : null);
  const comparisonUnit =
    asText(recoveryRecord.metricT00UnitSystem) ??
    (comparisonMetricT00Si != null ? "SI_inferred_jm3" : null);
  const canonicalNorm =
    asText(canonicalRecord.metricT00Normalization) ??
    asText(canonicalRecord.qeiSamplingNormalization);
  const comparisonNorm =
    asText(recoveryRecord.metricT00Normalization) ??
    asText(recoveryRecord.qeiSamplingNormalization);

  const canonicalFormula: SourceFormulaPathAudit = {
    authority_id: "canonical_qi_forensics",
    formula_path_id: "canonical_qi_forensics.metricT00Si_Jm3",
    formula_class: canonicalClass,
    source_field_path: "canonical.metricT00Si_Jm3",
    code_path_references: [
      {
        path: "scripts/warp-full-solve-campaign.ts",
        symbol: "buildQiForensicsArtifact",
      },
      {
        path: "server/energy-pipeline.ts",
        symbol: "buildMetricT00Contract",
      },
    ],
    inputs_used: {
      rhoSource: asText(canonicalRecord.rhoSource),
      metricT00Ref: asText(canonicalRecord.metricT00Ref),
      metricT00Source: asText(canonicalRecord.metricT00Source),
      metricT00Derivation: canonicalDerivation,
      metricT00GeomSource: canonicalGeomSource,
      qeiSamplingNormalization: asText(canonicalRecord.qeiSamplingNormalization),
      qeiRenormalizationScheme: asText(canonicalRecord.qeiRenormalizationScheme),
      dutyEffective_FR: null,
      sectorCount: null,
      concurrentSectors: null,
      qCavity: null,
      qSpoilingFactor: null,
      gammaGeo: null,
      gammaVanDenBroeck: null,
      tauSelected_s: toFiniteNumber(canonicalRecord.tauSelected_s),
      tauLC_s: toFiniteNumber(canonicalRecord.tauLC_s),
      tauPulse_s: toFiniteNumber(canonicalRecord.tauPulse_s),
      selectorAvailabilityNote:
        "Canonical qi-forensics artifact does not serialize duty/sector/Q/gamma selectors.",
    },
    intermediate_terms: {
      rhoMetric_Jm3: toFiniteNumber(canonicalRecord.rhoMetric_Jm3),
      metricStressRhoSiMean_Jm3: toFiniteNumber(canonicalRecord.metricStressRhoSiMean_Jm3),
      couplingAlpha: toFiniteNumber(canonicalRecord.couplingAlpha),
      metricT00SiRelError: toFiniteNumber(canonicalRecord.metricT00SiRelError),
      qeiSamplingNormalization: asText(canonicalRecord.qeiSamplingNormalization),
      qeiRenormalizationScheme: asText(canonicalRecord.qeiRenormalizationScheme),
    },
    final_metricT00Si_Jm3: canonicalMetricT00Si,
    unit_contract: canonicalUnit,
    normalization_contract: canonicalNorm,
    derivation_mode: canonicalDerivationMode,
    readiness_authoritative: true,
  };
  const comparisonFormula: SourceFormulaPathAudit = {
    authority_id: "recovery_search_case",
    formula_path_id: "recovery_search_case.metricT00Si_Jm3",
    formula_class: comparisonClass,
    source_field_path: "recovery.bestCandidate.metricT00Si_Jm3",
    code_path_references: [
      {
        path: "scripts/warp-g4-recovery-search.ts",
        symbol: "extractMetricDecomposition",
      },
      {
        path: "scripts/warp-g4-recovery-search.ts",
        symbol: "buildCandidateSummary",
      },
    ],
    inputs_used: {
      rhoSource: asText(recoveryRecord.rhoSource),
      metricT00Ref: asText(recoveryRecord.metricT00Ref),
      metricT00Source: asText(recoveryRecord.metricT00Source),
      metricT00Derivation: comparisonDerivation,
      metricT00GeomSource: comparisonGeomSource,
      metricT00ContractStatus: asText(recoveryRecord.metricT00ContractStatus),
      qeiSamplingNormalization: asText(recoveryRecord.qeiSamplingNormalization),
      qeiRenormalizationScheme: asText(recoveryRecord.qeiRenormalizationScheme),
      dutyCycle: toFiniteNumber(recoveryParams.dutyCycle),
      dutyShip: toFiniteNumber(recoveryParams.dutyShip),
      dutyEffective_FR:
        toFiniteNumber(recoveryParams.dutyEffective_FR) ??
        toFiniteNumber(recoveryRecord.dutyEffective_FR),
      sectorCount: toFiniteNumber(recoveryParams.sectorCount),
      concurrentSectors: toFiniteNumber(recoveryParams.concurrentSectors),
      qCavity: toFiniteNumber(recoveryParams.qCavity),
      qSpoilingFactor: toFiniteNumber(recoveryParams.qSpoilingFactor),
      gammaGeo: toFiniteNumber(recoveryParams.gammaGeo),
      gammaVanDenBroeck: toFiniteNumber(recoveryParams.gammaVanDenBroeck),
      tauSelected_s:
        toFiniteNumber(recoveryParams.tau_s_ms) != null
          ? (toFiniteNumber(recoveryParams.tau_s_ms) as number) * 1e-3
          : null,
      gap_nm: toFiniteNumber(recoveryParams.gap_nm),
      shipRadius_m: toFiniteNumber(recoveryParams.shipRadius_m),
    },
    intermediate_terms: {
      rhoMetric_Jm3: toFiniteNumber(recoveryRecord.rhoMetric_Jm3),
      metricStressRhoSiMean_Jm3: toFiniteNumber(recoveryRecord.metricStressRhoSiMean_Jm3),
      couplingAlpha: toFiniteNumber(recoveryRecord.couplingAlpha),
      metricT00SiRelError: toFiniteNumber(recoveryRecord.metricT00SiRelError),
      qeiSamplingNormalization: asText(recoveryRecord.qeiSamplingNormalization),
      qeiRenormalizationScheme: asText(recoveryRecord.qeiRenormalizationScheme),
    },
    final_metricT00Si_Jm3: comparisonMetricT00Si,
    unit_contract: comparisonUnit,
    normalization_contract: comparisonNorm,
    derivation_mode: comparisonDerivationMode,
    readiness_authoritative: false,
  };

  const formulaClassMatch = canonicalFormula.formula_class === comparisonFormula.formula_class;
  const unitContractMatch =
    canonicalFormula.unit_contract != null &&
    comparisonFormula.unit_contract != null &&
    canonicalFormula.unit_contract === comparisonFormula.unit_contract;
  const normalizationContractMatch =
    canonicalFormula.normalization_contract != null &&
    comparisonFormula.normalization_contract != null &&
    canonicalFormula.normalization_contract === comparisonFormula.normalization_contract;
  const derivationModeMatch = canonicalFormula.derivation_mode === comparisonFormula.derivation_mode;
  const finalMetricDeltaAbs =
    canonicalMetricT00Si != null && comparisonMetricT00Si != null
      ? Math.abs(canonicalMetricT00Si - comparisonMetricT00Si)
      : null;
  const finalMetricDeltaRel =
    canonicalMetricT00Si != null && comparisonMetricT00Si != null
      ? finalMetricDeltaAbs /
        Math.max(Math.abs(canonicalMetricT00Si), Math.abs(comparisonMetricT00Si), 1)
      : null;
  const metricParity =
    canonicalMetricT00Si != null &&
    comparisonMetricT00Si != null &&
    numericallyEqual(canonicalMetricT00Si, comparisonMetricT00Si, relTol, absTol);
  const formulaEquivalent =
    formulaClassMatch &&
    unitContractMatch &&
    normalizationContractMatch &&
    derivationModeMatch &&
    metricParity;
  const reconstructionOnlyComparison =
    comparisonFormula.derivation_mode === "reconstructed" &&
    canonicalFormula.derivation_mode !== "reconstructed" &&
    !formulaEquivalent;
  const comparisonMode: SourceFormulaComparisonMode =
    reconstructionOnlyComparison ||
    (canonicalFormula.derivation_mode === "direct" &&
      comparisonFormula.derivation_mode === "reconstructed")
      ? "authoritative_direct_vs_reconstructed_proxy"
      : formulaClassMatch && derivationModeMatch
        ? "formula_parity_check"
        : "mixed_formula_path_audit";

  let formulaMismatchClass: SourceFormulaMismatchClass = "none";
  if (reconstructionOnlyComparison) {
    formulaMismatchClass = "direct_vs_reconstructed";
  } else if (
    canonicalFormula.unit_contract != null &&
    comparisonFormula.unit_contract != null &&
    canonicalFormula.unit_contract !== comparisonFormula.unit_contract
  ) {
    formulaMismatchClass = "different_unit_formula";
  } else if (
    canonicalFormula.normalization_contract != null &&
    comparisonFormula.normalization_contract != null &&
    canonicalFormula.normalization_contract !== comparisonFormula.normalization_contract
  ) {
    formulaMismatchClass = "different_normalization_formula";
  } else if (
    canonicalFormula.formula_class !== "unknown" &&
    comparisonFormula.formula_class !== "unknown" &&
    canonicalFormula.formula_class !== comparisonFormula.formula_class
  ) {
    formulaMismatchClass = "different_metric_source_formula";
  } else if (
    canonicalFormula.formula_class === comparisonFormula.formula_class &&
    canonicalFormula.derivation_mode === comparisonFormula.derivation_mode &&
    finalMetricDeltaAbs != null &&
    !metricParity
  ) {
    formulaMismatchClass = "same_formula_numeric_drift";
  } else if (!formulaEquivalent) {
    formulaMismatchClass = "unresolved_formula_mismatch";
  }

  const intermediateTermKeys = new Set([
    ...Object.keys(canonicalFormula.intermediate_terms),
    ...Object.keys(comparisonFormula.intermediate_terms),
  ]);
  const intermediateTermDeltas = Array.from(intermediateTermKeys).map((term) => {
    const canonicalValue = canonicalFormula.intermediate_terms[term];
    const comparisonValue = comparisonFormula.intermediate_terms[term];
    return {
      term,
      canonical_value: canonicalValue ?? null,
      comparison_value: comparisonValue ?? null,
      equal: valuesEquivalent(canonicalValue, comparisonValue),
    };
  });
  const termComparisons: SourceFormulaTermComparison[] = [
    buildSourceFormulaTermComparison({
      termId: "final_metricT00Si_Jm3",
      directValue: canonicalFormula.final_metricT00Si_Jm3,
      reconstructedValue: comparisonFormula.final_metricT00Si_Jm3,
      units: "J/m^3",
      note:
        reconstructionOnlyComparison && !metricParity
          ? "Direct canonical metric T00 and reconstructed recovery metric T00 diverge materially."
          : "Final metric T00 comparison.",
    }),
    ...Array.from(intermediateTermKeys).map((term) =>
      buildSourceFormulaTermComparison({
        termId: term,
        directValue: canonicalFormula.intermediate_terms[term],
        reconstructedValue: comparisonFormula.intermediate_terms[term],
        units:
          term === "rhoMetric_Jm3" || term === "metricStressRhoSiMean_Jm3"
            ? "J/m^3"
            : term === "couplingAlpha" || term === "metricT00SiRelError"
              ? "dimensionless"
              : null,
        note:
          term === "metricStressRhoSiMean_Jm3" &&
          canonicalFormula.intermediate_terms[term] == null &&
          comparisonFormula.intermediate_terms[term] != null
            ? "Reconstructed path emits stress-density mean explicitly; canonical direct artifact does not serialize it as a separate intermediate."
            : term === "rhoMetric_Jm3" &&
                valuesEquivalent(
                  canonicalFormula.intermediate_terms[term],
                  comparisonFormula.intermediate_terms[term],
                )
              ? "Shared rhoMetric term is numerically aligned across direct and reconstructed paths."
              : null,
      }),
    ),
  ];
  const resolvedInputComparisons: SourceFormulaResolvedInputComparison[] = [
    buildSourceFormulaComparisonEntry({
      id: "rhoSource",
      directValue: canonicalFormula.inputs_used.rhoSource,
      reconstructedValue: comparisonFormula.inputs_used.rhoSource,
      note: "Metric source selector carried into the formula path.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "metricT00Ref",
      directValue: canonicalFormula.inputs_used.metricT00Ref,
      reconstructedValue: comparisonFormula.inputs_used.metricT00Ref,
      note: "Metric T00 provenance reference used by each path.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "metricT00Derivation",
      directValue: canonicalFormula.inputs_used.metricT00Derivation,
      reconstructedValue: comparisonFormula.inputs_used.metricT00Derivation,
      note: "Direct path uses authoritative metric output; comparison path reconstructs through forward shift -> K -> rho_E.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "metricT00GeomSource",
      directValue: canonicalFormula.inputs_used.metricT00GeomSource,
      reconstructedValue: comparisonFormula.inputs_used.metricT00GeomSource,
      note: "Metric geometry provenance class.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "qeiSamplingNormalization",
      directValue: canonicalFormula.inputs_used.qeiSamplingNormalization,
      reconstructedValue: comparisonFormula.inputs_used.qeiSamplingNormalization,
    }),
    buildSourceFormulaComparisonEntry({
      id: "qeiRenormalizationScheme",
      directValue: canonicalFormula.inputs_used.qeiRenormalizationScheme,
      reconstructedValue: comparisonFormula.inputs_used.qeiRenormalizationScheme,
    }),
    buildSourceFormulaComparisonEntry({
      id: "dutyEffective_FR",
      directValue: canonicalFormula.inputs_used.dutyEffective_FR,
      reconstructedValue: comparisonFormula.inputs_used.dutyEffective_FR,
      units: "fraction",
      note:
        "Recovery path emits duty-effective input; canonical direct artifact does not serialize an equivalent duty selector.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "sectorCount",
      directValue: canonicalFormula.inputs_used.sectorCount,
      reconstructedValue: comparisonFormula.inputs_used.sectorCount,
      units: "count",
      note:
        "Sector-strobing inputs are present on the reconstructed path only in current artifacts.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "concurrentSectors",
      directValue: canonicalFormula.inputs_used.concurrentSectors,
      reconstructedValue: comparisonFormula.inputs_used.concurrentSectors,
      units: "count",
      note:
        "Concurrent-sector selector is present on the reconstructed path only in current artifacts.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "gammaGeo",
      directValue: canonicalFormula.inputs_used.gammaGeo,
      reconstructedValue: comparisonFormula.inputs_used.gammaGeo,
      units: "dimensionless",
      note:
        "Geometry amplification selector is present on the reconstructed path only in current artifacts.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "gammaVanDenBroeck",
      directValue: canonicalFormula.inputs_used.gammaVanDenBroeck,
      reconstructedValue: comparisonFormula.inputs_used.gammaVanDenBroeck,
      units: "dimensionless",
      note:
        "VdB amplification selector is present on the reconstructed path only in current artifacts.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "qCavity",
      directValue: canonicalFormula.inputs_used.qCavity,
      reconstructedValue: comparisonFormula.inputs_used.qCavity,
      units: "quality_factor",
      note: "Q cavity selector used by the reconstructed path.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "qSpoilingFactor",
      directValue: canonicalFormula.inputs_used.qSpoilingFactor,
      reconstructedValue: comparisonFormula.inputs_used.qSpoilingFactor,
      units: "dimensionless",
      note: "Q spoiling selector used by the reconstructed path.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "selected_tau_s",
      directValue: canonicalFormula.inputs_used.tauSelected_s,
      reconstructedValue: comparisonFormula.inputs_used.tauSelected_s,
      units: "s",
      note:
        "Canonical selected QEI timescale vs reconstructed candidate tau input.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "tauLC_s",
      directValue: canonicalFormula.inputs_used.tauLC_s,
      reconstructedValue: null,
      units: "s",
      note: "Canonical lower-bound timescale is not serialized on the reconstructed path.",
    }),
    buildSourceFormulaComparisonEntry({
      id: "tauPulse_s",
      directValue: canonicalFormula.inputs_used.tauPulse_s,
      reconstructedValue: null,
      units: "s",
      note: "Canonical pulse timescale is not serialized on the reconstructed path.",
    }),
  ];
  const mismatchReasons = new Set<SourceFormulaMismatchReason>();
  if (!formulaEquivalent) {
    if (
      canonicalFormula.unit_contract != null &&
      comparisonFormula.unit_contract != null &&
      canonicalFormula.unit_contract !== comparisonFormula.unit_contract
    ) {
      mismatchReasons.add("unit_contract_mismatch");
    }
    if (
      canonicalFormula.normalization_contract != null &&
      comparisonFormula.normalization_contract != null &&
      canonicalFormula.normalization_contract !== comparisonFormula.normalization_contract
    ) {
      mismatchReasons.add("normalization_mismatch");
    }
    const dutyInputIds = new Set([
      "dutyEffective_FR",
      "sectorCount",
      "concurrentSectors",
      "gammaGeo",
      "gammaVanDenBroeck",
      "qCavity",
      "qSpoilingFactor",
    ]);
    if (
      resolvedInputComparisons.some(
        (entry) =>
          dutyInputIds.has(entry.inputId) &&
          (entry.status === "mismatched" ||
            entry.status === "missing_direct_input" ||
            entry.status === "missing_reconstructed_input"),
      )
    ) {
      mismatchReasons.add("duty_definition_mismatch");
    }
    const timingInputIds = new Set(["selected_tau_s", "tauLC_s", "tauPulse_s"]);
    if (
      resolvedInputComparisons.some(
        (entry) =>
          timingInputIds.has(entry.inputId) &&
          (entry.status === "mismatched" ||
            entry.status === "missing_direct_input" ||
            entry.status === "missing_reconstructed_input"),
      )
    ) {
      mismatchReasons.add("timing_source_mismatch");
    }
    const canonicalRhoMetric = toFiniteNumber(canonicalFormula.intermediate_terms.rhoMetric_Jm3);
    if (
      reconstructionOnlyComparison &&
      canonicalRhoMetric != null &&
      comparisonMetricT00Si != null &&
      numericallyEqual(canonicalRhoMetric, comparisonMetricT00Si, relTol, absTol) &&
      !metricParity
    ) {
      mismatchReasons.add("proxy_vs_metric_term_gap");
    }
    if (
      termComparisons.some(
        (entry) =>
          entry.status === "missing_direct_input" ||
          entry.status === "missing_reconstructed_input",
      ) ||
      resolvedInputComparisons.some(
        (entry) =>
          entry.status === "missing_direct_input" ||
          entry.status === "missing_reconstructed_input",
      )
    ) {
      mismatchReasons.add("missing_term_mapping");
    }
    if (mismatchReasons.size === 0) {
      mismatchReasons.add("unexpected_numeric_divergence");
    }
  }
  const mismatchReasonPriority: SourceFormulaMismatchReason[] = [
    "unit_contract_mismatch",
    "normalization_mismatch",
    "proxy_vs_metric_term_gap",
    "duty_definition_mismatch",
    "timing_source_mismatch",
    "missing_term_mapping",
    "unexpected_numeric_divergence",
  ];
  const mismatchReason =
    mismatchReasonPriority.find((entry) => mismatchReasons.has(entry)) ?? "none";
  const additionalMismatchReasons = Array.from(mismatchReasons).filter(
    (entry) => entry !== mismatchReason,
  );
  const policyOverride = args.comparisonPolicyOverride ?? {};
  const tolerancePolicy: SourceFormulaTolerancePolicy = {
    relTol,
    absTol,
    numericParityRule:
      "final_metric_numeric_parity requires delta <= max(absTol, relTol * max(|direct|, |reconstructed|, 1)).",
    formulaEquivalenceRequires: [
      "formula_class_match",
      "unit_contract_match",
      "normalization_contract_match",
      "derivation_mode_match",
      "final_metric_numeric_parity",
    ],
  };
  const interpretationPolicy: SourceFormulaInterpretationPolicy =
    reconstructionOnlyComparison &&
    mismatchReason === "proxy_vs_metric_term_gap" &&
    !policyOverride?.comparison_path_expected_equivalence &&
    !policyOverride?.comparisonPathExpectedEquivalence
      ? {
          policyId: "expected_proxy_vs_metric_gap_non_promotable",
          parityExpected: false,
          promotionBlockedByMismatch: true,
          laneAUnaffectedByMismatch: true,
          interpretationStatus: "advisory",
          note:
            "Authoritative direct metric and reconstructed proxy paths are not expected to satisfy parity in reconstruction-only comparison mode; mismatch remains non-promotable for parity claims.",
        }
      : !formulaEquivalent &&
          (policyOverride?.comparison_path_expected_equivalence === true ||
            policyOverride?.comparisonPathExpectedEquivalence === true)
        ? {
            policyId: "parity_required_before_promotion",
            parityExpected: true,
            promotionBlockedByMismatch: true,
            laneAUnaffectedByMismatch: true,
            interpretationStatus: "blocking",
            note:
              "Policy requires direct-vs-comparison parity before promotion; mismatch remains open until equivalent term mapping is achieved.",
          }
        : !formulaEquivalent
          ? {
              policyId: "open_congruence_failure",
              parityExpected: true,
              promotionBlockedByMismatch: true,
              laneAUnaffectedByMismatch: true,
              interpretationStatus: "blocking",
              note:
                "Mismatch remains an open congruence failure because the current policy surface does not settle it as an expected proxy-vs-metric gap.",
            }
          : {
              policyId: "parity_required_before_promotion",
              parityExpected: true,
              promotionBlockedByMismatch: false,
              laneAUnaffectedByMismatch: true,
              interpretationStatus: "advisory",
              note:
                "Direct and comparison paths satisfy current parity policy within emitted tolerance.",
            };

  const formulaComparison: SourceFormulaComparison = {
    directFormulaId:
      canonicalFormula.derivation_mode === "direct" ? canonicalFormula.formula_path_id : null,
    reconstructedFormulaId:
      comparisonFormula.derivation_mode === "reconstructed"
        ? comparisonFormula.formula_path_id
        : null,
    comparisonMode,
    tolerancePolicy,
    formula_class_match: formulaClassMatch,
    unit_contract_match: unitContractMatch,
    normalization_contract_match: normalizationContractMatch,
    derivation_mode_match: derivationModeMatch,
    mismatchReason,
    additionalMismatchReasons,
    resolvedInputComparisons,
    termComparisons,
    intermediate_term_deltas: intermediateTermDeltas,
    final_metric_delta_abs: finalMetricDeltaAbs,
    final_metric_delta_rel: finalMetricDeltaRel,
    formulaEquivalent,
    reconstructionOnlyComparison,
    formulaMismatchClass,
    notes: [
      `direct_formula_id=${canonicalFormula.formula_path_id}`,
      `reconstructed_formula_id=${comparisonFormula.formula_path_id}`,
      `comparison_mode=${comparisonMode}`,
      `canonical.formula_class=${canonicalFormula.formula_class}`,
      `comparison.formula_class=${comparisonFormula.formula_class}`,
      `canonical.derivation_mode=${canonicalFormula.derivation_mode}`,
      `comparison.derivation_mode=${comparisonFormula.derivation_mode}`,
      `mismatch_reason=${mismatchReason}`,
      `additional_mismatch_reasons=${additionalMismatchReasons.join(",") || "none"}`,
      `formula_equivalent=${String(formulaEquivalent)}`,
      `reconstruction_only_comparison=${String(reconstructionOnlyComparison)}`,
    ],
  };

  const defaultPolicy: SourceFormulaComparisonPolicy = {
    authoritative_formula_path_id: canonicalFormula.formula_path_id,
    comparison_formula_path_id: comparisonFormula.formula_path_id,
    comparison_path_policy: "canonical_authoritative_recovery_comparison_only",
    comparison_path_role: "reconstruction_only",
    comparison_path_expected_equivalence: false,
    comparison_path_blocks_readiness: false,
    comparison_mismatch_disposition: "advisory",
    authoritativeFormulaPathId: canonicalFormula.formula_path_id,
    comparisonFormulaPathId: comparisonFormula.formula_path_id,
    comparisonPathRole: "reconstruction_only",
    comparisonPathExpectedEquivalence: false,
    comparisonPathBlocksReadiness: false,
    comparisonMismatchDisposition: "advisory",
    comparison_requires_formula_equivalence: false,
  };
  const comparisonPathRole =
    policyOverride.comparison_path_role ??
    policyOverride.comparisonPathRole ??
    defaultPolicy.comparison_path_role;
  const expectedEquivalence =
    policyOverride.comparison_path_expected_equivalence ??
    policyOverride.comparisonPathExpectedEquivalence ??
    defaultPolicy.comparison_path_expected_equivalence;
  const blocksReadiness =
    policyOverride.comparison_path_blocks_readiness ??
    policyOverride.comparisonPathBlocksReadiness ??
    defaultPolicy.comparison_path_blocks_readiness;
  const mismatchDisposition =
    policyOverride.comparison_mismatch_disposition ??
    policyOverride.comparisonMismatchDisposition ??
    (blocksReadiness ? "blocking" : "advisory");
  const policy: SourceFormulaComparisonPolicy = {
    ...defaultPolicy,
    ...policyOverride,
    comparison_path_role: comparisonPathRole,
    comparison_path_expected_equivalence: expectedEquivalence,
    comparison_path_blocks_readiness: blocksReadiness,
    comparison_mismatch_disposition: mismatchDisposition,
    authoritativeFormulaPathId: canonicalFormula.formula_path_id,
    comparisonFormulaPathId: comparisonFormula.formula_path_id,
    comparisonPathRole: comparisonPathRole,
    comparisonPathExpectedEquivalence: expectedEquivalence,
    comparisonPathBlocksReadiness: blocksReadiness,
    comparisonMismatchDisposition: mismatchDisposition,
    comparison_requires_formula_equivalence: expectedEquivalence,
  };

  const payloadBase: Nhm2SourceFormulaAuditArtifact = {
    artifactType: "nhm2_source_formula_audit/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This source-formula artifact compares canonical vs recovery metricT00Si derivation paths; it does not retune NHM2.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    sourceToYorkArtifact: normalizePath(args.sourceToYorkArtifactPath),
    sourcePaths: {
      firstDivergenceArtifact: firstDivergencePath ? normalizePath(firstDivergencePath) : null,
      canonicalPath: canonicalPath ? normalizePath(canonicalPath) : null,
      recoveryPath: recoveryPath ? normalizePath(recoveryPath) : null,
      recoveryCaseId,
    },
    policy,
    interpretationPolicy,
    canonicalFormula,
    comparisonFormula,
    formulaComparison,
    stage: {
      formulaEquivalent,
      reconstructionOnlyComparison,
      formulaMismatchClass,
      mismatchReason,
      sourceFormulaInterpretationPolicy: interpretationPolicy.policyId,
      summary:
        formulaMismatchClass === "none"
          ? "Canonical and comparison source formulas are equivalent within emitted tolerance."
          : `source formula mismatch class=${formulaMismatchClass}; mismatch_reason=${mismatchReason}; interpretation_policy=${interpretationPolicy.policyId}`,
    },
    notes: [
      `comparison_path_role=${policy.comparison_path_role}; expected_equivalence=${String(policy.comparison_path_expected_equivalence)}; blocks_readiness=${String(policy.comparison_path_blocks_readiness)}; mismatch_disposition=${policy.comparison_mismatch_disposition}.`,
      `interpretation_policy=${interpretationPolicy.policyId}; parity_expected=${String(interpretationPolicy.parityExpected)}; promotion_blocked=${String(interpretationPolicy.promotionBlockedByMismatch)}; lane_a_unaffected=${String(interpretationPolicy.laneAUnaffectedByMismatch)}.`,
      `final_metric_delta_abs=${finalMetricDeltaAbs ?? "null"}`,
      `final_metric_delta_rel=${finalMetricDeltaRel ?? "null"}`,
    ],
  };
  return {
    ...payloadBase,
    checksum: computeSourceFormulaAuditChecksum(payloadBase),
  };
};

export const renderNhm2SourceFormulaAuditMarkdown = (
  payload: Nhm2SourceFormulaAuditArtifact,
): string => {
  const formatCell = (value: unknown): string =>
    value == null ? "null" : JSON.stringify(value).replace(/\|/g, "\\|");
  const canonicalCodeRows = payload.canonicalFormula.code_path_references
    .map((entry) => `| ${entry.path} | ${entry.symbol} |`)
    .join("\n");
  const comparisonCodeRows = payload.comparisonFormula.code_path_references
    .map((entry) => `| ${entry.path} | ${entry.symbol} |`)
    .join("\n");
  const resolvedInputRows = payload.formulaComparison.resolvedInputComparisons
    .map(
      (entry) =>
        `| ${entry.inputId} | ${formatCell(entry.directValue)} | ${formatCell(entry.reconstructedValue)} | ${entry.delta ?? "null"} | ${entry.relativeDelta ?? "null"} | ${entry.units ?? "null"} | ${entry.status} | ${entry.note ?? "null"} |`,
    )
    .join("\n");
  const termRows = payload.formulaComparison.termComparisons
    .map(
      (entry) =>
        `| ${entry.termId} | ${formatCell(entry.directValue)} | ${formatCell(entry.reconstructedValue)} | ${entry.delta ?? "null"} | ${entry.relativeDelta ?? "null"} | ${entry.units ?? "null"} | ${entry.status} | ${entry.note ?? "null"} |`,
    )
    .join("\n");
  const intermediateRows = payload.formulaComparison.intermediate_term_deltas
    .map(
      (entry) =>
        `| ${entry.term} | ${formatCell(entry.canonical_value)} | ${formatCell(entry.comparison_value)} | ${entry.equal} |`,
    )
    .join("\n");
  const notes = payload.notes.length
    ? payload.notes.map((entry) => `- ${entry}`).join("\n")
    : "- none";
  return `# NHM2 Source-Formula Audit (${payload.generatedOn})

"${payload.boundaryStatement}"

## Source Paths
- sourceAuditArtifact: \`${payload.sourceAuditArtifact}\`
- sourceToYorkArtifact: \`${payload.sourceToYorkArtifact}\`
- firstDivergenceArtifact: \`${payload.sourcePaths.firstDivergenceArtifact ?? "null"}\`
- canonicalPath: \`${payload.sourcePaths.canonicalPath ?? "null"}\`
- recoveryPath: \`${payload.sourcePaths.recoveryPath ?? "null"}\`
- recoveryCaseId: \`${payload.sourcePaths.recoveryCaseId ?? "null"}\`

## Policy
| field | value |
|---|---|
| authoritative_formula_path_id | ${payload.policy.authoritative_formula_path_id} |
| comparison_formula_path_id | ${payload.policy.comparison_formula_path_id} |
| comparison_path_policy | ${payload.policy.comparison_path_policy} |
| comparison_path_role | ${payload.policy.comparison_path_role} |
| comparison_path_expected_equivalence | ${payload.policy.comparison_path_expected_equivalence} |
| comparison_path_blocks_readiness | ${payload.policy.comparison_path_blocks_readiness} |
| comparison_mismatch_disposition | ${payload.policy.comparison_mismatch_disposition} |
| authoritativeFormulaPathId | ${payload.policy.authoritativeFormulaPathId} |
| comparisonFormulaPathId | ${payload.policy.comparisonFormulaPathId} |
| comparisonPathRole | ${payload.policy.comparisonPathRole} |
| comparisonPathExpectedEquivalence | ${payload.policy.comparisonPathExpectedEquivalence} |
| comparisonPathBlocksReadiness | ${payload.policy.comparisonPathBlocksReadiness} |
| comparisonMismatchDisposition | ${payload.policy.comparisonMismatchDisposition} |
| comparison_requires_formula_equivalence | ${payload.policy.comparison_requires_formula_equivalence} |

## Interpretation Policy
| field | value |
|---|---|
| policyId | ${payload.interpretationPolicy.policyId} |
| parityExpected | ${payload.interpretationPolicy.parityExpected} |
| promotionBlockedByMismatch | ${payload.interpretationPolicy.promotionBlockedByMismatch} |
| laneAUnaffectedByMismatch | ${payload.interpretationPolicy.laneAUnaffectedByMismatch} |
| interpretationStatus | ${payload.interpretationPolicy.interpretationStatus} |
| note | ${payload.interpretationPolicy.note} |

## Canonical Formula Path
| field | value |
|---|---|
| authority_id | ${payload.canonicalFormula.authority_id} |
| formula_path_id | ${payload.canonicalFormula.formula_path_id} |
| formula_class | ${payload.canonicalFormula.formula_class} |
| source_field_path | ${payload.canonicalFormula.source_field_path} |
| final_metricT00Si_Jm3 | ${payload.canonicalFormula.final_metricT00Si_Jm3 ?? "null"} |
| unit_contract | ${payload.canonicalFormula.unit_contract ?? "null"} |
| normalization_contract | ${payload.canonicalFormula.normalization_contract ?? "null"} |
| derivation_mode | ${payload.canonicalFormula.derivation_mode} |
| readiness_authoritative | ${payload.canonicalFormula.readiness_authoritative} |

### Canonical Code Paths
| path | symbol |
|---|---|
${canonicalCodeRows || "| none | none |"}

## Comparison Formula Path
| field | value |
|---|---|
| authority_id | ${payload.comparisonFormula.authority_id} |
| formula_path_id | ${payload.comparisonFormula.formula_path_id} |
| formula_class | ${payload.comparisonFormula.formula_class} |
| source_field_path | ${payload.comparisonFormula.source_field_path} |
| final_metricT00Si_Jm3 | ${payload.comparisonFormula.final_metricT00Si_Jm3 ?? "null"} |
| unit_contract | ${payload.comparisonFormula.unit_contract ?? "null"} |
| normalization_contract | ${payload.comparisonFormula.normalization_contract ?? "null"} |
| derivation_mode | ${payload.comparisonFormula.derivation_mode} |
| readiness_authoritative | ${payload.comparisonFormula.readiness_authoritative} |

### Comparison Code Paths
| path | symbol |
|---|---|
${comparisonCodeRows || "| none | none |"}

## Formula Comparison
| field | value |
|---|---|
| directFormulaId | ${payload.formulaComparison.directFormulaId ?? "null"} |
| reconstructedFormulaId | ${payload.formulaComparison.reconstructedFormulaId ?? "null"} |
| comparisonMode | ${payload.formulaComparison.comparisonMode} |
| formula_class_match | ${payload.formulaComparison.formula_class_match} |
| unit_contract_match | ${payload.formulaComparison.unit_contract_match} |
| normalization_contract_match | ${payload.formulaComparison.normalization_contract_match} |
| derivation_mode_match | ${payload.formulaComparison.derivation_mode_match} |
| mismatchReason | ${payload.formulaComparison.mismatchReason} |
| additionalMismatchReasons | ${payload.formulaComparison.additionalMismatchReasons.join(",") || "none"} |
| final_metric_delta_abs | ${payload.formulaComparison.final_metric_delta_abs ?? "null"} |
| final_metric_delta_rel | ${payload.formulaComparison.final_metric_delta_rel ?? "null"} |
| formulaEquivalent | ${payload.formulaComparison.formulaEquivalent} |
| reconstructionOnlyComparison | ${payload.formulaComparison.reconstructionOnlyComparison} |
| formulaMismatchClass | ${payload.formulaComparison.formulaMismatchClass} |

### Tolerance Policy
| field | value |
|---|---|
| relTol | ${payload.formulaComparison.tolerancePolicy.relTol} |
| absTol | ${payload.formulaComparison.tolerancePolicy.absTol} |
| numericParityRule | ${payload.formulaComparison.tolerancePolicy.numericParityRule} |
| formulaEquivalenceRequires | ${payload.formulaComparison.tolerancePolicy.formulaEquivalenceRequires.join(",")} |

### Resolved Inputs
| inputId | directValue | reconstructedValue | delta | relativeDelta | units | status | note |
|---|---|---|---|---|---|---|---|
${resolvedInputRows || "| none | null | null | null | null | null | not_comparable | null |"}

### Term Comparisons
| termId | directValue | reconstructedValue | delta | relativeDelta | units | status | note |
|---|---|---|---|---|---|---|---|
${termRows || "| none | null | null | null | null | null | not_comparable | null |"}

### Intermediate Terms (Legacy Alias)
| term | canonical_value | comparison_value | equal |
|---|---|---|---|
${intermediateRows || "| none | null | null | true |"}

## Stage
| field | value |
|---|---|
| formulaEquivalent | ${payload.stage.formulaEquivalent} |
| reconstructionOnlyComparison | ${payload.stage.reconstructionOnlyComparison} |
| formulaMismatchClass | ${payload.stage.formulaMismatchClass} |
| mismatchReason | ${payload.stage.mismatchReason} |
| sourceFormulaInterpretationPolicy | ${payload.stage.sourceFormulaInterpretationPolicy} |
| summary | ${payload.stage.summary} |

## Notes
${notes}
`;
};

const buildSourceMechanismParityRouteFeasibilityBlock = (args: {
  sourceFormulaAudit: Nhm2SourceFormulaAuditArtifact;
  sourceFormulaArtifactPath: string;
}): SourceMechanismParityRouteFeasibilityBlock => {
  const termComparisons = args.sourceFormulaAudit.formulaComparison.termComparisons;
  const matchedTerms = termComparisons
    .filter((entry) => entry.status === "matched")
    .map((entry) => entry.termId);
  const unmatchedTerms = termComparisons
    .filter((entry) => entry.status !== "matched")
    .map((entry) => entry.termId);
  const dominantMismatchEntry =
    termComparisons.find((entry) => entry.termId === "final_metricT00Si_Jm3") ??
    termComparisons.find((entry) => entry.status === "mismatched") ??
    termComparisons.find((entry) => entry.status !== "matched") ??
    null;
  const dominantMismatchTerm = dominantMismatchEntry?.termId ?? null;
  const sharedContributors = matchedTerms.includes("rhoMetric_Jm3")
    ? ["rhoMetric_Jm3"]
    : [];
  const sharedSupportingTerms = [
    "couplingAlpha",
    "metricT00SiRelError",
    "qeiSamplingNormalization",
    "qeiRenormalizationScheme",
  ].filter((termId) => matchedTerms.includes(termId));
  const directOnlyContributors =
    dominantMismatchTerm === "final_metricT00Si_Jm3"
      ? ["direct_metric_closure_term_set_beyond_rhoMetric"]
      : [];
  const reconstructedOnlyContributors = unmatchedTerms.includes(
    "metricStressRhoSiMean_Jm3",
  )
    ? ["metricStressRhoSiMean_Jm3"]
    : [];
  const unmatchedContributors = [
    ...directOnlyContributors,
    ...reconstructedOnlyContributors,
  ];
  const missingProxyTerms = [...directOnlyContributors];
  const missingDirectTerms = directOnlyContributors.length
    ? ["authoritative_direct_metric_additive_decomposition_for_final_metricT00Si_Jm3"]
    : [];
  const feasibilityStatus: SourceMechanismParityRouteFeasibilityStatus =
    unmatchedTerms.length === 0
      ? "closable_with_existing_emitted_terms"
      : !args.sourceFormulaAudit.formulaComparison.derivation_mode_match &&
          args.sourceFormulaAudit.formulaComparison.formulaMismatchClass ===
            "direct_vs_reconstructed"
        ? "blocked_by_derivation_class_difference"
        : missingDirectTerms.length > 0
          ? "closable_after_missing_term_serialization"
          : "blocked_pending_model_upgrade";
  const routeBlockingClass: SourceMechanismParityRouteBlockingClass =
    feasibilityStatus === "blocked_by_derivation_class_difference"
      ? "direct_metric_vs_reconstructed_proxy_derivation_gap"
      : feasibilityStatus === "closable_after_missing_term_serialization"
        ? "missing_metric_side_serialization"
        : missingProxyTerms.length > 0
          ? "missing_proxy_term_mapping"
          : "none";
  const closureWorkItems =
    feasibilityStatus === "blocked_by_derivation_class_difference"
      ? [
          "Serialize an additive authoritative direct-metric decomposition for final_metricT00Si_Jm3 instead of exposing only the aggregate final metric term.",
          "Define a mapped proxy closure term set beyond rhoMetric_Jm3, or upgrade the reconstructed path to a direct-metric derivation class.",
          "Re-emit the source-formula audit to show whether final_metricT00Si_Jm3 becomes term-closable or remains architecture-level non-equivalent.",
        ]
      : feasibilityStatus === "closable_after_missing_term_serialization"
        ? [
            "Emit the missing authoritative direct-metric additive decomposition for final_metricT00Si_Jm3.",
            "Re-compare the reconstructed proxy path against the newly serialized direct-side term set under the existing tolerance policy.",
          ]
        : [
            "Close the remaining direct-vs-reconstructed terms under the source-formula tolerance policy.",
          ];
  const nextClosureAction =
    feasibilityStatus === "blocked_by_derivation_class_difference"
      ? "emit_authoritative_direct_metric_closure_decomposition_and_define_proxy_mapping_contract"
      : feasibilityStatus === "closable_after_missing_term_serialization"
        ? "serialize_authoritative_direct_metric_closure_terms"
        : "re_emit_source_formula_audit_with_numeric_parity";
  const routeSummary =
    feasibilityStatus === "blocked_by_derivation_class_difference"
      ? "Parity route is not realistically closable in current architecture without a derivation-class upgrade: the reconstructed path already matches rhoMetric_Jm3 but does not carry a mapped direct-metric closure term beyond rhoMetric, and the authoritative direct path emits final_metricT00Si_Jm3 only as an aggregate."
      : feasibilityStatus === "closable_after_missing_term_serialization"
        ? "Parity route appears closable only after missing authoritative direct-side decomposition is serialized."
        : feasibilityStatus === "closable_with_existing_emitted_terms"
          ? "Parity route is closable with existing emitted terms."
          : "Parity route remains blocked pending additional model closure work.";

  return {
    routeId: "direct_proxy_parity_route",
    routeStatus: unmatchedTerms.length === 0 ? "satisfied" : "available_but_unmet",
    feasibilityStatus,
    routeBlockingClass,
    dominantMismatchTerm,
    matchedTerms,
    unmatchedTerms,
    sharedContributors,
    sharedSupportingTerms,
    directOnlyContributors,
    reconstructedOnlyContributors,
    unmatchedContributors,
    directPathDecomposition: {
      pathRole: "authoritative_direct_metric",
      formulaClass: args.sourceFormulaAudit.canonicalFormula.formula_class,
      derivationMode: args.sourceFormulaAudit.canonicalFormula.derivation_mode,
      decompositionStatus: "aggregate_authoritative_metric_term_only",
      finalMetricTermId: "final_metricT00Si_Jm3",
      contributorTerms: sharedContributors,
      sharedContributorTerms: sharedContributors,
      supportingMatchedTerms: sharedSupportingTerms,
      unavailableContributorTerms: missingDirectTerms,
      missingAdditiveBreakdown: true,
      note:
        "Canonical direct path exposes rhoMetric-scale agreement but serializes final_metricT00Si_Jm3 as an authoritative aggregate, so the residual direct-only closure contribution is not additively decomposed in current artifacts.",
    },
    reconstructedPathDecomposition: {
      pathRole: "reconstructed_proxy",
      formulaClass: args.sourceFormulaAudit.comparisonFormula.formula_class,
      derivationMode: args.sourceFormulaAudit.comparisonFormula.derivation_mode,
      decompositionStatus: "proxy_reconstruction_terms_available",
      finalMetricTermId: "final_metricT00Si_Jm3",
      contributorTerms: sharedContributors,
      sharedContributorTerms: sharedContributors,
      supportingMatchedTerms: sharedSupportingTerms,
      unavailableContributorTerms: missingProxyTerms,
      missingAdditiveBreakdown: false,
      note:
        "Reconstructed path closes at the rhoMetric-scale proxy term and emits metricStressRhoSiMean_Jm3, but does not expose a mapped direct-metric closure term beyond rhoMetric_Jm3 for final-metric parity.",
    },
    missingProxyTerms,
    missingDirectTerms,
    closureWorkItems,
    nextClosureAction,
    proofOfClosureArtifact: normalizePath(args.sourceFormulaArtifactPath),
    routeSummary,
  };
};

const computeSourceMechanismParityRouteFeasibilityChecksum = (
  payload: Nhm2SourceMechanismParityRouteFeasibilityArtifact,
): string => {
  const copy = JSON.parse(JSON.stringify(payload)) as Record<string, unknown>;
  delete copy.generatedAt;
  delete copy.checksum;
  return crypto.createHash("sha256").update(stableStringify(copy)).digest("hex");
};

export const buildNhm2SourceMechanismParityRouteFeasibilityArtifact = (args: {
  payload: ProofPackPayload;
  sourceFormulaAudit: Nhm2SourceFormulaAuditArtifact;
  sourceFormulaArtifactPath: string;
  sourceMechanismPromotionContractArtifactPath: string;
  sourceMechanismMaturityArtifactPath: string;
}): Nhm2SourceMechanismParityRouteFeasibilityArtifact => {
  const sourceMechanismParityRouteFeasibility =
    buildSourceMechanismParityRouteFeasibilityBlock({
      sourceFormulaAudit: args.sourceFormulaAudit,
      sourceFormulaArtifactPath: args.sourceFormulaArtifactPath,
    });
  const payloadBase: Nhm2SourceMechanismParityRouteFeasibilityArtifact = {
    artifactType: "nhm2_source_mechanism_parity_route_feasibility/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This artifact evaluates whether the direct_proxy_parity_route is realistically closable in the current architecture; it does not itself promote the source/mechanism lane or alter Lane A.",
    sourceFormulaArtifact: normalizePath(args.sourceFormulaArtifactPath),
    sourceMechanismPromotionContractArtifact: normalizePath(
      args.sourceMechanismPromotionContractArtifactPath,
    ),
    sourceMechanismMaturityArtifact: normalizePath(
      args.sourceMechanismMaturityArtifactPath,
    ),
    sourceMechanismParityRouteFeasibility,
    notes: [
      `route_status=${sourceMechanismParityRouteFeasibility.routeStatus}; feasibility_status=${sourceMechanismParityRouteFeasibility.feasibilityStatus}; blocking_class=${sourceMechanismParityRouteFeasibility.routeBlockingClass}.`,
      `dominant_mismatch_term=${sourceMechanismParityRouteFeasibility.dominantMismatchTerm ?? "none"}; matched_terms=${sourceMechanismParityRouteFeasibility.matchedTerms.join(",") || "none"}; unmatched_terms=${sourceMechanismParityRouteFeasibility.unmatchedTerms.join(",") || "none"}.`,
      `missing_proxy_terms=${sourceMechanismParityRouteFeasibility.missingProxyTerms.join(",") || "none"}; missing_direct_terms=${sourceMechanismParityRouteFeasibility.missingDirectTerms.join(",") || "none"}.`,
    ],
  };
  return {
    ...payloadBase,
    checksum: computeSourceMechanismParityRouteFeasibilityChecksum(payloadBase),
  };
};

