const buildYorkPaperComparisonMatrix = (args: {
  payload: ProofPackPayload;
  renderMatchesGeometry: boolean;
}): YorkPaperComparisonRecord[] => {
  const scoring = args.payload.classificationScoring;
  const verdict = args.payload.verdict;
  const nhm2NatarioAligned =
    scoring?.winning_reference === "natario_control" &&
    scoring.margin_sufficient === true &&
    verdict === NHM2_DIAGNOSTIC_OUTCOME.LOW_EXPANSION_LIKE;
  const nhm2AlcubierreAligned =
    scoring?.winning_reference === "alcubierre_control" &&
    verdict === NHM2_DIAGNOSTIC_OUTCOME.ALCUBIERRE_LIKE;

  return [
    {
      reference_id: "alcubierre_primary",
      source_link: "https://arxiv.org/abs/gr-qc/0009013",
      convention_match_status: "matched",
      observer_match_status: "matched",
      foliation_match_status: "matched",
      theta_match_status: "matched",
      sign_match_status: "matched",
      morphology_match_status: nhm2AlcubierreAligned ? "matched" : "morphology_different",
      comparison_scope:
        "Lane A only; compare the authoritative Eulerian 3+1 York morphology against Alcubierre's signed fore/aft expansion pattern.",
      difference_causes: nhm2AlcubierreAligned ? [] : ["real_nhm2_morphology_difference"],
      notes: [
        "The convention bridge is direct: both sides are evaluated in an Eulerian 3+1 interpretation.",
        nhm2AlcubierreAligned
          ? "NHM2 currently falls inside the Alcubierre-like signed-lobe class under Lane A."
          : "NHM2 does not reproduce Alcubierre's strong signed fore/aft lobe morphology under the authoritative Lane A diagnostic.",
      ],
    },
    {
      reference_id: "natario_primary",
      source_link: "https://arxiv.org/abs/gr-qc/0110086",
      convention_match_status: "compatible_after_sign_flip",
      observer_match_status: "matched",
      foliation_match_status: "matched",
      theta_match_status: "compatible_after_sign_flip",
      sign_match_status: "compatible_after_sign_flip",
      morphology_match_status: nhm2NatarioAligned
        ? "compatible_after_observer_scope_note"
        : "morphology_different",
      comparison_scope:
        "Lane A only; compare the authoritative Eulerian low-expansion morphology against Natario's zero-expansion/volume-preserving family after sign alignment.",
      difference_causes: nhm2NatarioAligned ? [] : ["real_nhm2_morphology_difference"],
      notes: [
        "Natario's expansion is expressed as div(X), so the comparison requires a sign-convention bridge to the repo's theta=-trK contract.",
        nhm2NatarioAligned
          ? "NHM2 matches the Natario-like low-expansion class after convention alignment, but the claim remains lane-local rather than metric-identical."
          : "NHM2 does not land in the Natario-like low-expansion class under the current authoritative Lane A classification.",
      ],
    },
    {
      reference_id: "gourgoulhon_3p1_reference",
      source_link: "https://arxiv.org/abs/gr-qc/0703035",
      convention_match_status: "matched",
      observer_match_status: "matched",
      foliation_match_status: "matched",
      theta_match_status: "matched",
      sign_match_status: "matched",
      morphology_match_status: "not_comparable_without_reprojection",
      comparison_scope:
        "Formalism-only bridge for the Lane A Eulerian theta=-trK interpretation; not a warp-bubble morphology comparator.",
      difference_causes: ["not_comparable_without_convention_remap"],
      notes: [
        args.renderMatchesGeometry
          ? "The render side is already parity-closed to the authoritative Lane A geometry, so Gourgoulhon is used only to justify the theta/sign bridge."
          : "The formalism bridge holds, but the current render path would need parity closure before it can support morphology claims.",
        "This source does not by itself define a warp-bubble lobe pattern.",
      ],
    },
  ];
};

export const buildNhm2YorkRenderDebugArtifact = (args: {
  payload: ProofPackPayload;
  solveAuthorityAudit: Nhm2SolveAuthorityAuditArtifact;
  sourceAuditArtifactPath: string;
  solveAuthorityAuditPath: string;
  diagnosticContractPath?: string;
}): Nhm2YorkRenderDebugArtifact => {
  const authoritativeLaneId =
    args.payload.diagnosticContract.diagnostic_policy
      .authoritativeLaneIdsForMechanismReadiness[0] ??
    args.payload.diagnosticContract.baseline_lane_id;
  const authoritativeLaneContract =
    args.payload.diagnosticContract.lanes.find(
      (entry) => entry.lane_id === authoritativeLaneId,
    ) ?? args.payload.diagnosticContract.lanes[0];
  if (!authoritativeLaneContract) {
    throw new Error("render_debug_authoritative_lane_missing");
  }
  const authoritativeLaneEvaluation =
    args.payload.diagnosticLanes.find((entry) => entry.lane_id === authoritativeLaneId) ?? null;
  if (!authoritativeLaneEvaluation) {
    throw new Error("render_debug_authoritative_lane_evaluation_missing");
  }

  const closedAuthorityStages: YorkRenderPolicy["closedAuthorityStages"] = [];
  if (args.solveAuthorityAudit.readiness.sourceAuthorityClosed) closedAuthorityStages.push("source");
  if (args.solveAuthorityAudit.readiness.timingAuthorityClosed) closedAuthorityStages.push("timing");
  if (args.solveAuthorityAudit.readiness.brickAuthorityClosed) closedAuthorityStages.push("brick");
  if (args.solveAuthorityAudit.readiness.snapshotAuthorityClosed) {
    closedAuthorityStages.push("snapshot");
  }
  if (args.solveAuthorityAudit.readiness.diagnosticAuthorityClosed) {
    closedAuthorityStages.push("diagnostic");
  }

  const renderPolicy: YorkRenderPolicy = {
    authoritativeLaneId,
    authoritativeLaneLabel: "Lane A authoritative mechanism-readiness comparison lane",
    advisoryLaneIds: args.payload.diagnosticLanes
      .filter((entry) => entry.lane_id !== authoritativeLaneId)
      .map((entry) => entry.lane_id),
    laneBReferenceOnly:
      args.payload.diagnosticLanes.find(
        (entry) => entry.lane_id === YORK_DIAGNOSTIC_ALTERNATE_LANE_ID,
      )?.is_reference_only === true,
    laneBCanOverrideAuthoritativeComparison: false,
    mechanismChainReady: args.solveAuthorityAudit.readiness.mechanismChainReady,
    closedAuthorityStages,
    imagesUsedAsPrimaryEvidence: false,
  };
  const laneUsed: YorkLaneUsedSummary = {
    lane_id: authoritativeLaneContract.lane_id,
    observer: authoritativeLaneContract.observer,
    observer_definition: authoritativeLaneContract.observer_definition_id,
    foliation: authoritativeLaneContract.foliation,
    foliation_definition: authoritativeLaneContract.foliation_definition,
    theta_definition: authoritativeLaneContract.theta_definition,
    sign_convention: authoritativeLaneContract.kij_sign_convention,
    normalization_rules: { ...authoritativeLaneContract.normalization_rules },
    view_geometry: { ...authoritativeLaneContract.coordinate_views },
    scope_note:
      "Lane A is the only authoritative lane for mechanism-readiness and paper comparison. Lane B remains advisory/reference-only and cannot override Lane A conclusions.",
  };

  const representativeCase =
    args.payload.cases.find((entry) => entry.caseId === "nhm2_certified") ?? args.payload.cases[0];
  if (!representativeCase) {
    throw new Error("render_debug_cases_missing");
  }

  const viewDefinitions: YorkViewDefinition[] = REQUIRED_YORK_VIEWS.map((viewId) => {
    const view =
      representativeCase.perView.find((entry) => entry.view === viewId) ??
      representativeCase.perView[0];
    return {
      view_id: viewId,
      coordinate_mode: view?.render.coordinate_mode ?? null,
      slice_plane: view?.render.slice_plane ?? null,
      sampling_choice: view?.samplingChoice ?? null,
      view_geometry: describeYorkViewGeometry(viewId),
      support_overlay: view?.render.support_overlay ?? null,
      normalization: view?.render.normalization ?? null,
      magnitude_mode: view?.render.magnitude_mode ?? null,
      surface_height: view?.render.surface_height ?? null,
    };
  });

  const frameDebugSummary: YorkFrameDebugRecord[] = args.payload.cases.flatMap((caseResult) =>
    REQUIRED_YORK_VIEWS.map((viewId) => {
      const renderView =
        caseResult.perView.find((entry) => entry.view === viewId) ??
        caseResult.perView[0] ??
        null;
      const offlineAudit =
        renderView == null ? null : resolveOfflineAuditForRenderView(caseResult, renderView);
      const shellActivity =
        renderView?.shellSupportCount != null &&
        renderView?.shellSupportCount > 0 &&
        renderView?.shellActiveCount != null
          ? renderView.shellActiveCount / renderView.shellSupportCount
          : viewId === "york-shell-map-3p1"
            ? caseResult.classificationFeatures.shell_map_activity
            : null;
      return {
        case_id: caseResult.caseId,
        view_id: viewId,
        theta_min: renderView?.rawExtrema.min ?? null,
        theta_max: renderView?.rawExtrema.max ?? null,
        theta_abs_max: renderView?.rawExtrema.absMax ?? null,
        positive_count: offlineAudit?.counts.positive ?? null,
        negative_count: offlineAudit?.counts.negative ?? null,
        near_zero_count: offlineAudit?.counts.zeroOrNearZero ?? null,
        signed_lobe_summary:
          offlineAudit?.coordinateMode === "x-z-midplane"
            ? caseResult.offlineYorkAudit?.alcubierreSignedLobeSummary?.signedLobeSummary ?? null
            : null,
        shell_activity: shellActivity ?? null,
        normalization_gain: renderView?.displayExtrema.gain ?? null,
        color_scale_mode: renderView == null ? "unavailable" : deriveYorkColorScaleMode(renderView),
        clipping_applied: renderView == null ? false : hasYorkDisplayClipping(renderView),
        hashes: {
          certificate_hash: renderView?.hashes.certificate_hash ?? null,
          frame_hash: renderView?.hashes.frame_hash ?? null,
          theta_channel_hash: renderView?.hashes.theta_channel_hash ?? null,
          slice_array_hash: renderView?.hashes.slice_array_hash ?? null,
          normalized_slice_hash: renderView?.hashes.normalized_slice_hash ?? null,
          support_mask_slice_hash: renderView?.hashes.support_mask_slice_hash ?? null,
          shell_masked_slice_hash: renderView?.hashes.shell_masked_slice_hash ?? null,
          metric_ref_hash: renderView?.identity.metric_ref_hash ?? null,
        },
        note: renderView?.note ?? null,
      };
    }),
  );

  const nhm2Case =
    args.payload.cases.find((entry) => entry.caseId === "nhm2_certified") ?? null;
  const renderMatchesGeometry =
    nhm2Case?.parity?.renderParityPass === true &&
    nhm2Case.parity.byView.every(
      (entry) =>
        entry.status === "pass" &&
        (entry.thetaVsRenderMaxAbsResidual ?? 0) === 0 &&
        entry.identity.complete === true,
    ) === true;

  const normalizationPolicy: YorkNormalizationPolicy = {
    contract_rules: { ...args.payload.diagnosticContract.normalization_rules },
    raw_surface_rule: "Raw York surfaces keep signed theta amplitude with symmetric-about-zero normalization.",
    topology_surface_rule:
      "The topology-normalized view adds unit-max scaling to preserve sign topology while discarding absolute amplitude.",
    raw_display_gain_rule: "display_gain must remain 1 for raw York views under the current contract.",
    render_range_method:
      representativeCase.primaryYork.displayExtrema?.rangeMethod ??
      "computeSliceRange:diverging:p98-abs-symmetric",
    display_gain_expected: 1,
    topology_normalization_scope:
      "Topology-only normalization is display-only and does not alter the underlying raw theta hashes.",
    notes: [
      "Display amplitudes are shaped by a symmetric percentile range, so visual height/color saturation should not be read as raw amplitude.",
      "Parity stays closed because raw theta hashes and render hashes still match exactly on the authoritative lane.",
    ],
  };
  const colorPolicy: YorkColorPolicy = {
    signed_color_family: "diverging blue-white-red",
    signed_color_midpoint: "white maps to near-zero signed theta",
    mode_by_view: viewDefinitions.map((entry) => ({
      view_id: entry.view_id,
      color_scale_mode:
        entry.view_id === "york-topology-normalized-3p1"
          ? "signed_diverging_unit_max"
          : entry.view_id === "york-shell-map-3p1"
            ? "signed_diverging_shell_localized"
            : "signed_diverging_p98_symmetric",
      sign_encoding: "negative theta -> blue branch, positive theta -> red branch",
    })),
    notes: [
      "Color encodes sign, not authority: Lane A is authoritative because of policy and parity closure, not because of image appearance.",
      "Shell-map coloring adds support-overlay context but does not change the signed-theta field itself.",
    ],
  };
  const signPolicy: YorkSignPolicy = {
    lane_theta_definition: authoritativeLaneContract.theta_definition,
    lane_sign_convention: authoritativeLaneContract.kij_sign_convention,
    lane_theta_source:
      nhm2Case?.snapshotMetrics?.laneComputation?.theta_source ?? "canonical_theta_channel",
    parity_source: "Lane A parity enforces theta-channel == render slice == -K trace reconstruction on required views.",
    paper_alignment_note:
      "Alcubierre aligns directly with the Lane A Eulerian sign convention; Natario requires a sign-convention bridge because the paper expresses expansion as div(X).",
  };
  const clippingPolicy: YorkClippingPolicy = {
    display_range_method:
      representativeCase.primaryYork.displayExtrema?.rangeMethod ??
      "computeSliceRange:diverging:p98-abs-symmetric",
    percentile_window: "2nd to 98th percentile, symmetric about zero for diverging York views",
    clipping_is_display_only: true,
    topology_view_adds_unit_max_normalization: true,
    clipping_detected_by:
      "display_range_method metadata, display-vs-raw extrema comparison, and topology normalized-slice hashes",
  };
  const nearZeroPolicy: YorkNearZeroPolicy = {
    theta_abs_threshold: YORK_RENDER_NEAR_ZERO_THETA_ABS_THRESHOLD,
    signed_structure_relative_floor: YORK_RENDER_SIGNED_STRUCTURE_RELATIVE_FLOOR,
    requires_signed_structure_to_escape_near_zero: true,
    note: "Near-zero suppression only applies when absolute amplitude is tiny and there is no meaningful signed structure above the relative structural floor.",
  };

  const controlComparison: YorkControlComparisonRecord[] = [
    {
      reference_case_id: "alcubierre_control",
      reference_role:
        args.payload.diagnosticContract.reference_controls.alcubierre_control.role,
      signed_lobe_expectation: "fore+/aft- signed-lobe control under Lane A",
      nhm2_distance:
        args.payload.classificationScoring?.distance_to_alcubierre_reference ?? null,
      nhm2_match_status:
        args.payload.classificationScoring?.winning_reference === "alcubierre_control"
          ? "matched"
          : "morphology_different",
      rendered_frame_reflects_numeric_classification: renderMatchesGeometry,
      required_views: REQUIRED_YORK_VIEWS.map((viewId) => {
        const nhm2View = nhm2Case?.perView.find((entry) => entry.view === viewId) ?? null;
        const controlCase =
          args.payload.cases.find((entry) => entry.caseId === "alcubierre_control") ?? null;
        const controlView = controlCase?.perView.find((entry) => entry.view === viewId) ?? null;
        return {
          view_id: viewId,
          nhm2_slice_hash: nhm2View?.hashes.slice_array_hash ?? null,
          reference_slice_hash: controlView?.hashes.slice_array_hash ?? null,
          same_coordinate_mode:
            nhm2View?.render.coordinate_mode != null &&
            nhm2View.render.coordinate_mode === controlView?.render.coordinate_mode,
        };
      }),
      notes: [
        "This control is the calibrated signed-lobe reference for Alcubierre-style Eulerian morphology.",
        "A large NHM2-vs-Alcubierre distance with parity closed indicates a genuine morphology difference rather than a render mismatch.",
      ],
    },
    {
      reference_case_id: "natario_control",
      reference_role: args.payload.diagnosticContract.reference_controls.natario_control.role,
      signed_lobe_expectation: "low-expansion / zero-expansion comparison control under Lane A",
      nhm2_distance:
        args.payload.classificationScoring?.distance_to_low_expansion_reference ?? null,
      nhm2_match_status:
        args.payload.classificationScoring?.winning_reference === "natario_control"
          ? "compatible_after_observer_scope_note"
          : "morphology_different",
      rendered_frame_reflects_numeric_classification: renderMatchesGeometry,
      required_views: REQUIRED_YORK_VIEWS.map((viewId) => {
        const nhm2View = nhm2Case?.perView.find((entry) => entry.view === viewId) ?? null;
        const controlCase =
          args.payload.cases.find((entry) => entry.caseId === "natario_control") ?? null;
        const controlView = controlCase?.perView.find((entry) => entry.view === viewId) ?? null;
        return {
          view_id: viewId,
          nhm2_slice_hash: nhm2View?.hashes.slice_array_hash ?? null,
          reference_slice_hash: controlView?.hashes.slice_array_hash ?? null,
          same_coordinate_mode:
            nhm2View?.render.coordinate_mode != null &&
            nhm2View.render.coordinate_mode === controlView?.render.coordinate_mode,
        };
      }),
      notes: [
        "This control bridges the primary Natario reference into the repo's calibrated control family.",
        "A tiny NHM2-vs-Natario-control distance with parity closed means the visual low-expansion morphology is already numerically backed.",
      ],
    },
  ];

  const paperReferenceMatrix = buildYorkPaperReferenceMatrix();
  const paperComparisonMatrix = buildYorkPaperComparisonMatrix({
    payload: args.payload,
    renderMatchesGeometry,
  });
  const differenceCauses = Array.from(
    new Set<YorkRenderDebugCauseClass>([
      "display_normalization_difference",
      ...paperComparisonMatrix.flatMap((entry) => entry.difference_causes),
    ]),
  ).filter((entry) => entry !== "not_comparable_without_convention_remap");
  const render_debug_verdict: YorkRenderDebugVerdict = renderMatchesGeometry
    ? "render_matches_authoritative_geometry"
    : "render_distorted_by_display_policy";
  const paper_comparison_verdict: YorkPaperComparisonVerdict =
    paperComparisonMatrix.some(
      (entry) =>
        entry.reference_id === "natario_primary" &&
        entry.morphology_match_status !== "morphology_different",
    )
      ? "paper_match_after_convention_alignment"
      : paperComparisonMatrix.some(
            (entry) => entry.morphology_match_status === "not_comparable_without_reprojection",
          )
        ? "paper_noncomparable_without_reprojection"
        : "nhm2_morphology_genuinely_differs_from_paper_reference";
  const dominant_difference_cause: YorkRenderDebugCauseClass =
    paperComparisonMatrix.find((entry) => entry.reference_id === "alcubierre_primary")
      ?.morphology_match_status === "morphology_different"
      ? "real_nhm2_morphology_difference"
      : "display_normalization_difference";
  const notes: string[] = [
    "Lane A remains the authoritative comparison lane for this artifact; Lane B is retained only for advisory/reference context.",
    `Render parity for NHM2 Lane A is ${renderMatchesGeometry ? "closed" : "open"}, so image appearance is interpreted only after hash/parity checks.`,
    `NHM2 classification distances: to Natario control=${args.payload.classificationScoring?.distance_to_low_expansion_reference ?? "null"}; to Alcubierre control=${args.payload.classificationScoring?.distance_to_alcubierre_reference ?? "null"}.`,
    "Primary-paper comparison is scope-limited to observer/foliation/sign-aligned Lane A semantics and does not assert invariant theory identity from image similarity.",
  ];

  const payloadBase: Nhm2YorkRenderDebugArtifact = {
    artifactType: "nhm2_york_render_debug/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This render-debug artifact audits York-frame display policy and primary-paper comparability under the closed Lane A mechanism chain; images are not treated as primary evidence.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    solveAuthorityAuditPath: normalizePath(args.solveAuthorityAuditPath),
    diagnosticContractPath: normalizePath(
      args.diagnosticContractPath ?? YORK_DIAGNOSTIC_CONTRACT_PATH,
    ),
    renderPolicy,
    laneUsed,
    viewDefinitions,
    normalizationPolicy,
    colorPolicy,
    signPolicy,
    clippingPolicy,
    nearZeroPolicy,
    frameDebugSummary,
    controlComparison,
    paperReferenceMatrix,
    paperComparisonMatrix,
    differenceCauses,
    render_debug_verdict,
    paper_comparison_verdict,
    dominant_difference_cause,
    lane_used_for_authoritative_comparison: authoritativeLaneId,
    images_used_as_primary_evidence: false,
    notes,
  };

  return {
    ...payloadBase,
    checksum: computeNhm2YorkRenderDebugChecksum(payloadBase),
  };
};

