const computeThetaPlusKTraceConsistency = (theta: Float32Array, kTrace: Float32Array) => {
  const n = Math.min(theta.length, kTrace.length);
  if (n <= 0) {
    return { rms: null, maxAbs: null, mean: null, sampleCount: 0, consistent: false };
  }
  let sum = 0;
  let sumSq = 0;
  let maxAbs = 0;
  let sampleCount = 0;
  let maxSignal = 0;
  for (let i = 0; i < n; i += 1) {
    const tv = Number(theta[i] ?? Number.NaN);
    const kv = Number(kTrace[i] ?? Number.NaN);
    if (!Number.isFinite(tv) || !Number.isFinite(kv)) continue;
    const residual = tv + kv;
    sum += residual;
    sumSq += residual * residual;
    maxAbs = Math.max(maxAbs, Math.abs(residual));
    maxSignal = Math.max(maxSignal, Math.abs(tv), Math.abs(kv));
    sampleCount += 1;
  }
  if (sampleCount <= 0) {
    return { rms: null, maxAbs: null, mean: null, sampleCount: 0, consistent: false };
  }
  const mean = sum / sampleCount;
  const rms = Math.sqrt(sumSq / sampleCount);
  const tolerance = Math.max(1e-12, maxSignal * 1e-6);
  return {
    rms,
    maxAbs,
    mean,
    sampleCount,
    consistent: maxAbs <= tolerance,
  };
};

export const readSourceFamilyEvidence = (snapshot: {
  stats: Record<string, unknown> | null;
  meta: Record<string, unknown> | null;
}): SourceFamilyEvidence => {
  const hasSourceFamilyEvidence = (mapping: Record<string, unknown> | null): boolean => {
    if (!mapping) return false;
    return (
      asText(mapping.family_id) !== null ||
      asText(mapping.metricT00Ref) !== null ||
      asText(mapping.warpFieldType) !== null ||
      asText(mapping.source_branch) !== null ||
      asText(mapping.shape_function_id) !== null
    );
  };
  const statsRoot = asRecord(snapshot.stats);
  const stressEnergyStats = asRecord(statsRoot?.stressEnergy);
  const preferredMapping = asRecord(stressEnergyStats?.mapping);
  const fallbackStressEnergy = asRecord(snapshot.meta?.stressEnergy);
  const fallbackMapping = asRecord(fallbackStressEnergy?.mapping);
  const selectedMapping = hasSourceFamilyEvidence(preferredMapping)
    ? preferredMapping
    : hasSourceFamilyEvidence(fallbackMapping)
      ? fallbackMapping
      : null;
  return {
    family_id: asText(selectedMapping?.family_id),
    metricT00Ref: asText(selectedMapping?.metricT00Ref),
    warpFieldType: asText(selectedMapping?.warpFieldType),
    source_branch: asText(selectedMapping?.source_branch),
    shape_function_id: asText(selectedMapping?.shape_function_id),
  };
};

const REDESIGN_MATTER_CHANNEL_IDS = [
  "rho",
  "Sx",
  "Sy",
  "Sz",
  "S_xx",
  "S_yy",
  "S_zz",
  "S_xy",
  "S_xz",
  "S_yz",
] as const;

const REDESIGN_GEOMETRY_CHANNEL_IDS = [
  "theta",
  "K_trace",
  "alpha",
  "beta_x",
  "beta_y",
  "beta_z",
  "gamma_xx",
  "gamma_xy",
  "gamma_xz",
  "gamma_yy",
  "gamma_yz",
  "gamma_zz",
] as const;

type YorkOptixNumericField = Float32Array | Float64Array;

const hashYorkOptixNumericField = (data: YorkOptixNumericField): string => {
  if (data instanceof Float32Array) {
    return hashFloat32(data);
  }
  return crypto
    .createHash("sha256")
    .update(Buffer.from(data.buffer, data.byteOffset, data.byteLength))
    .digest("hex");
};

const computeOptionalNumericFieldHash = (
  data: YorkOptixNumericField | null | undefined,
): string | null =>
  (data instanceof Float32Array || data instanceof Float64Array) && data.length > 0
    ? hashYorkOptixNumericField(data)
    : null;

const computeOptionalFloat32Hash = (
  data: Float32Array | null | undefined,
): string | null => computeOptionalNumericFieldHash(data);

const computeSnapshotChannelSetHash = (
  snapshot: {
    channels: Record<string, { data: Float32Array } | undefined>;
  },
  channelIds: readonly string[],
): string | null => {
  const pairs: string[] = [];
  for (const channelId of [...channelIds].sort((lhs, rhs) => lhs.localeCompare(rhs))) {
    const hash = computeOptionalNumericFieldHash(snapshot.channels[channelId]?.data);
    if (hash) pairs.push(`${channelId}:${hash}`);
  }
  if (pairs.length === 0) return null;
  return crypto.createHash("sha256").update(pairs.join("|")).digest("hex");
};

const computeSourceFamilyEvidenceHash = (
  sourceFamily: SourceFamilyEvidence,
): string | null => {
  const hasEvidence =
    sourceFamily.family_id != null ||
    sourceFamily.metricT00Ref != null ||
    sourceFamily.warpFieldType != null ||
    sourceFamily.source_branch != null ||
    sourceFamily.shape_function_id != null;
  return hasEvidence ? computeDeterministicHash(sourceFamily) : null;
};

const computeRmsFromFloat32 = (data: Float32Array | null | undefined): number | null => {
  if (!(data instanceof Float32Array) || data.length === 0) return null;
  let sumSq = 0;
  for (let i = 0; i < data.length; i += 1) sumSq += data[i] * data[i];
  return Math.sqrt(sumSq / data.length);
};

const computeMaxAbsFromFloat32 = (data: Float32Array | null | undefined): number | null => {
  if (!(data instanceof Float32Array) || data.length === 0) return null;
  let out = 0;
  for (let i = 0; i < data.length; i += 1) {
    const value = Math.abs(data[i]);
    if (value > out) out = value;
  }
  return out;
};

const buildAuthoritativeLowExpansionGateFromSnapshot = (args: {
  snapshot: HullScientificSnapshot;
  thetaPlusKTrace: CaseSnapshotMetrics["thetaPlusKTrace"];
}): NonNullable<CaseSnapshotMetrics["authoritativeLowExpansionGate"]> => {
  const stats = asRecord(args.snapshot.stats);
  const divBetaChannel =
    args.snapshot.channels.div_beta?.data instanceof Float32Array
      ? args.snapshot.channels.div_beta.data
      : null;
  const divergenceRms =
    toFiniteNumber(stats.divBetaRms) ?? computeRmsFromFloat32(divBetaChannel);
  const divergenceMaxAbs =
    toFiniteNumber(stats.divBetaMaxAbs) ?? computeMaxAbsFromFloat32(divBetaChannel);
  const source = asText(stats.divBetaSource) ?? (divBetaChannel ? "gr_evolve_brick" : null);
  const thetaKResidualMaxAbs = args.thetaPlusKTrace.maxAbs;
  const thetaKConsistencyStatus: "pass" | "fail" | "unknown" =
    thetaKResidualMaxAbs == null
      ? "unknown"
      : thetaKResidualMaxAbs <= THETA_K_TOLERANCE
        ? "pass"
        : "fail";
  const status: "pass" | "fail" | "missing" =
    divergenceRms == null || source == null || thetaKConsistencyStatus === "unknown"
      ? "missing"
      : divergenceRms <= NATARIO_EXPANSION_TOLERANCE &&
          thetaKConsistencyStatus === "pass"
        ? "pass"
        : "fail";
  const reason =
    status === "missing"
      ? divergenceRms == null || source == null
        ? "brick_native_div_beta_missing"
        : "theta_k_consistency_missing"
      : divergenceRms != null && divergenceRms > NATARIO_EXPANSION_TOLERANCE
        ? "brick_native_divergence_constraint_failed"
        : thetaKConsistencyStatus === "fail"
          ? "theta_k_consistency_failed"
          : "authoritative_low_expansion_ok";
  return {
    status,
    reason,
    source,
    proxy: false,
    divergenceObservable: "div_beta",
    divergenceRms,
    divergenceMaxAbs,
    divergenceTolerance: NATARIO_EXPANSION_TOLERANCE,
    thetaKConsistencyStatus,
    thetaKResidualMaxAbs,
    thetaKTolerance: THETA_K_TOLERANCE,
  };
};

const computeLaneTensorInputsHashFromSnapshot = (args: {
  snapshot: {
    channels: Record<string, { data: Float32Array } | undefined>;
  };
  requiredInputs: string[];
}): string | null => {
  if (args.requiredInputs.length === 0) return null;
  const pairs: string[] = [];
  for (const channelId of args.requiredInputs) {
    const data = args.snapshot.channels[channelId]?.data;
    if (!(data instanceof Float32Array) || data.length === 0) return null;
    pairs.push(`${channelId}:${hashFloat32(data)}`);
  }
  return crypto
    .createHash("sha256")
    .update(pairs.join("|"))
    .digest("hex");
};

const runCase = async (args: {
  diagnosticLane: YorkDiagnosticLane;
  caseId: CaseId;
  label: string;
  familyExpectation: CaseResult["familyExpectation"];
  metricVolumeRef: HullMetricVolumeRefV1;
  frameEndpoint: string;
  proxyFrameEndpoint: string | null;
  compareDirectAndProxy: boolean;
  requireCongruentNhm2FullSolve: boolean;
  yorkViews: HullScientificRenderView[];
  frameSize: { width: number; height: number };
}): Promise<CaseResult> => {
  const perView: YorkViewSummary[] = [];
  const laneConfigs: Array<{ lane: YorkRenderLane; endpoint: string }> =
    args.compareDirectAndProxy && args.proxyFrameEndpoint
      ? [
          { lane: "direct", endpoint: args.frameEndpoint },
          { lane: "proxy", endpoint: args.proxyFrameEndpoint },
        ]
      : [{ lane: "single", endpoint: args.frameEndpoint }];
  for (const view of args.yorkViews) {
    const payload = buildYorkPayload({
      caseId: args.caseId,
      renderView: view,
      diagnosticLaneId: args.diagnosticLane.lane_id,
      metricVolumeRef: args.metricVolumeRef,
      requireCongruentNhm2FullSolve: args.requireCongruentNhm2FullSolve,
      width: args.frameSize.width,
      height: args.frameSize.height,
    });
    const laneSummaries: YorkViewSummary[] = [];
    for (const laneConfig of laneConfigs) {
      laneSummaries.push(
        await renderYorkView({
          frameEndpoint: laneConfig.endpoint,
          payload,
          view,
          lane: laneConfig.lane,
        }),
      );
    }
    const selected =
      laneSummaries.find((entry) => entry.ok) ??
      laneSummaries.find((entry) => entry.sourceLane === "direct") ??
      laneSummaries[0];
    const laneResults: YorkLaneResultSummary[] = laneSummaries.map((entry) => ({
      lane: entry.sourceLane ?? "single",
      endpoint: entry.endpoint ?? args.frameEndpoint,
      ok: entry.ok,
      httpStatus: entry.httpStatus,
      errorCode: entry.errorCode,
      responseMessage: entry.responseMessage,
      preflightBranch: entry.preflightBranch,
      preflightRequirement: entry.preflightRequirement,
      error: entry.error,
    }));
    perView.push({
      ...selected,
      laneResults,
    });
  }

  let snapshotMetrics: CaseSnapshotMetrics | null = null;
  let offlineYorkAudit: CaseOfflineYorkAudit | null = null;
  let parity: CaseLaneAParityAudit | null = null;
  try {
    const snapshot = await loadProofPackSnapshot(
      args.metricVolumeRef,
      PROOF_PACK_SNAPSHOT_TIMEOUT_MS,
    );
    const thetaCanonical = snapshot.channels.theta?.data;
    const kTrace = snapshot.channels.K_trace?.data;
    const laneId: YorkDiagnosticLaneId | null = isYorkDiagnosticLaneId(
      args.diagnosticLane.lane_id,
    )
      ? args.diagnosticLane.lane_id
      : null;
    const laneField =
      laneId != null
        ? computeYorkDiagnosticLaneField({
            laneId,
            dims: snapshot.dims,
            voxelSizeM: snapshot.voxelSize_m,
            theta: thetaCanonical instanceof Float32Array ? thetaCanonical : null,
            kTrace: kTrace instanceof Float32Array ? kTrace : null,
            betaX:
              snapshot.channels.beta_x?.data instanceof Float32Array
                ? snapshot.channels.beta_x.data
                : null,
            betaY:
              snapshot.channels.beta_y?.data instanceof Float32Array
                ? snapshot.channels.beta_y.data
                : null,
            betaZ:
              snapshot.channels.beta_z?.data instanceof Float32Array
                ? snapshot.channels.beta_z.data
                : null,
            alpha:
              snapshot.channels.alpha?.data instanceof Float32Array
                ? snapshot.channels.alpha.data
                : null,
            gammaXX:
              snapshot.channels.gamma_xx?.data instanceof Float32Array
                ? snapshot.channels.gamma_xx.data
                : null,
            gammaXY:
              snapshot.channels.gamma_xy?.data instanceof Float32Array
                ? snapshot.channels.gamma_xy.data
                : null,
            gammaXZ:
              snapshot.channels.gamma_xz?.data instanceof Float32Array
                ? snapshot.channels.gamma_xz.data
                : null,
            gammaYY:
              snapshot.channels.gamma_yy?.data instanceof Float32Array
                ? snapshot.channels.gamma_yy.data
                : null,
            gammaYZ:
              snapshot.channels.gamma_yz?.data instanceof Float32Array
                ? snapshot.channels.gamma_yz.data
                : null,
            gammaZZ:
              snapshot.channels.gamma_zz?.data instanceof Float32Array
                ? snapshot.channels.gamma_zz.data
                : null,
          })
        : {
            ok: false as const,
            error: "scientific_york_lane_tensor_missing" as const,
            missingChannels: ["diagnostic_lane_id"],
          };
    const thetaLane = laneField.ok ? laneField.theta : null;
    const contractField = laneField.ok ? laneField.contractField : null;
    const runtimeLaneEvidence =
      perView.find(
        (entry) =>
          entry.ok === true && entry.identity.lane_id === args.diagnosticLane.lane_id,
      )?.laneEvidence ?? null;
    const laneTensorInputsHash = laneField.ok
      ? computeLaneTensorInputsHashFromSnapshot({
          snapshot,
          requiredInputs: laneField.observerConstruction.observer_inputs_required,
        })
      : null;
    const sourceFamily = readSourceFamilyEvidence(snapshot);
    const thetaPlusKTrace =
      thetaLane instanceof Float32Array && contractField instanceof Float32Array
        ? computeThetaPlusKTraceConsistency(thetaLane, contractField)
        : {
            rms: null,
            maxAbs: null,
            mean: null,
            sampleCount: 0,
            consistent: false,
          };
    snapshotMetrics = {
      dims: snapshot.dims,
      resolvedUrl: snapshot.resolvedUrl,
      metricRefHash: snapshot.metricRefHash,
      requestMetricRefHash: resolveMetricRefHash(args.metricVolumeRef),
      source: snapshot.source,
      chart: snapshot.chart,
      channelHashes: {
        theta: thetaLane instanceof Float32Array ? hashFloat32(thetaLane) : null,
        K_trace: kTrace instanceof Float32Array ? hashFloat32(kTrace) : null,
        theta_canonical:
          thetaCanonical instanceof Float32Array ? hashFloat32(thetaCanonical) : null,
        lane_contract:
          contractField instanceof Float32Array ? hashFloat32(contractField) : null,
      },
      laneComputation: {
        lane_id: laneId,
        theta_source: laneField.ok ? laneField.source : laneField.error,
        contract_source: laneField.ok ? laneField.contractSource : laneField.error,
        observer_definition_id:
          laneField.ok ? laneField.observerConstruction.observer_definition_id : null,
        observer_inputs_required:
          laneField.ok ? [...laneField.observerConstruction.observer_inputs_required] : [],
        observer_construction_inputs:
          laneField.ok ? [...laneField.observerConstruction.observer_construction_inputs] : [],
        observer_construction_formula:
          laneField.ok ? laneField.observerConstruction.observer_construction_formula : null,
        observer_normalized:
          laneField.ok ? laneField.observerConstruction.observer_normalized : false,
        observer_approximation:
          laneField.ok ? laneField.observerConstruction.observer_approximation : null,
        observer_inputs_present:
          laneField.ok
            ? runtimeLaneEvidence?.observer_inputs_present ??
              laneField.observerConstruction.observer_inputs_present
            : false,
        lane_b_semantic_mode:
          laneField.ok
            ? runtimeLaneEvidence?.lane_b_semantic_mode ??
              laneField.observerConstruction.lane_b_semantic_mode
            : null,
        lane_b_tensor_inputs_hash:
          laneField.ok
            ? runtimeLaneEvidence?.lane_b_tensor_inputs_hash ?? laneTensorInputsHash
            : null,
        lane_b_geometry_ready:
          laneField.ok
            ? runtimeLaneEvidence?.lane_b_geometry_ready ??
              laneField.observerConstruction.lane_b_geometry_ready
            : false,
        lane_b_semantics_closed:
          laneField.ok
            ? runtimeLaneEvidence?.lane_b_semantics_closed ??
              laneField.observerConstruction.semantics_closed
            : false,
        requires_gamma_metric:
          laneField.ok ? laneField.observerConstruction.requires_gamma_metric : false,
        semantics_closed:
          laneField.ok ? laneField.observerConstruction.semantics_closed : false,
        cross_lane_claim_ready:
          laneField.ok ? laneField.observerConstruction.cross_lane_claim_ready : false,
        reference_comparison_ready:
          laneField.ok
            ? laneField.observerConstruction.reference_comparison_ready
            : false,
      },
      sourceFamily,
      thetaPlusKTrace,
      authoritativeLowExpansionGate: buildAuthoritativeLowExpansionGateFromSnapshot({
        snapshot,
        thetaPlusKTrace,
      }),
    };
    offlineYorkAudit = computeOfflineYorkAudit({
      caseId: args.caseId,
      theta: thetaLane instanceof Float32Array ? thetaLane : null,
      dims: snapshot.dims,
    });
    parity = computeCaseLaneAParityAudit({
      lane: args.diagnosticLane,
      caseId: args.caseId,
      views: args.yorkViews,
      perView,
      snapshotMetrics,
      theta: thetaLane instanceof Float32Array ? thetaLane : null,
      contractField: contractField instanceof Float32Array ? contractField : null,
      supportMask:
        snapshot.channels.tile_support_mask?.data instanceof Float32Array
          ? snapshot.channels.tile_support_mask.data
          : null,
      hullSdf:
        snapshot.channels.hull_sdf?.data instanceof Float32Array
          ? snapshot.channels.hull_sdf.data
          : null,
      dims: snapshot.dims,
    });
  } catch {
    snapshotMetrics = null;
    offlineYorkAudit = null;
    parity = null;
  }

  const primaryViewId = args.yorkViews.includes("york-surface-rho-3p1")
    ? "york-surface-rho-3p1"
    : args.yorkViews[0];
  const primaryView = perView.find((entry) => entry.view === primaryViewId) ?? null;
  const caseCore: Omit<CaseResult, "classificationFeatures"> = {
    caseId: args.caseId,
    label: args.label,
    familyExpectation: args.familyExpectation,
    metricVolumeRef: args.metricVolumeRef,
    perView,
    primaryYork: {
      view: primaryViewId,
      rawExtrema: primaryView?.rawExtrema ?? null,
      displayExtrema: primaryView?.displayExtrema ?? null,
      nearZeroTheta: primaryView?.nearZeroTheta ?? null,
      coordinateMode: primaryView?.render.coordinate_mode ?? null,
      samplingChoice: primaryView?.samplingChoice ?? null,
      supportOverlapPct: primaryView?.supportOverlapPct ?? null,
    },
    snapshotMetrics,
    offlineYorkAudit,
    parity,
  };
  return {
    ...caseCore,
    classificationFeatures: buildCaseClassificationFeatures(caseCore),
  };
};

const buildAuthoritativeLowExpansionGateSummary = (args: {
  cases: CaseResult[];
}): ProofPackPayload["authoritativeLowExpansionGate"] => {
  const nhm2Case = args.cases.find((entry) => entry.caseId === "nhm2_certified") ?? null;
  const gate = nhm2Case?.snapshotMetrics?.authoritativeLowExpansionGate ?? null;
  if (!nhm2Case || !gate) return undefined;
  return {
    sourceCaseId: nhm2Case.caseId,
    status: gate.status,
    reason: gate.reason,
    source: gate.source,
    authoritative: true,
    divergenceObservable: gate.divergenceObservable,
    divergenceRms: gate.divergenceRms,
    divergenceMaxAbs: gate.divergenceMaxAbs,
    divergenceTolerance: gate.divergenceTolerance,
    thetaKConsistencyStatus: gate.thetaKConsistencyStatus,
    thetaKResidualMaxAbs: gate.thetaKResidualMaxAbs,
    thetaKTolerance: gate.thetaKTolerance,
    projectionDerivedStatus: "advisory_only",
    projectionDerivedNote:
      "Projection-derived betaDiagnostics remain visible for comparison, but authoritative Natario-like low-expansion classification is gated only by brick-native div_beta plus theta/K consistency.",
  };
};

const formatAuthoritativeLowExpansionGateProofPackNote = (
  gate: NonNullable<ProofPackPayload["authoritativeLowExpansionGate"]>,
): string =>
  `authoritative_low_expansion_gate=${gate.status} source=${gate.source ?? "null"} divergence_rms=${gate.divergenceRms ?? "null"} divergence_max_abs=${gate.divergenceMaxAbs ?? "null"} theta_k_status=${gate.thetaKConsistencyStatus} reason=${gate.reason}`;

const AUTHORITATIVE_LOW_EXPANSION_BLOCKED_NOTE =
  "Natario-like morphology remains visible, but authoritative low-expansion classification is blocked until the brick-native div_beta gate passes on the same Lane A surface.";

export const refreshProofPackAuthoritativeLowExpansionGate = async (
  payload: ProofPackPayload,
  options?: {
    loadSnapshot?: (
      ref: HullMetricVolumeRefV1,
      timeoutMs?: number,
    ) => Promise<HullScientificSnapshot>;
  },
): Promise<ProofPackPayload> => {
  const nhm2Index = payload.cases.findIndex((entry) => entry.caseId === "nhm2_certified");
  if (nhm2Index < 0) return payload;
  const nhm2Case = payload.cases[nhm2Index];
  if (!nhm2Case?.snapshotMetrics) return payload;
  const loadSnapshot = options?.loadSnapshot ?? loadProofPackSnapshot;
  const snapshot = await loadSnapshot(nhm2Case.metricVolumeRef, PROOF_PACK_SNAPSHOT_TIMEOUT_MS);
  const thetaPlusKTrace =
    nhm2Case.snapshotMetrics.thetaPlusKTrace ??
    (snapshot.channels.theta?.data instanceof Float32Array &&
    snapshot.channels.K_trace?.data instanceof Float32Array
      ? computeThetaPlusKTraceConsistency(
          snapshot.channels.theta.data,
          snapshot.channels.K_trace.data,
        )
      : {
          rms: null,
          maxAbs: null,
          mean: null,
          sampleCount: 0,
          consistent: false,
        });
  const authoritativeLowExpansionGate = buildAuthoritativeLowExpansionGateFromSnapshot({
    snapshot,
    thetaPlusKTrace,
  });
  const cases = payload.cases.map((entry, index) =>
    index !== nhm2Index
      ? entry
      : {
          ...entry,
          snapshotMetrics: entry.snapshotMetrics
            ? {
                ...entry.snapshotMetrics,
                thetaPlusKTrace,
                authoritativeLowExpansionGate,
              }
            : entry.snapshotMetrics,
        },
  );
  const authoritativeLowExpansionGateSummary = buildAuthoritativeLowExpansionGateSummary({
    cases,
  });
  let notes = payload.notes.filter(
    (entry) =>
      !entry.startsWith("authoritative_low_expansion_gate=") &&
      entry !== AUTHORITATIVE_LOW_EXPANSION_BLOCKED_NOTE &&
      entry !==
        "Projection-derived betaDiagnostics remain visible for comparison, but authoritative Natario-like low-expansion classification is gated only by brick-native div_beta plus theta/K consistency.",
  );
  if (authoritativeLowExpansionGateSummary) {
    notes.push(
      formatAuthoritativeLowExpansionGateProofPackNote(authoritativeLowExpansionGateSummary),
    );
    notes.push(authoritativeLowExpansionGateSummary.projectionDerivedNote);
    if (
      payload.classificationScoring?.winning_reference === "natario_control" &&
      authoritativeLowExpansionGateSummary.status !== "pass"
    ) {
      notes.push(AUTHORITATIVE_LOW_EXPANSION_BLOCKED_NOTE);
    }
  }
  const payloadBase: ProofPackPayload = {
    ...payload,
    generatedOn: DATE_STAMP,
    generatedAt: new Date().toISOString(),
    cases,
    authoritativeLowExpansionGate: authoritativeLowExpansionGateSummary,
    notes,
  };
  return {
    ...payloadBase,
    checksum: computeChecksum(payloadBase),
  };
};

const buildYorkFixedScaleCaseInputs = async (args: {
  cases: CaseResult[];
  diagnosticLane: YorkDiagnosticLane;
}): Promise<YorkFixedScaleInputCase[]> => {
  const laneId: YorkDiagnosticLaneId | null = isYorkDiagnosticLaneId(args.diagnosticLane.lane_id)
    ? args.diagnosticLane.lane_id
    : null;
  if (laneId == null) {
    throw new Error(`fixed_scale_lane_id_unsupported:${args.diagnosticLane.lane_id}`);
  }
  return Promise.all(
    args.cases.map(async (caseResult) => {
      const snapshot = await loadProofPackSnapshot(
        caseResult.metricVolumeRef,
        PROOF_PACK_SNAPSHOT_TIMEOUT_MS,
      );
      const laneField = computeYorkDiagnosticLaneField({
        laneId,
        dims: snapshot.dims,
        voxelSizeM: snapshot.voxelSize_m,
        theta:
          snapshot.channels.theta?.data instanceof Float32Array
            ? snapshot.channels.theta.data
            : null,
        kTrace:
          snapshot.channels.K_trace?.data instanceof Float32Array
            ? snapshot.channels.K_trace.data
            : null,
        betaX:
          snapshot.channels.beta_x?.data instanceof Float32Array
            ? snapshot.channels.beta_x.data
            : null,
        betaY:
          snapshot.channels.beta_y?.data instanceof Float32Array
            ? snapshot.channels.beta_y.data
            : null,
        betaZ:
          snapshot.channels.beta_z?.data instanceof Float32Array
            ? snapshot.channels.beta_z.data
            : null,
        alpha:
          snapshot.channels.alpha?.data instanceof Float32Array
            ? snapshot.channels.alpha.data
            : null,
        gammaXX:
          snapshot.channels.gamma_xx?.data instanceof Float32Array
            ? snapshot.channels.gamma_xx.data
            : null,
        gammaXY:
          snapshot.channels.gamma_xy?.data instanceof Float32Array
            ? snapshot.channels.gamma_xy.data
            : null,
        gammaXZ:
          snapshot.channels.gamma_xz?.data instanceof Float32Array
            ? snapshot.channels.gamma_xz.data
            : null,
        gammaYY:
          snapshot.channels.gamma_yy?.data instanceof Float32Array
            ? snapshot.channels.gamma_yy.data
            : null,
        gammaYZ:
          snapshot.channels.gamma_yz?.data instanceof Float32Array
            ? snapshot.channels.gamma_yz.data
            : null,
        gammaZZ:
          snapshot.channels.gamma_zz?.data instanceof Float32Array
            ? snapshot.channels.gamma_zz.data
            : null,
      });
      if (!laneField.ok) {
        throw new Error(`fixed_scale_lane_field_missing:${caseResult.caseId}:${laneField.error}`);
      }
      const xzSlice = extractThetaSliceXZMidplane(laneField.theta, snapshot.dims);
      const xrhoSlice = extractThetaSliceXRho(laneField.theta, snapshot.dims);
      const xzViewSummary =
        caseResult.perView.find((entry) => entry.view === "york-surface-3p1") ?? null;
      const xrhoViewSummary =
        caseResult.perView.find((entry) => entry.view === "york-surface-rho-3p1") ?? null;
      return {
        case_id: caseResult.caseId,
        label: caseResult.label,
        views: [
          {
            view_id: "york-surface-3p1",
            coordinate_mode: "x-z-midplane",
            sampling_choice: "x-z midplane",
            source_width: snapshot.dims[0],
            source_height: snapshot.dims[2],
            slice: xzSlice,
            slice_hash: hashFloat32(xzSlice),
            raw_extrema: computeRawSliceExtrema(xzSlice),
            signed_lobe_summary:
              caseResult.offlineYorkAudit?.alcubierreSignedLobeSummary?.signedLobeSummary ??
              null,
            support_overlap_pct: xzViewSummary?.supportOverlapPct ?? caseResult.primaryYork.supportOverlapPct ?? null,
            near_zero_theta: xzViewSummary?.nearZeroTheta ?? caseResult.primaryYork.nearZeroTheta ?? null,
          },
          {
            view_id: "york-surface-rho-3p1",
            coordinate_mode: "x-rho",
            sampling_choice: "x-rho cylindrical remap",
            source_width: snapshot.dims[0],
            source_height: Math.max(2, snapshot.dims[2]),
            slice: xrhoSlice,
            slice_hash: hashFloat32(xrhoSlice),
            raw_extrema: computeRawSliceExtrema(xrhoSlice),
            signed_lobe_summary: null,
            support_overlap_pct:
              xrhoViewSummary?.supportOverlapPct ?? caseResult.primaryYork.supportOverlapPct ?? null,
            near_zero_theta:
              xrhoViewSummary?.nearZeroTheta ?? caseResult.primaryYork.nearZeroTheta ?? null,
          },
          {
            view_id: "york-topology-normalized-3p1",
            coordinate_mode: "x-z-midplane",
            sampling_choice: "x-z midplane",
            source_width: snapshot.dims[0],
            source_height: snapshot.dims[2],
            slice: xzSlice,
            slice_hash: hashFloat32(xzSlice),
            raw_extrema: computeRawSliceExtrema(xzSlice),
            signed_lobe_summary:
              caseResult.offlineYorkAudit?.alcubierreSignedLobeSummary?.signedLobeSummary ??
              null,
            support_overlap_pct: xzViewSummary?.supportOverlapPct ?? caseResult.primaryYork.supportOverlapPct ?? null,
            near_zero_theta: xzViewSummary?.nearZeroTheta ?? caseResult.primaryYork.nearZeroTheta ?? null,
          },
        ],
      };
    }),
  );
};

