const findCalibrationPairMetric = (
  calibrationArtifact: WarpYorkCanonicalCalibrationArtifact,
  lhsCaseId: CalibrationPanelCaseId,
  rhsCaseId: CalibrationPanelCaseId,
): CalibrationPairMetric | null =>
  calibrationArtifact.pairwiseMetrics.find(
    (entry) =>
      (entry.lhs_case_id === lhsCaseId && entry.rhs_case_id === rhsCaseId) ||
      (entry.lhs_case_id === rhsCaseId && entry.rhs_case_id === lhsCaseId),
  ) ?? null;

const findCalibrationView = (
  caseExport: CalibrationCaseExport,
  viewId: YorkFixedScaleViewId,
): CalibrationViewExport | null =>
  caseExport.views.find((entry) => entry.view_id === viewId) ?? null;

const findOptixFieldRender = (
  caseRender: YorkOptixPresentationCaseRecord,
  fieldId: YorkOptixPresentationFieldId,
  variant: YorkOptixPresentationFieldVariant,
): YorkOptixPresentationFieldRenderEntry | null =>
  caseRender.fieldRenders.find(
    (entry) =>
      entry.presentationFieldId === fieldId && entry.variant === variant,
  ) ?? null;

const summarizeCanonicalComparisonCaseReadability = (
  caseRender: YorkOptixPresentationCaseRecord,
): YorkOptixFieldSuiteReadabilityStatus => {
  const relevantRenders = caseRender.fieldRenders.filter(
    (entry) =>
      entry.variant === "main" &&
      FINAL_CANONICAL_COMPARISON_PRIMARY_FIELDS.includes(entry.presentationFieldId),
  );
  if (relevantRenders.length === 0) return "flat";
  if (relevantRenders.every((entry) => entry.warnings.length === 0)) return "readable";
  if (relevantRenders.every((entry) => entry.warnings.length > 0)) return "flat";
  return "mixed";
};

const describeDiagnosticMorphologyClass = (
  caseId: CalibrationPanelCaseId,
  nhm2CurrentClass: WarpYorkCanonicalCalibrationArtifact["nhm2CurrentClass"],
): string => {
  switch (caseId) {
    case "flat_space_zero_theta":
      return "flat_zero_reference";
    case "natario_control":
      return "natario_like_low_expansion_control";
    case "alcubierre_control":
      return "alcubierre_like_signed_lobe_control";
    case "nhm2_certified":
    default:
      return nhm2CurrentClass;
  }
};

const summarizeCanonicalDiagnosticCase = (args: {
  caseId: CalibrationPanelCaseId;
  pairwiseComparisons: CanonicalVisualComparisonPairSummary[];
}): string => {
  if (args.caseId === "flat_space_zero_theta") {
    return "Flat space remains the zero-theta reference and anchors both the diagnostic and presentation layers against a known near-zero baseline.";
  }
  const toNatario = args.pairwiseComparisons.find(
    (entry) => entry.other_case_id === "natario_control",
  );
  const toAlcubierre = args.pairwiseComparisons.find(
    (entry) => entry.other_case_id === "alcubierre_control",
  );
  if (args.caseId === "nhm2_certified") {
    return `Under the authoritative Lane A contract, NHM2 remains closer to Natario than Alcubierre. Raw-control distance is ${toNatario?.raw_control_distance ?? "null"} to Natario versus ${toAlcubierre?.raw_control_distance ?? "null"} to Alcubierre, and shared-scale pixel RMS is ${toNatario?.pixel_rms ?? "null"} versus ${toAlcubierre?.pixel_rms ?? "null"}.`;
  }
  if (args.caseId === "natario_control") {
    return "Natario remains the calibrated low-expansion control family. Its diagnostic separation from Alcubierre stays materially larger than the NHM2-to-Natario gap.";
  }
  return "Alcubierre remains the signed-lobe control comparator. Against the same Lane A contract, NHM2 stays materially farther from Alcubierre than from Natario.";
};

const summarizeCanonicalPresentationCase = (args: {
  caseRender: YorkOptixPresentationCaseRecord;
  readabilityStatus: YorkOptixFieldSuiteReadabilityStatus;
}): string => {
  const laneBinding =
    Array.from(
      new Set(
        args.caseRender.fieldRenders
          .map((entry) => entry.laneId)
          .filter((entry): entry is string => typeof entry === "string" && entry.length > 0),
      ),
    )[0] ?? "unreported";
  const transportInheritance =
    args.caseRender.fieldRenders.some((entry) => entry.inheritsTransportContext) ? "present" : "absent";
  return `Solve-backed OptiX 3+1 presentation is available for this case with readability status ${args.readabilityStatus}. Field renders stay bound to ${laneBinding}, use a dedicated neutral field canvas, and keep transport-context inheritance ${transportInheritance}. They remain secondary to the fixed-scale diagnostic layer.`;
};

const summarizeCanonicalMorphologyInterpretation = (args: {
  caseId: CalibrationPanelCaseId;
}): CanonicalVisualComparisonCaseRecord["morphologyInterpretation"] => {
  switch (args.caseId) {
    case "flat_space_zero_theta":
      return {
        beta_magnitude:
          "Shift magnitude stays near the zero baseline and does not produce a localized transport shell.",
        beta_x:
          "Ship-axis shift stays near zero and serves as the transport baseline for the canonical controls.",
        trace_check:
          "Trace check stays near the zero baseline and serves as the control reference for the other cases.",
        longitudinal_signed_strain:
          "Longitudinal signed strain stays near the flat reference with no meaningful ship-axis deformation pattern.",
        tracefree_magnitude:
          "Tracefree magnitude remains effectively a baseline support map and does not introduce a non-flat morphology signal.",
        energy_density:
          "Energy density remains the baseline reference rather than a warp-family morphology driver.",
        comparativeNote:
          "Use the flat baseline only as a zero reference. The family decision comes from how NHM2 separates from Natario and Alcubierre above this baseline.",
      };
    case "natario_control":
      return {
        beta_magnitude:
          "Shift magnitude localizes on the transport-support shell without producing the stronger Alcubierre-side transport split.",
        beta_x:
          "Ship-axis shift shows the sliding transport organization expected for the calibrated Natario-like low-expansion control.",
        trace_check:
          "Trace check remains low-expansion and near-zero dominant, which is consistent with the current Natario-like control class.",
        longitudinal_signed_strain:
          "Longitudinal signed strain carries the main visible deformation pattern without producing an Alcubierre-style fore/aft signed lobe split.",
        tracefree_magnitude:
          "Tracefree magnitude localizes deformation while staying in a low-expansion presentation family.",
        energy_density:
          "Energy density stays localized on the same solved support family and provides context rather than a separate class decision.",
        comparativeNote:
          "Natario provides the closest canonical visual family for NHM2 in both the authoritative metrics and the readable OptiX field suite.",
      };
    case "alcubierre_control":
      return {
        beta_magnitude:
          "Shift magnitude remains solve-backed and readable, but the more important separation still comes from the signed transport structure.",
        beta_x:
          "Ship-axis shift presents the strongest canonical signed transport split and remains the clearest Alcubierre-side comparator.",
        trace_check:
          "Trace check remains the clearest signed-lobe comparator and anchors what the repo treats as Alcubierre-like morphology under the current contract.",
        longitudinal_signed_strain:
          "Longitudinal signed strain presents a stronger signed split than the NHM2/Natario pair and remains the canonical Alcubierre-side visual comparator.",
        tracefree_magnitude:
          "Tracefree magnitude is localized, but the decisive separation from NHM2 still comes from the signed-lobe behavior rather than the magnitude channel alone.",
        energy_density:
          "Energy density stays solve-backed and readable, but it remains secondary to the signed-lobe diagnostic difference.",
        comparativeNote:
          "Alcubierre remains the canonical outlier for NHM2. The presentation layer now makes that gap easier to inspect, but the class verdict still comes from Lane A diagnostics.",
      };
    case "nhm2_certified":
    default:
      return {
        beta_magnitude:
          "Shift magnitude is live and shell-localized, but its solved transport pattern remains closer to Natario than to Alcubierre.",
        beta_x:
          "Ship-axis shift is now directly visible and still stays closer to Natario's low-expansion transport family than to Alcubierre's stronger signed transport split.",
        trace_check:
          "Trace check remains low-amplitude and does not recover the stronger Alcubierre-style signed fore/aft lobe pattern.",
        longitudinal_signed_strain:
          "Longitudinal signed strain is the clearest human-facing deformation view for NHM2 and it stays closer to Natario’s low-expansion structure than to Alcubierre’s signed-lobe structure.",
        tracefree_magnitude:
          "Tracefree magnitude is live and localized, but it does not reveal an Alcubierre-like transition; it stays in the same low-expansion family as the Natario control.",
        energy_density:
          "Energy density remains solve-backed and localized on the same support family that already underwrites the Lane A classification.",
        comparativeNote:
          "Taken together, the authoritative metrics and the readable OptiX fields keep NHM2 in the Natario-like low-expansion family rather than the Alcubierre-like signed-lobe family.",
      };
  }
};

export const buildNhm2CanonicalVisualComparisonArtifact = async (args: {
  generatedOn: string;
  sourceAuditArtifactPath: string;
  canonicalCalibrationArtifactPath: string;
  fixedScaleArtifactPath: string;
  optixRenderArtifactPath: string;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  fixedScaleComparisonArtifact: Nhm2YorkFixedScaleComparisonArtifact;
  optixRenderArtifact: Nhm2YorkOptixRenderArtifact;
  exportDirectory: string;
}): Promise<Nhm2CanonicalVisualComparisonArtifact> => {
  fs.mkdirSync(args.exportDirectory, { recursive: true });
  const caseRecords: CanonicalVisualComparisonCaseRecord[] = [];
  const cardOutputs: Array<{ title: string; imagePath: string }> = [];
  for (const caseId of FINAL_CANONICAL_COMPARISON_CASE_ORDER) {
    const calibrationCase =
      args.canonicalCalibrationArtifact.canonicalCases.find(
        (entry) => entry.case_id === caseId,
      ) ?? null;
    const optixCase =
      args.optixRenderArtifact.caseRenders.find((entry) => entry.case_id === caseId) ?? null;
    if (!calibrationCase || !optixCase) {
      throw new Error(`Missing canonical comparison case payload for ${caseId}`);
    }
    const diagnosticPrimaryView = findCalibrationView(calibrationCase, "york-surface-3p1");
    const comparisonTargets = FINAL_CANONICAL_COMPARISON_CASE_ORDER.filter(
      (entry) => entry !== caseId,
    );
    const pairwiseComparisons: CanonicalVisualComparisonPairSummary[] = comparisonTargets.map(
      (otherCaseId) => {
        const pairMetric = findCalibrationPairMetric(
          args.canonicalCalibrationArtifact,
          caseId,
          otherCaseId,
        );
        const primaryMetric =
          pairMetric?.views.find((entry) => entry.view_id === "york-surface-3p1") ?? null;
        return {
          other_case_id: otherCaseId,
          raw_control_distance: pairMetric?.raw_control_distance ?? null,
          metric_source_stage: primaryMetric?.metric_source_stage ?? null,
          pixel_rms: primaryMetric?.pixel_rms ?? null,
          mean_absolute_pixel_difference:
            primaryMetric?.mean_absolute_pixel_difference ?? null,
          changed_pixel_fraction: primaryMetric?.changed_pixel_fraction ?? null,
          diff_abs_max: primaryMetric?.diff_abs_max ?? null,
          comparison_note:
            "Authoritative Lane A comparison from the shared fixed-scale york-surface-3p1 export.",
        };
      },
    );
    const readabilityStatus = summarizeCanonicalComparisonCaseReadability(optixCase);
    const mainRender =
      optixCase.contextRenders.find((entry) => entry.renderView === "transport-3p1") ?? null;
    const hullOverlay =
      optixCase.contextRenders.find((entry) => entry.renderView === "full-atlas") ?? null;
    const fieldRenders = FINAL_CANONICAL_COMPARISON_PRIMARY_FIELDS.map((fieldId) => {
      const render = findOptixFieldRender(optixCase, fieldId, "main");
      return {
        presentationFieldId: fieldId,
        label:
          render?.label ??
          OPTIX_PRESENTATION_FIELD_DESCRIPTORS.find(
            (entry) => entry.presentationFieldId === fieldId,
          )?.label ??
          fieldId,
        imagePath: render?.imagePath ? normalizePath(render.imagePath) : null,
        imageHash: render?.presentationProjectionImageHash ?? null,
        laneId: render?.laneId ?? null,
        baseImagePolicy: render?.baseImagePolicy ?? "neutral_field_canvas",
        baseImageSource: render?.baseImageSource ?? "none",
        inheritsTransportContext: render?.inheritsTransportContext ?? false,
        contextCompositionMode: render?.contextCompositionMode ?? "none",
        fieldMin: render?.fieldMin ?? null,
        fieldMax: render?.fieldMax ?? null,
        fieldAbsMax: render?.fieldAbsMax ?? null,
        displayPolicyId: render?.displayPolicyId ?? null,
        displayRangeMin: render?.displayRangeMin ?? null,
        displayRangeMax: render?.displayRangeMax ?? null,
        displayTransform: render?.displayTransform ?? null,
        colormapFamily: render?.colormapFamily ?? null,
        warnings: render?.warnings ?? [],
        renderTaxonomy: render?.renderTaxonomy ?? null,
      };
    });
    const laneBinding =
      Array.from(
        new Set(
          optixCase.fieldRenders
            .map((entry) => entry.laneId)
            .filter((entry): entry is string => typeof entry === "string" && entry.length > 0),
        ),
      )[0] ?? null;
    const cardPath = path.join(args.exportDirectory, `${caseId}-comparison-card.png`);
    await renderCanonicalComparisonCard({
      title: `${calibrationCase.label} (${describeDiagnosticMorphologyClass(caseId, args.canonicalCalibrationArtifact.nhm2CurrentClass)})`,
      tiles: [
        {
          label: "Diagnostic: york-surface-3p1",
          imagePath: diagnosticPrimaryView?.png_path ?? null,
        },
        {
          label: "OptiX: transport-3p1",
          imagePath: mainRender?.imagePath ?? null,
        },
        {
          label: "Field: longitudinal_signed_strain",
          imagePath:
            fieldRenders.find(
              (entry) => entry.presentationFieldId === "longitudinal_signed_strain",
            )?.imagePath ?? null,
        },
        {
          label: "Field: tracefree_magnitude",
          imagePath:
            fieldRenders.find(
              (entry) => entry.presentationFieldId === "tracefree_magnitude",
            )?.imagePath ?? null,
        },
      ],
      outputPath: cardPath,
    });
    cardOutputs.push({ title: calibrationCase.label, imagePath: cardPath });
    caseRecords.push({
      case_id: caseId,
      label: calibrationCase.label,
      case_role: calibrationCase.case_role,
      diagnosticLayer: {
        authoritative: true,
        laneId: args.canonicalCalibrationArtifact.comparisonContract.laneUsed,
        primaryViewId: "york-surface-3p1",
        primaryViewPath: diagnosticPrimaryView?.png_path
          ? normalizePath(diagnosticPrimaryView.png_path)
          : null,
        primaryViewHash: diagnosticPrimaryView?.png_hash ?? null,
        sliceRefs: calibrationCase.views,
        pairwiseComparisons,
        morphologyClass: describeDiagnosticMorphologyClass(
          caseId,
          args.canonicalCalibrationArtifact.nhm2CurrentClass,
        ),
        diagnosticSummary: summarizeCanonicalDiagnosticCase({
          caseId,
          pairwiseComparisons,
        }),
      },
      presentationLayer: {
        secondary: true,
        readabilityStatus,
        laneBinding,
        mainRenderPath: mainRender?.imagePath ? normalizePath(mainRender.imagePath) : null,
        hullOverlayPath: hullOverlay?.imagePath ? normalizePath(hullOverlay.imagePath) : null,
        fieldRenders,
        displayPolicySummary: fieldRenders.map((entry) => ({
          presentationFieldId: entry.presentationFieldId,
          displayPolicyId: entry.displayPolicyId,
          displayRangeMin: entry.displayRangeMin,
          displayRangeMax: entry.displayRangeMax,
          displayTransform: entry.displayTransform,
          colormapFamily: entry.colormapFamily,
        })),
        presentationSummary: summarizeCanonicalPresentationCase({
          caseRender: optixCase,
          readabilityStatus,
        }),
      },
      morphologyInterpretation: summarizeCanonicalMorphologyInterpretation({ caseId }),
      comparisonCardPath: normalizePath(cardPath),
      comparisonCardRender: null,
    });
  }
  const overviewPanelPath = path.join(
    args.exportDirectory,
    "nhm2-canonical-comparison-overview.png",
  );
  await renderCanonicalComparisonOverviewPanel({
    title: "Final NHM2 vs Natario vs Alcubierre Comparison",
    cards: cardOutputs,
    outputPath: overviewPanelPath,
  });
  const presentationVerdict: CanonicalVisualComparisonPresentationVerdict =
    args.optixRenderArtifact.presentationReadinessVerdict ===
      "ready_for_human_inspection" &&
    args.optixRenderArtifact.presentationRenderBackedByAuthoritativeMetric
      ? "presentation_layer_ready_and_consistent"
      : args.optixRenderArtifact.presentationRenderQuality === "failed" ||
          !args.optixRenderArtifact.presentationRenderBackedByAuthoritativeMetric
        ? "presentation_layer_not_ready"
        : "presentation_layer_has_advisories";
  const artifactBase: Nhm2CanonicalVisualComparisonArtifact = {
    artifactType: "nhm2_canonical_visual_comparison/v1",
    generatedOn: args.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This final comparison pack combines the authoritative Lane A diagnostic contract with the readable solve-backed OptiX 3+1 presentation layer so NHM2, Natario, and Alcubierre can be compared without changing the proof basis.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    canonicalCalibrationArtifactPath: normalizePath(args.canonicalCalibrationArtifactPath),
    fixedScaleArtifactPath: normalizePath(args.fixedScaleArtifactPath),
    optixRenderArtifactPath: normalizePath(args.optixRenderArtifactPath),
    exportDirectory: normalizePath(args.exportDirectory),
    authoritativeDiagnosticBasis: {
      laneUsed: args.canonicalCalibrationArtifact.comparisonContract.laneUsed,
      observer: args.canonicalCalibrationArtifact.comparisonContract.observer,
      foliation: args.canonicalCalibrationArtifact.comparisonContract.foliation,
      thetaDefinition:
        args.canonicalCalibrationArtifact.comparisonContract.thetaDefinition,
      signConvention: args.canonicalCalibrationArtifact.comparisonContract.signConvention,
      fixedScalePolicy: args.canonicalCalibrationArtifact.comparisonContract.fixedScalePolicy,
      visualMetricSourceStage:
        args.canonicalCalibrationArtifact.comparisonContract.visualMetricSourceStage,
      note:
        "Lane A fixed-scale slices and pre-PNG color-buffer metrics remain the authoritative basis for class decisions in this comparison pack.",
    },
    presentationLayerStatus: {
      presentationRenderLayerStatus:
        args.optixRenderArtifact.presentationRenderLayerStatus,
      fieldSuiteRealizationStatus:
        args.optixRenderArtifact.fieldSuiteRealizationStatus,
      fieldSuiteReadabilityStatus:
        args.optixRenderArtifact.fieldSuiteReadabilityStatus,
      presentationRenderQuality: args.optixRenderArtifact.presentationRenderQuality,
      presentationReadinessVerdict:
        args.optixRenderArtifact.presentationReadinessVerdict,
      presentationRenderBackedByAuthoritativeMetric:
        args.optixRenderArtifact.presentationRenderBackedByAuthoritativeMetric,
    },
    canonicalCases: caseRecords,
    overviewPanelPath: normalizePath(overviewPanelPath),
    finalComparisonVerdict:
      args.canonicalCalibrationArtifact.decisionGate.calibration_verdict,
    diagnosticVerdict: args.fixedScaleComparisonArtifact.fixed_scale_render_verdict,
    presentationVerdict,
    nhm2ClosestCanonicalFamily: args.canonicalCalibrationArtifact.nhm2CurrentClass,
    alcubierreLikeTransitionObserved:
      args.canonicalCalibrationArtifact.nhm2CurrentClass ===
      "alcubierre_like_signed_lobe"
        ? "yes"
        : "no",
    recommendedNextAction:
      presentationVerdict === "presentation_layer_ready_and_consistent"
        ? "If a different morphology is still desired, continue model-family work rather than render debugging."
        : "Resolve remaining presentation issues before relying on the OptiX layer for human-facing comparison.",
    scopeNote:
      "This is a repo-local comparison pack. The authoritative morphology verdict still comes from Lane A diagnostics; the OptiX suite is secondary presentation only.",
    renderTaxonomy: null,
    overviewPanelRender: null,
    notes: [
      "diagnostic_layer_primary=true",
      "presentation_layer_secondary=true",
      `nhm2_vs_natario_pixel_rms=${args.fixedScaleComparisonArtifact.nhm2_vs_natario_visual_distance?.pixel_rms ?? "null"}`,
      `nhm2_vs_alcubierre_pixel_rms=${args.fixedScaleComparisonArtifact.nhm2_vs_alcubierre_visual_distance?.pixel_rms ?? "null"}`,
      "remaining_ambiguity=model_related_not_presentation_related",
    ],
  };
  return {
    ...artifactBase,
    checksum: computeCanonicalVisualComparisonChecksum(artifactBase),
  };
};

