const computeRenderTaxonomyChecksum = (payload: RenderTaxonomyArtifact): string =>
  crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex");

export const buildRenderTaxonomyArtifact = (args: {
  generatedOn: string;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  optixRenderArtifact: Nhm2YorkOptixRenderArtifact;
  shiftGeometryArtifact: Nhm2ShiftGeometryVisualizationArtifact;
  curvatureInvariantArtifact: Nhm2CurvatureInvariantVisualizationArtifact;
  canonicalVisualComparisonArtifact: Nhm2CanonicalVisualComparisonArtifact;
}): RenderTaxonomyArtifact => {
  const renderEntries: RenderTaxonomyManifestEntry[] = [];
  const addEntry = (caseId: string, metadata: RenderTaxonomyEntryMetadata | null) => {
    if (!metadata) return;
    syncCanonicalRenderAliasFile(metadata.legacyPath, metadata.canonicalPath);
    renderEntries.push(toRenderTaxonomyManifestEntry(caseId, metadata));
  };
  for (const caseEntry of args.canonicalCalibrationArtifact.canonicalCases) {
    for (const view of caseEntry.views) {
      addEntry(caseEntry.case_id, view.renderTaxonomy);
    }
  }
  for (const caseEntry of args.optixRenderArtifact.caseRenders) {
    for (const render of caseEntry.contextRenders) {
      addEntry(caseEntry.case_id, render.renderTaxonomy);
    }
    for (const render of caseEntry.fieldRenders) {
      addEntry(caseEntry.case_id, render.renderTaxonomy);
    }
  }
  for (const render of args.shiftGeometryArtifact.renderEntries) {
    addEntry(render.caseId, render.renderTaxonomy);
  }
  for (const render of args.curvatureInvariantArtifact.renderEntries) {
    addEntry(render.caseId, render.renderTaxonomy);
  }
  for (const caseEntry of args.canonicalVisualComparisonArtifact.canonicalCases) {
    addEntry(caseEntry.case_id, caseEntry.comparisonCardRender);
  }
  addEntry("canonical_family", args.canonicalVisualComparisonArtifact.overviewPanelRender);
  const categoryCounts = {
    diagnostic_lane_a: 0,
    transport_context: 0,
    scientific_3p1_field: 0,
    comparison_panel: 0,
    mechanism_overlay: 0,
    invariant_crosscheck: 0,
  } satisfies Record<RenderTaxonomyCategory, number>;
  for (const entry of renderEntries) {
    categoryCounts[entry.renderCategory] += 1;
  }
  const artifactBase: RenderTaxonomyArtifact = {
    artifactType: "warp_render_taxonomy/v1",
    generatedOn: args.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This manifest standardizes the role, field semantics, labeling, and canonical storage path of solve-backed render outputs without changing the authoritative Lane A evidence policy.",
    authoritativeRenderCategory: "diagnostic_lane_a",
    presentationRenderCategory: "scientific_3p1_field",
    comparisonRenderCategory: "comparison_panel",
    repoOrientationConvention: {
      orientationConventionId: RENDER_ORIENTATION_CONVENTION.orientationConventionId,
      axisLabels: { ...RENDER_ORIENTATION_CONVENTION.axisLabels },
      note: RENDER_ORIENTATION_CONVENTION.note,
    },
    renderCategories: [...RENDER_TAXONOMY_CATEGORY_DEFINITIONS],
    fieldFamilies: [...RENDER_FIELD_FAMILY_DEFINITIONS],
    canonicalRenderRoot: normalizePath(DEFAULT_RENDER_TAXONOMY_CANONICAL_ROOT),
    renderEntries,
    summary: {
      totalRenderCount: renderEntries.length,
      categoryCounts,
      authoritativeRenderCount: renderEntries.filter(
        (entry) => entry.authoritativeStatus === "primary_authoritative",
      ).length,
      secondaryRenderCount: renderEntries.filter(
        (entry) => entry.authoritativeStatus !== "primary_authoritative",
      ).length,
    },
    notes: [
      "diagnostic_lane_a remains the proof surface for class decisions.",
      "transport_context remains a separate solve-backed context family and is not a dedicated field frame.",
      "scientific_3p1_field remains solve-backed but secondary presentation only, including brick-native curvature invariants when surfaced as NHM2 scientific frames.",
      "shift_geometry suites remain solve-backed but interpretive and cannot outrun the authoritative Lane A diagnostic surface.",
      "comparison_panel outputs are communication/review surfaces, not proof surfaces.",
      "mechanism_overlay outputs remain interpretive and secondary to both diagnostics and single-field presentation renders.",
      categoryCounts.invariant_crosscheck > 0
        ? "invariant_crosscheck contains only explicit comparison or cross-basis consistency products and remains separate from the main brick-native invariant field suite."
        : "Brick-native curvature invariants are now surfaced as scientific_3p1_field renders, while invariant_crosscheck remains empty until explicit comparison or cross-basis products exist.",
    ],
  };
  return {
    ...artifactBase,
    checksum: computeRenderTaxonomyChecksum(artifactBase),
  };
};

