const computeCanonicalCalibrationChecksum = (
  payload: WarpYorkCanonicalCalibrationArtifact,
): string => {
  const copy = JSON.parse(JSON.stringify(payload)) as Record<string, unknown>;
  delete copy.generatedAt;
  delete copy.checksum;
  return crypto.createHash("sha256").update(stableStringify(copy)).digest("hex");
};

const computeAblationPanelChecksum = (payload: Nhm2YorkAblationPanelArtifact): string => {
  const copy = JSON.parse(JSON.stringify(payload)) as Record<string, unknown>;
  delete copy.generatedAt;
  delete copy.checksum;
  return crypto.createHash("sha256").update(stableStringify(copy)).digest("hex");
};

const findCalibrationInputView = (
  input: CalibrationInputCase,
  viewId: YorkFixedScaleViewId,
): YorkFixedScaleInputView => {
  const view = input.views.find((entry) => entry.view_id === viewId);
  if (!view) throw new Error(`calibration_view_missing:${input.case_id}:${viewId}`);
  return view;
};

const normalizeCalibrationSliceForView = (
  inputView: YorkFixedScaleInputView,
  viewId: YorkFixedScaleViewId,
): Float32Array =>
  viewId === "york-topology-normalized-3p1" ? normalizeSliceToUnitMax(inputView.slice) : inputView.slice;

const buildSyntheticZeroCalibrationCase = (
  referenceCase: YorkFixedScaleInputCase,
): CalibrationInputCase => ({
  case_id: "flat_space_zero_theta",
  label: "Flat-space zero-theta baseline",
  case_role: "zero_baseline",
  source_kind: "synthetic_zero_reference",
  views: FIXED_SCALE_VIEW_IDS.map((viewId) => {
    const referenceView = findFixedScaleInputView(referenceCase, viewId);
    const zeroSlice = new Float32Array(referenceView.slice.length);
    return {
      view_id: viewId,
      coordinate_mode: referenceView.coordinate_mode,
      sampling_choice: referenceView.sampling_choice,
      source_width: referenceView.source_width,
      source_height: referenceView.source_height,
      slice: zeroSlice,
      slice_hash: hashFloat32(zeroSlice),
      raw_extrema: computeRawSliceExtrema(zeroSlice),
      signed_lobe_summary: "mixed_or_flat",
      support_overlap_pct: 1,
      near_zero_theta: true,
    };
  }),
});

const buildCalibrationPanelCaseInputs = (
  caseInputs: YorkFixedScaleInputCase[],
): CalibrationInputCase[] => {
  const byCaseId = new Map(caseInputs.map((entry) => [entry.case_id, entry]));
  const referenceCase = byCaseId.get("nhm2_certified") ?? caseInputs[0];
  if (!referenceCase) throw new Error("calibration_reference_case_missing");
  const orderedKnownCases: CalibrationInputCase[] = ["alcubierre_control", "natario_control", "nhm2_certified"]
    .map((caseId) => byCaseId.get(caseId))
    .filter((entry): entry is YorkFixedScaleInputCase => entry != null)
    .map((entry) => ({
      case_id: entry.case_id,
      label: entry.label,
      case_role: entry.case_id === "nhm2_certified" ? "nhm2_current" : "canonical_control",
      source_kind: "proof_pack_case",
      views: entry.views.map((view) => ({ ...view })),
    }));
  return [buildSyntheticZeroCalibrationCase(referenceCase), ...orderedKnownCases];
};

const buildCalibrationClassificationFeatures = (args: {
  inputCase: CalibrationInputCase;
  viewPolicies: YorkFixedScaleViewPolicy[];
}): CaseClassificationFeatures => {
  const xz = findCalibrationInputView(args.inputCase, "york-surface-3p1");
  const xrho = findCalibrationInputView(args.inputCase, "york-surface-rho-3p1");
  const xzCounts = computeSliceSignCounts(xz.slice);
  const xrhoCounts = computeSliceSignCounts(xrho.slice);
  const xzPolicy = args.viewPolicies.find((entry) => entry.view_id === "york-surface-3p1");
  const displayAbsMax =
    (xz.raw_extrema.absMax ?? 0) > 0 && (xzPolicy?.global_abs_max ?? 0) > 0
      ? Math.min(1, (xz.raw_extrema.absMax ?? 0) / Math.max(xzPolicy?.global_abs_max ?? 0, 1e-45))
      : 0;
  const nearZeroTheta =
    xz.near_zero_theta ??
    xrho.near_zero_theta ??
    (((xz.raw_extrema.absMax ?? 0) <= YORK_SIGN_STRUCTURE_EPS &&
      (xrho.raw_extrema.absMax ?? 0) <= YORK_SIGN_STRUCTURE_EPS) ||
      (xzCounts.positive === 0 && xzCounts.negative === 0));
  return {
    theta_abs_max_raw: xz.raw_extrema.absMax ?? 0,
    theta_abs_max_display: displayAbsMax,
    positive_count_xz: xzCounts.positive,
    negative_count_xz: xzCounts.negative,
    positive_count_xrho: xrhoCounts.positive,
    negative_count_xrho: xrhoCounts.negative,
    support_overlap_pct: xz.support_overlap_pct ?? 1,
    near_zero_theta: nearZeroTheta,
    signed_lobe_summary: xz.signed_lobe_summary ?? "mixed_or_flat",
    shell_map_activity: 0,
  };
};

const renderAmplifiedDifference = async (args: {
  lhsSlice: Float32Array;
  rhsSlice: Float32Array;
  sourceWidth: number;
  sourceHeight: number;
  outputWidth: number;
  outputHeight: number;
  globalAbsMax: number;
  outputPath: string;
}): Promise<{
  diffAbsMax: number | null;
  amplificationGain: number | null;
  diffRendered: FixedScaleRenderedImage;
}> => {
  const diffSlice = new Float32Array(Math.min(args.lhsSlice.length, args.rhsSlice.length));
  let diffAbsMax = 0;
  for (let i = 0; i < diffSlice.length; i += 1) {
    const diff = (args.lhsSlice[i] ?? 0) - (args.rhsSlice[i] ?? 0);
    diffSlice[i] = diff;
    diffAbsMax = Math.max(diffAbsMax, Math.abs(diff));
  }
  const amplificationGain =
    diffAbsMax > 0
      ? Math.min(128, Math.max(1, Math.max(args.globalAbsMax, 1e-45) / diffAbsMax))
      : 1;
  for (let i = 0; i < diffSlice.length; i += 1) diffSlice[i] *= amplificationGain;
  const diffRendered = await renderSignedSlicePng({
    slice: diffSlice,
    sourceWidth: args.sourceWidth,
    sourceHeight: args.sourceHeight,
    outputWidth: args.outputWidth,
    outputHeight: args.outputHeight,
    absMax: Math.max(args.globalAbsMax, 1e-45),
    signMultiplier: 1,
    backgroundRgb: [8, 12, 20],
  });
  ensureDirForFile(args.outputPath);
  fs.writeFileSync(args.outputPath, diffRendered.png);
  return {
    diffAbsMax,
    amplificationGain,
    diffRendered,
  };
};

const buildSharedComparisonViewPolicies = (args: {
  inputCases: Array<Pick<CalibrationInputCase, "views">>;
  frameSize: { width: number; height: number };
}): YorkFixedScaleViewPolicy[] =>
  FIXED_SCALE_VIEW_IDS.map((viewId) => {
    const anyView = findFixedScaleInputView(args.inputCases[0]! as YorkFixedScaleInputCase, viewId);
    const globalAbsMax =
      viewId === "york-topology-normalized-3p1"
        ? 1
        : Math.max(
            0,
            ...args.inputCases.map(
              (entry) =>
                findFixedScaleInputView(entry as YorkFixedScaleInputCase, viewId).raw_extrema
                  .absMax ?? 0,
            ),
          );
    return {
      view_id: viewId,
      policy_id:
        viewId === "york-topology-normalized-3p1"
          ? "comparison_fixed_topology_global"
          : "comparison_fixed_raw_global",
      coordinate_mode: anyView.coordinate_mode,
      slice_plane: anyView.coordinate_mode,
      output_size: { ...args.frameSize },
      raw_scale_scope: "shared_global_per_view",
      color_scale_mode:
        viewId === "york-topology-normalized-3p1"
          ? "signed_diverging_unit"
          : "signed_diverging_global",
      sign_encoding: "lane_a_signed_theta",
      global_abs_max: globalAbsMax,
      clipping_applied: false,
      note:
        viewId === "york-topology-normalized-3p1"
          ? "Topology-only normalization to unit max, then one fixed shared display range."
          : "All compared cases share one global raw amplitude range for this view with no per-case autoscaling.",
    };
  });

const renderComparisonPanelCases = async (args: {
  inputCases: CalibrationInputCase[];
  viewPolicies: YorkFixedScaleViewPolicy[];
  exportDirectory: string;
  frameSize: { width: number; height: number };
  collisionPrefix: string;
}): Promise<{
  caseExports: CalibrationCaseExport[];
  caseExportByKey: Map<string, CalibrationViewExport>;
  renderedByCaseView: Map<string, FixedScaleRenderedImage>;
  blockingFindings: FixedScaleCollisionCode[];
  advisoryFindings: FixedScaleCollisionCode[];
  collisionRecords: FixedScaleExportIntegrityCollisionRecord[];
}> => {
  const caseExports: CalibrationCaseExport[] = [];
  const caseExportByKey = new Map<string, CalibrationViewExport>();
  const renderedByCaseView = new Map<string, FixedScaleRenderedImage>();
  const blockingFindings: FixedScaleCollisionCode[] = [];
  const advisoryFindings: FixedScaleCollisionCode[] = [];
  const collisionRecords: FixedScaleExportIntegrityCollisionRecord[] = [];
  for (const inputCase of args.inputCases) {
    const viewsForCase: CalibrationViewExport[] = [];
    for (const viewId of FIXED_SCALE_VIEW_IDS) {
      const inputView = findCalibrationInputView(inputCase, viewId);
      const renderSlice = normalizeCalibrationSliceForView(inputView, viewId);
      const extrema = computeRawSliceExtrema(renderSlice);
      const counts = computeSliceSignCounts(renderSlice);
      const policy = args.viewPolicies.find((entry) => entry.view_id === viewId);
      if (!policy) throw new Error(`comparison_view_policy_missing:${viewId}`);
      const pngPath = path.join(
        args.exportDirectory,
        `${inputCase.case_id}-${viewId}-${
          viewId === "york-topology-normalized-3p1" ? "fixed-global-topology" : "fixed-global-raw"
        }.png`,
      );
      const rendered = await renderSignedSlicePng({
        slice: renderSlice,
        sourceWidth: inputView.source_width,
        sourceHeight: inputView.source_height,
        outputWidth: args.frameSize.width,
        outputHeight: args.frameSize.height,
        absMax: Math.max(policy.global_abs_max ?? 0, 1e-45),
      });
      ensureDirForFile(pngPath);
      fs.writeFileSync(pngPath, rendered.png);
      renderedByCaseView.set(`${inputCase.case_id}:${viewId}`, rendered);
      const viewExport: CalibrationViewExport = {
        case_id: inputCase.case_id,
        view_id: viewId,
        policy_id: policy.policy_id,
        theta_min: extrema.min,
        theta_max: extrema.max,
        theta_abs_max: extrema.absMax,
        positive_count: counts.positive,
        negative_count: counts.negative,
        near_zero_count: counts.zeroOrNearZero,
        sample_count: counts.total,
        signed_lobe_summary: inputView.signed_lobe_summary,
        support_overlap_pct: inputView.support_overlap_pct ?? null,
        slice_hash: hashFloat32(renderSlice),
        display_buffer_hash: rendered.displayBufferHash,
        color_buffer_hash: rendered.colorBufferHash,
        png_path: normalizePath(pngPath),
        png_hash: rendered.pngHash,
        renderTaxonomy: null,
      };
      viewsForCase.push(viewExport);
      caseExportByKey.set(`${inputCase.case_id}:${viewId}`, viewExport);
    }
    caseExports.push({
      case_id: inputCase.case_id,
      label: inputCase.label,
      case_role: inputCase.case_role,
      source_kind: inputCase.source_kind,
      validation_passed: false,
      validation_note: "comparison_only_case",
      views: viewsForCase,
    });
  }
  for (const viewId of FIXED_SCALE_VIEW_IDS) {
    for (let lhsIndex = 0; lhsIndex < args.inputCases.length; lhsIndex += 1) {
      for (let rhsIndex = lhsIndex + 1; rhsIndex < args.inputCases.length; rhsIndex += 1) {
        const lhsCaseId = args.inputCases[lhsIndex]!.case_id;
        const rhsCaseId = args.inputCases[rhsIndex]!.case_id;
        const lhsExport = caseExportByKey.get(`${lhsCaseId}:${viewId}`);
        const rhsExport = caseExportByKey.get(`${rhsCaseId}:${viewId}`);
        if (!lhsExport || !rhsExport) continue;
        const colorBufferDiffer = lhsExport.color_buffer_hash !== rhsExport.color_buffer_hash;
        if (colorBufferDiffer && lhsExport.png_hash === rhsExport.png_hash) {
          const findingCode: FixedScaleCollisionCode =
            viewId === "york-topology-normalized-3p1"
              ? "topology_export_collision"
              : "display_buffer_distinguishable_png_collision";
          blockingFindings.push(findingCode);
          advisoryFindings.push("fixed_scale_png_quantization_collapse");
          collisionRecords.push({
            record_id: `${args.collisionPrefix}:${lhsCaseId}:${rhsCaseId}:${viewId}`,
            finding_code: findingCode,
            view_id: viewId,
            lhs_case_id: lhsCaseId,
            rhs_case_id: rhsCaseId,
            lhs_source_slice_hash: lhsExport.slice_hash,
            rhs_source_slice_hash: rhsExport.slice_hash,
            lhs_display_buffer_hash: lhsExport.display_buffer_hash,
            rhs_display_buffer_hash: rhsExport.display_buffer_hash,
            lhs_color_buffer_hash: lhsExport.color_buffer_hash,
            rhs_color_buffer_hash: rhsExport.color_buffer_hash,
            lhs_png_hash: lhsExport.png_hash,
            rhs_png_hash: rhsExport.png_hash,
            note:
              "Distinct pre-PNG display/color buffers collapsed into an identical comparison PNG.",
          });
        }
      }
    }
  }
  return {
    caseExports,
    caseExportByKey,
    renderedByCaseView,
    blockingFindings,
    advisoryFindings,
    collisionRecords,
  };
};

const buildGenericComparisonPairMetric = async (args: {
  pairId: string;
  lhsCase: CalibrationInputCase;
  rhsCase: CalibrationInputCase;
  viewPolicies: YorkFixedScaleViewPolicy[];
  renderedByCaseView: Map<string, FixedScaleRenderedImage>;
  exportDirectory: string;
  frameSize: { width: number; height: number };
  collisionPrefix: string;
  rawControlDistance: number | null;
}): Promise<{
  metric: GenericComparisonPairMetric;
  blockingFindings: FixedScaleCollisionCode[];
  collisionRecords: FixedScaleExportIntegrityCollisionRecord[];
}> => {
  const views: CalibrationDiffViewMetric[] = [];
  const blockingFindings: FixedScaleCollisionCode[] = [];
  const collisionRecords: FixedScaleExportIntegrityCollisionRecord[] = [];
  for (const viewId of FIXED_SCALE_VIEW_IDS) {
    const lhsRendered = args.renderedByCaseView.get(`${args.lhsCase.case_id}:${viewId}`);
    const rhsRendered = args.renderedByCaseView.get(`${args.rhsCase.case_id}:${viewId}`);
    if (!lhsRendered || !rhsRendered) {
      throw new Error(`comparison_render_missing:${args.pairId}:${viewId}`);
    }
    const lhsView = findCalibrationInputView(args.lhsCase, viewId);
    const rhsView = findCalibrationInputView(args.rhsCase, viewId);
    const lhsSlice = normalizeCalibrationSliceForView(lhsView, viewId);
    const rhsSlice = normalizeCalibrationSliceForView(rhsView, viewId);
    const pixelMetrics = computeColorBufferMetrics(lhsRendered.colorBuffer, rhsRendered.colorBuffer);
    const diffPngPath = path.join(
      args.exportDirectory,
      `${args.pairId}-${viewId}-diff-amplified.png`,
    );
    const diffResult = await renderAmplifiedDifference({
      lhsSlice,
      rhsSlice,
      sourceWidth: lhsView.source_width,
      sourceHeight: lhsView.source_height,
      outputWidth: args.frameSize.width,
      outputHeight: args.frameSize.height,
      globalAbsMax:
        args.viewPolicies.find((entry) => entry.view_id === viewId)?.global_abs_max ?? 1,
      outputPath: diffPngPath,
    });
    if (
      pixelMetrics.pixel_rms === 0 &&
      pixelMetrics.mean_absolute_pixel_difference === 0 &&
      lhsRendered.colorBufferHash !== rhsRendered.colorBufferHash
    ) {
      blockingFindings.push("fixed_scale_metric_stage_mismatch");
      collisionRecords.push({
        record_id: `${args.collisionPrefix}:${args.pairId}:${viewId}`,
        finding_code: "fixed_scale_metric_stage_mismatch",
        view_id: viewId,
        lhs_case_id: args.lhsCase.case_id,
        rhs_case_id: args.rhsCase.case_id,
        lhs_source_slice_hash: lhsView.slice_hash,
        rhs_source_slice_hash: rhsView.slice_hash,
        lhs_display_buffer_hash: lhsRendered.displayBufferHash,
        rhs_display_buffer_hash: rhsRendered.displayBufferHash,
        lhs_color_buffer_hash: lhsRendered.colorBufferHash,
        rhs_color_buffer_hash: rhsRendered.colorBufferHash,
        lhs_png_hash: lhsRendered.pngHash,
        rhs_png_hash: rhsRendered.pngHash,
        note:
          "The comparison pair reported zero distance even though the pre-PNG buffers differ.",
      });
    }
    views.push({
      view_id: viewId,
      metric_source_stage: "pre_png_color_buffer",
      pixel_rms: pixelMetrics.pixel_rms,
      mean_absolute_pixel_difference: pixelMetrics.mean_absolute_pixel_difference,
      changed_pixel_fraction: pixelMetrics.changed_pixel_fraction,
      diff_abs_max: diffResult.diffAbsMax,
      amplification_gain: diffResult.amplificationGain,
      lhs_display_buffer_hash: lhsRendered.displayBufferHash,
      rhs_display_buffer_hash: rhsRendered.displayBufferHash,
      lhs_color_buffer_hash: lhsRendered.colorBufferHash,
      rhs_color_buffer_hash: rhsRendered.colorBufferHash,
      lhs_png_hash: lhsRendered.pngHash,
      rhs_png_hash: rhsRendered.pngHash,
      diff_png_path: normalizePath(diffPngPath),
      diff_png_hash: diffResult.diffRendered.pngHash,
    });
  }
  return {
    metric: {
      pair_id: args.pairId,
      lhs_case_id: args.lhsCase.case_id,
      rhs_case_id: args.rhsCase.case_id,
      raw_control_distance: args.rawControlDistance,
      metric_source_stage: "pre_png_color_buffer",
      views,
    },
    blockingFindings,
    collisionRecords,
  };
};

export const buildWarpYorkCanonicalCalibrationArtifact = async (args: {
  payload: ProofPackPayload;
  solveAuthorityAudit: Nhm2SolveAuthorityAuditArtifact;
  sourceAuditArtifactPath: string;
  solveAuthorityAuditPath: string;
  fixedScaleArtifactPath: string;
  exportDirectory: string;
  frameSize: {
    width: number;
    height: number;
  };
  caseInputs: YorkFixedScaleInputCase[];
}): Promise<WarpYorkCanonicalCalibrationArtifact> => {
  const authoritativeLaneId =
    args.payload.diagnosticContract.diagnostic_policy
      .authoritativeLaneIdsForMechanismReadiness[0] ??
    args.payload.diagnosticContract.baseline_lane_id;
  const authoritativeLaneContract =
    args.payload.diagnosticContract.lanes.find((entry) => entry.lane_id === authoritativeLaneId) ??
    args.payload.diagnosticContract.lanes[0];
  if (!authoritativeLaneContract) {
    throw new Error("canonical_calibration_authoritative_lane_missing");
  }
  const laneUsed: YorkLaneUsedSummary = {
    lane_id: authoritativeLaneContract.lane_id,
    observer: authoritativeLaneContract.observer,
    observer_definition: authoritativeLaneContract.observer_definition_id,
    foliation: authoritativeLaneContract.foliation,
    foliation_definition: authoritativeLaneContract.foliation_definition,
    theta_definition: authoritativeLaneContract.theta_definition,
    sign_convention: authoritativeLaneContract.kij_sign_convention,
    normalization_rules: { ...authoritativeLaneContract.normalization_rules },
    view_geometry: { ...authoritativeLaneContract.coordinate_views },
    scope_note:
      "Lane A is the sole authoritative calibration basis. Flat, Alcubierre, Natario, and NHM2 are rendered under the same Lane A contract and compared from the pre-PNG color buffer.",
  };
  const calibrationCases = buildCalibrationPanelCaseInputs(args.caseInputs);
  const viewPolicies: YorkFixedScaleViewPolicy[] = FIXED_SCALE_VIEW_IDS.map((viewId) => {
    const anyView = findCalibrationInputView(calibrationCases[0]!, viewId);
    const globalAbsMax =
      viewId === "york-topology-normalized-3p1"
        ? 1
        : Math.max(
            0,
            ...calibrationCases.map(
              (entry) => findCalibrationInputView(entry, viewId).raw_extrema.absMax ?? 0,
            ),
          );
    return {
      view_id: viewId,
      policy_id:
        viewId === "york-topology-normalized-3p1"
          ? "comparison_fixed_topology_global"
          : "comparison_fixed_raw_global",
      coordinate_mode: anyView.coordinate_mode,
      slice_plane: anyView.coordinate_mode,
      output_size: { ...args.frameSize },
      raw_scale_scope: "shared_global_per_view",
      color_scale_mode:
        viewId === "york-topology-normalized-3p1"
          ? "signed_diverging_unit"
          : "signed_diverging_global",
      sign_encoding: "lane_a_signed_theta",
      global_abs_max: globalAbsMax,
      clipping_applied: false,
      note:
        viewId === "york-topology-normalized-3p1"
          ? "Topology-only normalization to unit max, then one fixed shared display range."
          : "All canonical cases share one global raw amplitude range for this view with no per-case autoscaling.",
    };
  });
  const calibrationCaseExports: CalibrationCaseExport[] = [];
  const calibrationExportByKey = new Map<string, CalibrationViewExport>();
  const renderedByCaseView = new Map<string, FixedScaleRenderedImage>();
  const blockingIntegrityFindings: FixedScaleCollisionCode[] = [];
  const advisoryIntegrityFindings: FixedScaleCollisionCode[] = [];
  const collisionRecords: FixedScaleExportIntegrityCollisionRecord[] = [];
  for (const inputCase of calibrationCases) {
    const viewsForCase: CalibrationViewExport[] = [];
    for (const viewId of FIXED_SCALE_VIEW_IDS) {
      const inputView = findCalibrationInputView(inputCase, viewId);
      const renderSlice = normalizeCalibrationSliceForView(inputView, viewId);
      const extrema = computeRawSliceExtrema(renderSlice);
      const counts = computeSliceSignCounts(renderSlice);
      const policy = viewPolicies.find((entry) => entry.view_id === viewId);
      if (!policy) throw new Error(`canonical_calibration_view_policy_missing:${viewId}`);
      const pngPath = path.join(
        args.exportDirectory,
        `${inputCase.case_id}-${viewId}-${
          viewId === "york-topology-normalized-3p1" ? "fixed-global-topology" : "fixed-global-raw"
        }.png`,
      );
      const rendered = await renderSignedSlicePng({
        slice: renderSlice,
        sourceWidth: inputView.source_width,
        sourceHeight: inputView.source_height,
        outputWidth: args.frameSize.width,
        outputHeight: args.frameSize.height,
        absMax: Math.max(policy.global_abs_max ?? 0, 1e-45),
      });
      ensureDirForFile(pngPath);
      fs.writeFileSync(pngPath, rendered.png);
      renderedByCaseView.set(`${inputCase.case_id}:${viewId}`, rendered);
      const viewExport: CalibrationViewExport = {
        case_id: inputCase.case_id,
        view_id: viewId,
        policy_id: policy.policy_id,
        theta_min: extrema.min,
        theta_max: extrema.max,
        theta_abs_max: extrema.absMax,
        positive_count: counts.positive,
        negative_count: counts.negative,
        near_zero_count: counts.zeroOrNearZero,
        sample_count: counts.total,
        signed_lobe_summary: inputView.signed_lobe_summary,
        support_overlap_pct: inputView.support_overlap_pct ?? null,
        slice_hash: hashFloat32(renderSlice),
        display_buffer_hash: rendered.displayBufferHash,
        color_buffer_hash: rendered.colorBufferHash,
        png_path: normalizePath(pngPath),
        png_hash: rendered.pngHash,
        renderTaxonomy: null,
      };
      viewsForCase.push(viewExport);
      calibrationExportByKey.set(`${inputCase.case_id}:${viewId}`, viewExport);
    }
    calibrationCaseExports.push({
      case_id: inputCase.case_id,
      label: inputCase.label,
      case_role: inputCase.case_role,
      source_kind: inputCase.source_kind,
      validation_passed: false,
      validation_note: "pending",
      views: viewsForCase,
    });
  }
  for (const viewId of FIXED_SCALE_VIEW_IDS) {
    for (let lhsIndex = 0; lhsIndex < calibrationCases.length; lhsIndex += 1) {
      for (let rhsIndex = lhsIndex + 1; rhsIndex < calibrationCases.length; rhsIndex += 1) {
        const lhsCaseId = calibrationCases[lhsIndex]!.case_id;
        const rhsCaseId = calibrationCases[rhsIndex]!.case_id;
        const lhsExport = calibrationExportByKey.get(`${lhsCaseId}:${viewId}`);
        const rhsExport = calibrationExportByKey.get(`${rhsCaseId}:${viewId}`);
        if (!lhsExport || !rhsExport) continue;
        const colorBufferDiffer = lhsExport.color_buffer_hash !== rhsExport.color_buffer_hash;
        if (colorBufferDiffer && lhsExport.png_hash === rhsExport.png_hash) {
          const findingCode: FixedScaleCollisionCode =
            viewId === "york-topology-normalized-3p1"
              ? "topology_export_collision"
              : "display_buffer_distinguishable_png_collision";
          blockingIntegrityFindings.push(findingCode);
          advisoryIntegrityFindings.push("fixed_scale_png_quantization_collapse");
          collisionRecords.push({
            record_id: `calibration:${lhsCaseId}:${rhsCaseId}:${viewId}`,
            finding_code: findingCode,
            view_id: viewId,
            lhs_case_id: lhsCaseId,
            rhs_case_id: rhsCaseId,
            lhs_source_slice_hash: lhsExport.slice_hash,
            rhs_source_slice_hash: rhsExport.slice_hash,
            lhs_display_buffer_hash: lhsExport.display_buffer_hash,
            rhs_display_buffer_hash: rhsExport.display_buffer_hash,
            lhs_color_buffer_hash: lhsExport.color_buffer_hash,
            rhs_color_buffer_hash: rhsExport.color_buffer_hash,
            lhs_png_hash: lhsExport.png_hash,
            rhs_png_hash: rhsExport.png_hash,
            note:
              "Distinct pre-PNG display/color buffers collapsed into an identical canonical calibration PNG.",
          });
        }
      }
    }
  }
  const featureByCaseId = new Map<CalibrationPanelCaseId, CaseClassificationFeatures>();
  const payloadCaseById = new Map(args.payload.cases.map((entry) => [entry.caseId, entry]));
  for (const inputCase of calibrationCases) {
    const payloadCase =
      inputCase.case_id === "flat_space_zero_theta" ? null : payloadCaseById.get(inputCase.case_id);
    featureByCaseId.set(
      inputCase.case_id,
      payloadCase?.classificationFeatures ??
        buildCalibrationClassificationFeatures({
          inputCase,
          viewPolicies,
        }),
    );
  }
  const pairwiseMetrics: CalibrationPairMetric[] = [];
  for (const pair of CALIBRATION_PAIR_CONFIGS) {
    const lhsInput = calibrationCases.find((entry) => entry.case_id === pair.lhs_case_id);
    const rhsInput = calibrationCases.find((entry) => entry.case_id === pair.rhs_case_id);
    if (!lhsInput || !rhsInput) {
      throw new Error(`canonical_calibration_pair_case_missing:${pair.pair_id}`);
    }
    const rawControlDistance = computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: featureByCaseId.get(pair.rhs_case_id)!,
      target: featureByCaseId.get(pair.lhs_case_id)!,
    }).distance;
    const views: CalibrationDiffViewMetric[] = [];
    for (const viewId of FIXED_SCALE_VIEW_IDS) {
      const lhsRendered = renderedByCaseView.get(`${pair.lhs_case_id}:${viewId}`);
      const rhsRendered = renderedByCaseView.get(`${pair.rhs_case_id}:${viewId}`);
      if (!lhsRendered || !rhsRendered) {
        throw new Error(`canonical_calibration_render_missing:${pair.pair_id}:${viewId}`);
      }
      const lhsView = findCalibrationInputView(lhsInput, viewId);
      const rhsView = findCalibrationInputView(rhsInput, viewId);
      const lhsSlice = normalizeCalibrationSliceForView(lhsView, viewId);
      const rhsSlice = normalizeCalibrationSliceForView(rhsView, viewId);
      const pixelMetrics = computeColorBufferMetrics(lhsRendered.colorBuffer, rhsRendered.colorBuffer);
      const diffPngPath = path.join(
        args.exportDirectory,
        `${pair.pair_id}-${viewId}-diff-amplified.png`,
      );
      const diffResult = await renderAmplifiedDifference({
        lhsSlice,
        rhsSlice,
        sourceWidth: lhsView.source_width,
        sourceHeight: lhsView.source_height,
        outputWidth: args.frameSize.width,
        outputHeight: args.frameSize.height,
        globalAbsMax:
          viewPolicies.find((entry) => entry.view_id === viewId)?.global_abs_max ?? 1,
        outputPath: diffPngPath,
      });
      if (
        pixelMetrics.pixel_rms === 0 &&
        pixelMetrics.mean_absolute_pixel_difference === 0 &&
        lhsRendered.colorBufferHash !== rhsRendered.colorBufferHash
      ) {
        blockingIntegrityFindings.push("fixed_scale_metric_stage_mismatch");
        collisionRecords.push({
          record_id: `calibration-metric:${pair.pair_id}:${viewId}`,
          finding_code: "fixed_scale_metric_stage_mismatch",
          view_id: viewId,
          lhs_case_id: pair.lhs_case_id,
          rhs_case_id: pair.rhs_case_id,
          lhs_source_slice_hash: calibrationExportByKey.get(`${pair.lhs_case_id}:${viewId}`)?.slice_hash ?? null,
          rhs_source_slice_hash: calibrationExportByKey.get(`${pair.rhs_case_id}:${viewId}`)?.slice_hash ?? null,
          lhs_display_buffer_hash: lhsRendered.displayBufferHash,
          rhs_display_buffer_hash: rhsRendered.displayBufferHash,
          lhs_color_buffer_hash: lhsRendered.colorBufferHash,
          rhs_color_buffer_hash: rhsRendered.colorBufferHash,
          lhs_png_hash: lhsRendered.pngHash,
          rhs_png_hash: rhsRendered.pngHash,
          note:
            "The canonical calibration pair reported zero distance even though the pre-PNG buffers differ.",
        });
      }
      views.push({
        view_id: viewId,
        metric_source_stage: "pre_png_color_buffer",
        pixel_rms: pixelMetrics.pixel_rms,
        mean_absolute_pixel_difference: pixelMetrics.mean_absolute_pixel_difference,
        changed_pixel_fraction: pixelMetrics.changed_pixel_fraction,
        diff_abs_max: diffResult.diffAbsMax,
        amplification_gain: diffResult.amplificationGain,
        lhs_display_buffer_hash: lhsRendered.displayBufferHash,
        rhs_display_buffer_hash: rhsRendered.displayBufferHash,
        lhs_color_buffer_hash: lhsRendered.colorBufferHash,
        rhs_color_buffer_hash: rhsRendered.colorBufferHash,
        lhs_png_hash: lhsRendered.pngHash,
        rhs_png_hash: rhsRendered.pngHash,
        diff_png_path: normalizePath(diffPngPath),
        diff_png_hash: diffResult.diffRendered.pngHash,
      });
    }
    pairwiseMetrics.push({
      pair_id: pair.pair_id,
      lhs_case_id: pair.lhs_case_id,
      rhs_case_id: pair.rhs_case_id,
      raw_control_distance: rawControlDistance,
      metric_source_stage: "pre_png_color_buffer",
      views,
    });
  }
  const zeroExpectationChecks: CalibrationZeroExpectationCheck[] = [];
  const flatCase = calibrationCases.find((entry) => entry.case_id === "flat_space_zero_theta");
  if (!flatCase) throw new Error("canonical_calibration_flat_case_missing");
  for (const viewId of FIXED_SCALE_VIEW_IDS) {
    const flatView = findCalibrationInputView(flatCase, viewId);
    const zeroRendered = await renderSignedSlicePng({
      slice: new Float32Array(flatView.slice.length),
      sourceWidth: flatView.source_width,
      sourceHeight: flatView.source_height,
      outputWidth: args.frameSize.width,
      outputHeight: args.frameSize.height,
      absMax: Math.max(
        viewPolicies.find((entry) => entry.view_id === viewId)?.global_abs_max ?? 0,
        1e-45,
      ),
    });
    const flatRendered = renderedByCaseView.get(`flat_space_zero_theta:${viewId}`);
    if (!flatRendered) throw new Error(`canonical_calibration_flat_render_missing:${viewId}`);
    const pixelMetrics = computeColorBufferMetrics(flatRendered.colorBuffer, zeroRendered.colorBuffer);
    const diffPngPath = path.join(
      args.exportDirectory,
      `flat_space_zero_theta-vs-zero_expectation-${viewId}-diff-amplified.png`,
    );
    const diffResult = await renderAmplifiedDifference({
      lhsSlice: normalizeCalibrationSliceForView(flatView, viewId),
      rhsSlice: new Float32Array(flatView.slice.length),
      sourceWidth: flatView.source_width,
      sourceHeight: flatView.source_height,
      outputWidth: args.frameSize.width,
      outputHeight: args.frameSize.height,
      globalAbsMax:
        viewPolicies.find((entry) => entry.view_id === viewId)?.global_abs_max ?? 1,
      outputPath: diffPngPath,
    });
    zeroExpectationChecks.push({
      view_id: viewId,
      metric_source_stage: "pre_png_color_buffer",
      pixel_rms: pixelMetrics.pixel_rms,
      mean_absolute_pixel_difference: pixelMetrics.mean_absolute_pixel_difference,
      changed_pixel_fraction: pixelMetrics.changed_pixel_fraction,
      diff_png_path: normalizePath(diffPngPath),
      diff_png_hash: diffResult.diffRendered.pngHash,
      expected_zero_display_buffer_hash: zeroRendered.displayBufferHash,
      actual_display_buffer_hash: flatRendered.displayBufferHash,
      expected_zero_color_buffer_hash: zeroRendered.colorBufferHash,
      actual_color_buffer_hash: flatRendered.colorBufferHash,
    });
  }
  const uniqueBlockingIntegrityFindings = Array.from(new Set(blockingIntegrityFindings));
  const uniqueAdvisoryIntegrityFindings = Array.from(new Set(advisoryIntegrityFindings));
  if (uniqueBlockingIntegrityFindings.length > 0) {
    const findingSummary = collisionRecords
      .map((entry) => `${entry.record_id}:${entry.finding_code}`)
      .join(",");
    throw new Error(
      `york_calibration_export_integrity_failed:${uniqueBlockingIntegrityFindings.join(",")}:${findingSummary}`,
    );
  }
  const flatValidated = zeroExpectationChecks.every(
    (entry) =>
      entry.pixel_rms === 0 &&
      entry.mean_absolute_pixel_difference === 0 &&
      entry.changed_pixel_fraction === 0,
  );
  const alcPayloadCase = payloadCaseById.get("alcubierre_control") ?? null;
  const natPayloadCase = payloadCaseById.get("natario_control") ?? null;
  const alcXzExport =
    calibrationExportByKey.get("alcubierre_control:york-surface-3p1") ?? null;
  const natXzExport = calibrationExportByKey.get("natario_control:york-surface-3p1") ?? null;
  const alcValidated =
    alcPayloadCase != null &&
    hasSufficientSignalForAlcubierreControl(alcPayloadCase) &&
    hasStrongForeAftYork(alcPayloadCase.primaryYork) &&
    (alcXzExport?.signed_lobe_summary === "fore+/aft-" ||
      alcXzExport?.signed_lobe_summary === "fore-/aft+");
  const natValidated =
    natPayloadCase != null &&
    isLowExpansion(natPayloadCase.primaryYork) &&
    (natXzExport?.signed_lobe_summary === "mixed_or_flat" ||
      natXzExport?.signed_lobe_summary == null);
  const controlValidationStatus: CalibrationControlValidationStatus =
    flatValidated && alcValidated && natValidated ? "validated" : "failed";
  const calibrationExportsById = new Map(
    calibrationCaseExports.map((entry) => [entry.case_id, entry]),
  );
  const setCaseValidation = (
    caseId: CalibrationPanelCaseId,
    passed: boolean,
    note: string,
  ): void => {
    const entry = calibrationExportsById.get(caseId);
    if (entry) {
      entry.validation_passed = passed;
      entry.validation_note = note;
    }
  };
  setCaseValidation(
    "flat_space_zero_theta",
    flatValidated,
    flatValidated
      ? "Synthetic zero baseline stays zero under the shared Lane A render contract."
      : "Synthetic zero baseline deviated from the zero expectation under the shared Lane A render contract.",
  );
  setCaseValidation(
    "alcubierre_control",
    alcValidated,
    alcValidated
      ? "Alcubierre control retains the expected strong signed lobe class under the shared contract."
      : "Alcubierre control did not satisfy the expected signed lobe validation under the shared contract.",
  );
  setCaseValidation(
    "natario_control",
    natValidated,
    natValidated
      ? "Natario control retains the expected low-expansion class under the shared contract."
      : "Natario control did not satisfy the expected low-expansion validation under the shared contract.",
  );
  setCaseValidation(
    "nhm2_certified",
    true,
    "NHM2 current solve is the target under test; its class is interpreted only after the canonical controls validate.",
  );
  const nhm2Score = scoreNhm2AgainstReferenceControls({
    contract: args.payload.diagnosticContract,
    alcubierreFeatures: featureByCaseId.get("alcubierre_control")!,
    natarioFeatures: featureByCaseId.get("natario_control")!,
    nhm2Features: featureByCaseId.get("nhm2_certified")!,
  });
  const nhm2CurrentClass: WarpYorkCanonicalCalibrationArtifact["nhm2CurrentClass"] =
    controlValidationStatus !== "validated"
      ? "anomalous_unclassified"
      : nhm2Score.winning_reference === "natario_control" &&
          nhm2Score.margin_sufficient === true &&
          nhm2Score.winning_reference_within_threshold === true &&
          nhm2Score.distinct_by_policy === false
        ? "natario_like_low_expansion"
        : nhm2Score.winning_reference === "alcubierre_control" &&
            nhm2Score.margin_sufficient === true &&
            nhm2Score.winning_reference_within_threshold === true &&
            nhm2Score.distinct_by_policy === false
          ? "alcubierre_like_signed_lobe"
          : "anomalous_unclassified";
  const calibrationVerdict: CalibrationDecisionVerdict =
    controlValidationStatus !== "validated"
      ? "render_contract_not_validated"
      : nhm2CurrentClass === "natario_like_low_expansion"
        ? "canonical_controls_validated_nhm2_natario_like"
        : nhm2CurrentClass === "alcubierre_like_signed_lobe"
          ? "canonical_controls_validated_nhm2_alcubierre_like"
          : "canonical_controls_validated_nhm2_anomalous_unclassified";
  const recommendedNextDebugTarget: WarpYorkCanonicalCalibrationArtifact["decisionGate"]["recommended_next_debug_target"] =
    controlValidationStatus !== "validated"
      ? "render_or_convention_contract"
      : nhm2CurrentClass === "anomalous_unclassified"
        ? "nhm2_source_design"
        : "nhm2_solve_or_coupling";
  const artifactBase: WarpYorkCanonicalCalibrationArtifact = {
    artifactType: "warp_york_canonical_calibration/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This canonical calibration ladder renders a synthetic flat baseline, Alcubierre control, Natario control, and NHM2 current solve under one authoritative Lane A contract so future York-frame debugging can distinguish renderer/convention failures from NHM2-local morphology.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    solveAuthorityAuditPath: normalizePath(args.solveAuthorityAuditPath),
    fixedScaleArtifactPath: normalizePath(args.fixedScaleArtifactPath),
    exportDirectory: normalizePath(args.exportDirectory),
    comparisonContract: {
      laneUsed: laneUsed.lane_id,
      observer: laneUsed.observer,
      foliation: laneUsed.foliation,
      thetaDefinition: laneUsed.theta_definition,
      signConvention: laneUsed.sign_convention,
      fixedScalePolicy:
        "comparison_fixed_raw_global + comparison_fixed_topology_global with no per-case autoscaling",
      visualMetricSourceStage: "pre_png_color_buffer",
      outputSize: { ...args.frameSize },
      requiredViews: [...FIXED_SCALE_VIEW_IDS],
    },
    laneUsed,
    observer: laneUsed.observer,
    foliation: laneUsed.foliation,
    thetaDefinition: laneUsed.theta_definition,
    signConvention: laneUsed.sign_convention,
    fixedScalePolicy:
      "comparison_fixed_raw_global + comparison_fixed_topology_global with no per-case autoscaling",
    visualMetricSourceStage: "pre_png_color_buffer",
    canonicalCases: Array.from(calibrationExportsById.values()),
    pairwiseMetrics,
    zeroExpectationChecks,
    controlValidation: {
      flat_space_zero_theta: {
        status: flatValidated ? "validated" : "failed",
        note:
          calibrationExportsById.get("flat_space_zero_theta")?.validation_note ??
          "flat baseline validation missing",
      },
      alcubierre_control: {
        status: alcValidated ? "validated" : "failed",
        note:
          calibrationExportsById.get("alcubierre_control")?.validation_note ??
          "Alcubierre validation missing",
      },
      natario_control: {
        status: natValidated ? "validated" : "failed",
        note:
          calibrationExportsById.get("natario_control")?.validation_note ??
          "Natario validation missing",
      },
      control_validation_status: controlValidationStatus,
    },
    nhm2CurrentClass,
    decisionGate: {
      calibration_verdict: calibrationVerdict,
      control_validation_status: controlValidationStatus,
      nhm2_current_class: nhm2CurrentClass,
      recommended_next_debug_target: recommendedNextDebugTarget,
      scope_note:
        "Primary comparator = canonical controls rendered through the repo's own Lane A contract. Literature figures remain secondary comparators after convention alignment and do not override this calibration ladder.",
    },
    exportIntegrity: {
      valid: true,
      visual_metric_source_stage: "pre_png_color_buffer",
      blockingFindings: uniqueBlockingIntegrityFindings,
      advisoryFindings: uniqueAdvisoryIntegrityFindings,
      collisionRecords,
    },
    notes: [
      `mechanism_chain_ready=${args.solveAuthorityAudit.readiness.mechanismChainReady}`,
      `diagnostic_authority_closed=${args.solveAuthorityAudit.readiness.diagnosticAuthorityClosed}`,
      `raw_distance_to_natario=${nhm2Score.distance_to_low_expansion_reference ?? "null"}`,
      `raw_distance_to_alcubierre=${nhm2Score.distance_to_alcubierre_reference ?? "null"}`,
      "Future strange York graphs should first be checked against this ladder before reopening renderer or convention debugging.",
      "If flat or canonical controls fail, blame the render/convention contract first. If they pass and NHM2 still differs, debug NHM2 solve/coupling or source design next.",
    ],
  };
  return {
    ...artifactBase,
    checksum: computeCanonicalCalibrationChecksum(artifactBase),
  };
};

export const renderWarpYorkCanonicalCalibrationMarkdown = (
  payload: WarpYorkCanonicalCalibrationArtifact,
): string => {
  const caseRows = payload.canonicalCases
    .flatMap((entry) =>
      entry.views.map(
        (view) =>
          `| ${entry.case_id} | ${entry.case_role} | ${view.view_id} | ${view.theta_abs_max ?? "null"} | ${view.positive_count} | ${view.negative_count} | ${view.near_zero_count} | ${view.signed_lobe_summary ?? "null"} | ${view.support_overlap_pct ?? "null"} | ${view.slice_hash ?? "null"} | ${view.display_buffer_hash} | ${view.color_buffer_hash} | ${view.png_path} |`,
      ),
    )
    .join("\n");
  const pairRows = payload.pairwiseMetrics
    .flatMap((entry) =>
      entry.views.map(
        (view) =>
          `| ${entry.pair_id} | ${view.view_id} | ${entry.raw_control_distance ?? "null"} | ${view.pixel_rms ?? "null"} | ${view.mean_absolute_pixel_difference ?? "null"} | ${view.changed_pixel_fraction ?? "null"} | ${view.diff_abs_max ?? "null"} | ${view.metric_source_stage} | ${view.diff_png_path} |`,
      ),
    )
    .join("\n");
  const zeroRows = payload.zeroExpectationChecks
    .map(
      (entry) =>
        `| ${entry.view_id} | ${entry.pixel_rms ?? "null"} | ${entry.mean_absolute_pixel_difference ?? "null"} | ${entry.changed_pixel_fraction ?? "null"} | ${entry.metric_source_stage} | ${entry.diff_png_path} |`,
    )
    .join("\n");
  const notes = payload.notes.length
    ? payload.notes.map((entry) => `- ${entry}`).join("\n")
    : "- none";
  return `# Warp York Canonical Calibration (${payload.generatedOn})

"${payload.boundaryStatement}"

## Comparison Contract
| field | value |
|---|---|
| laneUsed | ${payload.comparisonContract.laneUsed} |
| observer | ${payload.comparisonContract.observer} |
| foliation | ${payload.comparisonContract.foliation} |
| thetaDefinition | ${payload.comparisonContract.thetaDefinition} |
| signConvention | ${payload.comparisonContract.signConvention} |
| fixedScalePolicy | ${payload.comparisonContract.fixedScalePolicy} |
| visualMetricSourceStage | ${payload.comparisonContract.visualMetricSourceStage} |
| outputSize | ${payload.comparisonContract.outputSize.width}x${payload.comparisonContract.outputSize.height} |
| requiredViews | ${payload.comparisonContract.requiredViews.join(", ")} |

## Canonical Cases
| case_id | case_role | view_id | theta_abs_max | positive_count | negative_count | near_zero_count | signed_lobe_summary | support_overlap_pct | slice_hash | display_buffer_hash | color_buffer_hash | png_path |
|---|---|---|---:|---:|---:|---:|---|---:|---|---|---|---|
${caseRows}

## Pairwise Metrics
| pair_id | view_id | raw_control_distance | pixel_rms | mean_absolute_pixel_difference | changed_pixel_fraction | diff_abs_max | metric_source_stage | diff_png_path |
|---|---|---:|---:|---:|---:|---:|---|---|
${pairRows}

## Flat Zero Checks
| view_id | pixel_rms | mean_absolute_pixel_difference | changed_pixel_fraction | metric_source_stage | diff_png_path |
|---|---:|---:|---:|---|---|
${zeroRows}

## Decision Gate
| field | value |
|---|---|
| calibration_verdict | ${payload.decisionGate.calibration_verdict} |
| control_validation_status | ${payload.decisionGate.control_validation_status} |
| nhm2_current_class | ${payload.decisionGate.nhm2_current_class} |
| recommended_next_debug_target | ${payload.decisionGate.recommended_next_debug_target} |
| scope_note | ${payload.decisionGate.scope_note} |

## Control Validation
| control | status | note |
|---|---|---|
| flat_space_zero_theta | ${payload.controlValidation.flat_space_zero_theta.status} | ${payload.controlValidation.flat_space_zero_theta.note} |
| alcubierre_control | ${payload.controlValidation.alcubierre_control.status} | ${payload.controlValidation.alcubierre_control.note} |
| natario_control | ${payload.controlValidation.natario_control.status} | ${payload.controlValidation.natario_control.note} |
| overall | ${payload.controlValidation.control_validation_status} | primary comparator = repo-local canonical controls |

## Notes
${notes}
`;
};

const toCalibrationInputCase = (
  inputCase: YorkFixedScaleInputCase,
  caseRole: CalibrationCaseRole,
  sourceKind: CalibrationInputCase["source_kind"],
): CalibrationInputCase => ({
  case_id: inputCase.case_id,
  label: inputCase.label,
  case_role: caseRole,
  source_kind: sourceKind,
  views: inputCase.views.map((view) => ({ ...view })),
});

const getPrimaryViewMetric = (
  metric: GenericComparisonPairMetric | null,
  viewId: YorkFixedScaleViewId = "york-surface-3p1",
): CalibrationDiffViewMetric | null => metric?.views.find((entry) => entry.view_id === viewId) ?? null;

const computeFlatReferenceFeatures = (referenceCase: CalibrationInputCase): CaseClassificationFeatures =>
  buildCalibrationClassificationFeatures({
    inputCase: buildSyntheticZeroCalibrationCase(referenceCase as YorkFixedScaleInputCase),
    viewPolicies: buildSharedComparisonViewPolicies({
      inputCases: [referenceCase],
      frameSize: { width: 1, height: 1 },
    }),
  });

export const classifyAblationMovement = (args: {
  ablationId: Nhm2AblationId;
  baselineDistances: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  ablationDistances: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  baselinePrimaryPixelRms: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  ablationPrimaryPixelRms: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  baselineSignedLobeSummary: YorkSignedLobeSummary | null;
  ablationSignedLobeSummary: YorkSignedLobeSummary | null;
  baselineSignCounts: { positive: number | null; negative: number | null };
  ablationSignCounts: { positive: number | null; negative: number | null };
}): Pick<
  Nhm2AblationComparisonRecord,
  | "movementClass"
  | "movementMagnitude"
  | "dominantShift"
  | "likelySubsystemImplication"
  | "signed_lobe_summary_change"
  | "raw_control_distance_delta"
  | "pixel_rms_delta"
  | "sign_count_delta"
> => {
  const towardNatario = safeSubtract(args.baselineDistances.natario, args.ablationDistances.natario);
  const towardAlcubierre = safeSubtract(
    args.baselineDistances.alcubierre,
    args.ablationDistances.alcubierre,
  );
  const towardFlat = safeSubtract(args.baselineDistances.flat, args.ablationDistances.flat);
  const pixelTowardNatario = safeSubtract(
    args.baselinePrimaryPixelRms.natario,
    args.ablationPrimaryPixelRms.natario,
  );
  const pixelTowardAlcubierre = safeSubtract(
    args.baselinePrimaryPixelRms.alcubierre,
    args.ablationPrimaryPixelRms.alcubierre,
  );
  const pixelTowardFlat = safeSubtract(
    args.baselinePrimaryPixelRms.flat,
    args.ablationPrimaryPixelRms.flat,
  );
  const rawCandidates: Array<{ movement: AblationMovementClass; gain: number }> = [
    { movement: "toward_natario", gain: Math.max(towardNatario ?? Number.NEGATIVE_INFINITY, 0) },
    {
      movement: "toward_alcubierre",
      gain: Math.max(towardAlcubierre ?? Number.NEGATIVE_INFINITY, 0),
    },
    {
      movement: "toward_flat_or_degenerate",
      gain: Math.max(towardFlat ?? Number.NEGATIVE_INFINITY, 0),
    },
  ];
  rawCandidates.sort((lhs, rhs) => rhs.gain - lhs.gain);
  const best = rawCandidates[0] ?? { movement: "no_meaningful_shift" as const, gain: 0 };
  const movementClass: AblationMovementClass = best.gain >= 0.01 ? best.movement : "no_meaningful_shift";
  const signedLobeSummaryChange =
    args.baselineSignedLobeSummary === args.ablationSignedLobeSummary
      ? "unchanged"
      : `${args.baselineSignedLobeSummary ?? "null"} -> ${args.ablationSignedLobeSummary ?? "null"}`;
  const signCountDelta = {
    positive: safeSubtract(
      args.ablationSignCounts.positive,
      args.baselineSignCounts.positive,
    ),
    negative: safeSubtract(
      args.ablationSignCounts.negative,
      args.baselineSignCounts.negative,
    ),
  };
  let dominantShift = "No material morphology change under the configured ablation.";
  let likelySubsystemImplication = "No single subsystem implication is dominant from this ablation alone.";
  if (movementClass === "toward_alcubierre") {
    dominantShift = "Ablation moved the current NHM2 morphology toward the Alcubierre control.";
    likelySubsystemImplication =
      args.ablationId === "nhm2_without_hull_coupling"
        ? "Hull coupling is suppressing Alcubierre-like signed lobes in the baseline NHM2 path."
        : args.ablationId === "nhm2_simplified_source"
          ? "Higher-order source shaping is suppressing Alcubierre-like signed lobes."
          : "The ablated subsystem is contributing to the baseline low-expansion class.";
  } else if (movementClass === "toward_natario") {
    dominantShift = "Ablation reinforced the existing Natario-like low-expansion class.";
    likelySubsystemImplication =
      args.ablationId === "nhm2_without_casimir_drive"
        ? "Casimir drive is not the primary morphology driver under the current request path."
        : "The ablated subsystem is not rescuing Alcubierre-like morphology in the baseline path.";
  } else if (movementClass === "toward_flat_or_degenerate") {
    dominantShift = "Ablation collapses part of the current morphology toward flat/degenerate output.";
    likelySubsystemImplication =
      args.ablationId === "nhm2_without_casimir_drive"
        ? "Casimir drive materially supports the current morphology amplitude."
        : "The ablated subsystem carries a substantial portion of the current morphology amplitude.";
  }
  return {
    movementClass,
    movementMagnitude: best.gain,
    dominantShift,
    likelySubsystemImplication,
    signed_lobe_summary_change: signedLobeSummaryChange,
    raw_control_distance_delta: {
      toward_natario: towardNatario,
      toward_alcubierre: towardAlcubierre,
      toward_flat: towardFlat,
    },
    pixel_rms_delta: {
      toward_natario: pixelTowardNatario,
      toward_alcubierre: pixelTowardAlcubierre,
      toward_flat: pixelTowardFlat,
    },
    sign_count_delta: signCountDelta,
  };
};

export const buildNhm2AblationSpecs = (args: {
  baseUrl: string;
  baselineMetricVolumeRef: HullMetricVolumeRefV1;
}): Array<{
  ablation_id: Nhm2AblationId;
  label: string;
  status: Nhm2AblationAvailability;
  reason: string;
  derivationNote: string;
  metricVolumeRef: HullMetricVolumeRefV1 | null;
  selectors: Nhm2AblationSelectorRecord | null;
  couplingToggles: Record<string, boolean | number | string | null>;
  hullSupportToggles: Record<string, boolean | number | string | null>;
}> => {
  const build = (
    ablation_id: Nhm2AblationId,
    label: string,
    derivationNote: string,
    overrides: Partial<Nhm2AblationSelectorRecord>,
    couplingToggles: Record<string, boolean | number | string | null>,
    hullSupportToggles: Record<string, boolean | number | string | null>,
  ) => {
    const derived = buildDerivedMetricVolumeRef({
      baseUrl: args.baseUrl,
      baselineMetricVolumeRef: args.baselineMetricVolumeRef,
      derivedSource: `york-ablation.${ablation_id}`,
      overrides,
    });
    return {
      ablation_id,
      label,
      status: "available" as const,
      reason: "Derived from the live NHM2 brick request by deterministic selector overrides.",
      derivationNote,
      metricVolumeRef: derived.metricVolumeRef,
      selectors: derived.selectors,
      couplingToggles,
      hullSupportToggles,
    };
  };
  return [
    build(
      "nhm2_without_hull_coupling",
      "NHM2 without hull coupling",
      "Replaces the NHM2 natario_sdf shell family with the uncoupled Natario shift shell while preserving the current scalar brick selectors.",
      {
        metricT00Ref: "warp.metric.T00.natario.shift",
        metricT00Source: "metric",
        warpFieldType: "natario",
        requireCongruentSolve: false,
        requireNhm2CongruentFullSolve: false,
      },
      {
        hull_coupling_removed: true,
        casimir_drive_preserved: true,
      },
      {
        support_mask_display_only: false,
        hull_surface_family: "natario_shift_shell_v1",
      },
    ),
    build(
      "nhm2_without_casimir_drive",
      "NHM2 without Casimir drive",
      "Preserves the NHM2 natario_sdf source family but drives q to a near-zero diagnostic floor so the live request path approximates drive-off behavior without changing the Lane A contract.",
      {
        q: 1e-6,
        requireCongruentSolve: false,
        requireNhm2CongruentFullSolve: false,
      },
      {
        hull_coupling_removed: false,
        casimir_drive_q: 1e-6,
      },
      {
        support_mask_display_only: false,
        hull_surface_family: "nhm2_natario_sdf_shell_v1",
      },
    ),
    build(
      "nhm2_simplified_source",
      "NHM2 simplified source",
      "Replaces the NHM2 natario_sdf shell family with the simpler irrotational shell while preserving the current scalar brick selectors.",
      {
        metricT00Ref: "warp.metric.T00.irrotational.shift",
        metricT00Source: "metric",
        warpFieldType: "irrotational",
        requireCongruentSolve: false,
        requireNhm2CongruentFullSolve: false,
      },
      {
        hull_coupling_removed: false,
        casimir_drive_preserved: true,
        simplified_source_family: "irrotational_shell_v1",
      },
      {
        support_mask_display_only: false,
        hull_surface_family: "irrotational_shell_v1",
      },
    ),
    {
      ablation_id: "nhm2_support_mask_off",
      label: "NHM2 support mask off",
      status: "unavailable" as const,
      reason:
        "Support-mask toggles exist only as display overlays in the current pipeline; they are not a distinct NHM2 solve/source ablation surface.",
      derivationNote:
        "Kept unavailable because the current repo exposes support mask changes only as display overlays, not as a source-side brick selector.",
      metricVolumeRef: null,
      selectors: null,
      couplingToggles: {
        hull_coupling_removed: false,
        casimir_drive_preserved: true,
      },
      hullSupportToggles: {
        support_mask_display_only: true,
      },
    },
  ];
};

export const buildNhm2ParameterSweepPlan = (args: {
  baselineSelectors: Nhm2AblationSelectorRecord;
}): Nhm2ParameterSweepDimension[] => {
  const baseline = args.baselineSelectors;
  return [
    {
      parameter_name: "dutyFR",
      baseline_value: baseline.dutyFR ?? 0.0015,
      sweep_values: [Math.max((baseline.dutyFR ?? 0.0015) * 0.5, 1e-6), (baseline.dutyFR ?? 0.0015) * 2],
      sampling_strategy: "deterministic_oat",
      rationale: "Duty cycle is an active brick selector and can change the effective source amplitude envelope without redefining the Lane A contract.",
    },
    {
      parameter_name: "q",
      baseline_value: baseline.q ?? 3,
      sweep_values: [Math.max((baseline.q ?? 3) / 3, 1e-6), (baseline.q ?? 3) * 2],
      sampling_strategy: "deterministic_oat",
      rationale: "q is the direct drive-side morphology lever in the live gr-evolve-brick request path.",
    },
    {
      parameter_name: "gammaGeo",
      baseline_value: baseline.gammaGeo ?? 26,
      sweep_values: [Math.max((baseline.gammaGeo ?? 26) * 0.5, 1), (baseline.gammaGeo ?? 26) * 2],
      sampling_strategy: "deterministic_oat",
      rationale: "gammaGeo is an active geometry-compression selector in the live request path.",
    },
    {
      parameter_name: "gammaVdB",
      baseline_value: baseline.gammaVdB ?? 500,
      sweep_values: [Math.max((baseline.gammaVdB ?? 500) * 0.5, 1), (baseline.gammaVdB ?? 500) * 2],
      sampling_strategy: "deterministic_oat",
      rationale: "gammaVdB is an active Van den Broeck-style morphology/compression selector in the live request path.",
    },
    {
      parameter_name: "zeta",
      baseline_value: baseline.zeta ?? 0.84,
      sweep_values: [
        Math.max(Math.min((baseline.zeta ?? 0.84) * 0.5, 0.99), 0),
        Math.max(Math.min((baseline.zeta ?? 0.84) * 1.15, 0.99), 0),
      ],
      sampling_strategy: "deterministic_oat",
      rationale: "zeta is an active bounded selector in the live request path and can change drive weighting without redesigning the source family.",
    },
  ];
};

export const classifySweepRunMorphology = (args: {
  features: CaseClassificationFeatures;
  scoring: Nhm2ReferenceScoring;
  distanceToFlat: number | null;
}): Nhm2SweepMovementClass => {
  const flatLike =
    (args.distanceToFlat ?? Number.POSITIVE_INFINITY) <= 0.05 &&
    (args.features.near_zero_theta === true ||
      (args.features.theta_abs_max_raw ?? Number.POSITIVE_INFINITY) <= YORK_SIGN_STRUCTURE_EPS);
  if (
    flatLike
  ) {
    return "flat_or_degenerate";
  }
  if (
    args.scoring.winning_reference === "natario_control" &&
    args.scoring.margin_sufficient === true &&
    args.scoring.winning_reference_within_threshold === true &&
    args.scoring.distinct_by_policy === false
  ) {
    return "natario_like_low_expansion";
  }
  if (
    args.scoring.winning_reference === "alcubierre_control" &&
    args.scoring.margin_sufficient === true &&
    args.scoring.winning_reference_within_threshold === true &&
    args.scoring.distinct_by_policy === false
  ) {
    return "alcubierre_like_signed_lobe";
  }
  return "unclassified_intermediate";
};

const buildNhm2AblationComparisonData = async (args: {
  baseUrl: string;
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  canonicalCaseInputs: YorkFixedScaleInputCase[];
  nhm2MetricVolumeRef: HullMetricVolumeRefV1;
  diagnosticLane: YorkDiagnosticLane;
  exportDirectory: string;
  frameSize: { width: number; height: number };
}): Promise<{
  ablationComparisons: Nhm2AblationComparisonRecord[];
  dominantSensitivityCause: AblationDominantSensitivityCause;
  ablationDecision: AblationDecision;
}> => {
  const canonicalById = new Map(args.canonicalCaseInputs.map((entry) => [entry.case_id, entry]));
  const nhm2Input = canonicalById.get("nhm2_certified");
  const natarioInput = canonicalById.get("natario_control");
  const alcubierreInput = canonicalById.get("alcubierre_control");
  if (!nhm2Input || !natarioInput || !alcubierreInput) {
    throw new Error("ablation_case_inputs_missing");
  }
  const zeroInput = buildSyntheticZeroCalibrationCase(nhm2Input);
  const specs = buildNhm2AblationSpecs({
    baseUrl: args.baseUrl,
    baselineMetricVolumeRef: args.nhm2MetricVolumeRef,
  });
  const derivedAvailable = await Promise.all(
    specs
      .filter((entry) => entry.status === "available" && entry.metricVolumeRef)
      .map((entry) =>
        buildDerivedYorkComparisonCase({
          caseId: entry.ablation_id,
          label: entry.label,
          metricVolumeRef: entry.metricVolumeRef!,
          diagnosticLane: args.diagnosticLane,
        }),
      ),
  );
  const derivedById = new Map(derivedAvailable.map((entry) => [entry.case_id, entry]));
  const comparisonInputs: CalibrationInputCase[] = [
    zeroInput,
    toCalibrationInputCase(alcubierreInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(natarioInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(nhm2Input, "nhm2_current", "proof_pack_case"),
    ...derivedAvailable.map((entry) =>
      toCalibrationInputCase(entry.inputCase, "nhm2_redesign", "derived_redesign_case"),
    ),
  ];
  const viewPolicies = buildSharedComparisonViewPolicies({
    inputCases: comparisonInputs,
    frameSize: args.frameSize,
  });
  const renderedPanel = await renderComparisonPanelCases({
    inputCases: comparisonInputs,
    viewPolicies,
    exportDirectory: args.exportDirectory,
    frameSize: args.frameSize,
    collisionPrefix: "ablation",
  });
  const featuresById = new Map<CalibrationPanelCaseId, CaseClassificationFeatures>();
  for (const inputCase of comparisonInputs) {
    featuresById.set(
      inputCase.case_id,
      buildCalibrationClassificationFeatures({
        inputCase,
        viewPolicies,
      }),
    );
  }
  const baselineFeatures = featuresById.get("nhm2_certified");
  const natarioFeatures = featuresById.get("natario_control");
  const alcubierreFeatures = featuresById.get("alcubierre_control");
  const flatFeatures = featuresById.get("flat_space_zero_theta");
  if (!baselineFeatures || !natarioFeatures || !alcubierreFeatures || !flatFeatures) {
    throw new Error("ablation_reference_features_missing");
  }
  const baselineDistances = {
    natario: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: natarioFeatures,
      target: baselineFeatures,
    }).distance,
    alcubierre: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: alcubierreFeatures,
      target: baselineFeatures,
    }).distance,
    flat: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: flatFeatures,
      target: baselineFeatures,
    }).distance,
  };
  const baselinePrimaryPixelRms = {
    natario:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "nhm2_vs_natario",
        ) ?? null,
      )?.pixel_rms ?? null,
    alcubierre:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "nhm2_vs_alcubierre",
        ) ?? null,
      )?.pixel_rms ?? null,
    flat:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "flat_vs_nhm2",
        ) ?? null,
      )?.pixel_rms ?? null,
  };
  const blockingFindings = [...renderedPanel.blockingFindings];
  const collisionRecords = [...renderedPanel.collisionRecords];
  const comparisons: Nhm2AblationComparisonRecord[] = [];
  for (const spec of specs) {
    if (spec.status === "unavailable" || !spec.metricVolumeRef || !spec.selectors) {
      comparisons.push({
        ablation_id: spec.ablation_id,
        case_id: spec.ablation_id,
        label: spec.label,
        status: "unavailable",
        reason: spec.reason,
        metricT00Ref: null,
        metricT00Source: null,
        metricRefHash: null,
        metricVolumeRefUrl: null,
        sourceSelectors: null,
        couplingToggles: spec.couplingToggles,
        hullSupportToggles: spec.hullSupportToggles,
        derivationNote: spec.derivationNote,
        caseViews: [],
        comparison_to_nhm2: null,
        comparison_to_natario: null,
        comparison_to_alcubierre: null,
        comparison_to_flat: null,
        raw_control_distance_delta: {
          toward_natario: null,
          toward_alcubierre: null,
          toward_flat: null,
        },
        pixel_rms_delta: {
          toward_natario: null,
          toward_alcubierre: null,
          toward_flat: null,
        },
        sign_count_delta: {
          positive: null,
          negative: null,
        },
        signed_lobe_summary_change: "unavailable",
        topology_view_delta: null,
        movementClass: "unavailable",
        movementMagnitude: null,
        dominantShift: "Unavailable in the current repo.",
        likelySubsystemImplication:
          spec.ablation_id === "nhm2_support_mask_off"
            ? "Support-mask behavior remains display-only and should not be treated as a solve-side morphology driver."
            : "No honest source-side ablation surface is currently implemented for this request.",
      });
      continue;
    }
    const derivedCase = derivedById.get(spec.ablation_id);
    if (!derivedCase) {
      throw new Error(`ablation_case_missing:${spec.ablation_id}`);
    }
    const ablationInput = comparisonInputs.find((entry) => entry.case_id === spec.ablation_id);
    if (!ablationInput) throw new Error(`ablation_input_missing:${spec.ablation_id}`);
    const ablationFeatures = featuresById.get(spec.ablation_id);
    if (!ablationFeatures) throw new Error(`ablation_features_missing:${spec.ablation_id}`);
    const comparisonToNhm2 = await buildGenericComparisonPairMetric({
      pairId: `${spec.ablation_id}-vs-nhm2_certified`,
      lhsCase: ablationInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "nhm2_certified")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "ablation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: baselineFeatures,
        target: ablationFeatures,
      }).distance,
    });
    const comparisonToNatario = await buildGenericComparisonPairMetric({
      pairId: `${spec.ablation_id}-vs-natario_control`,
      lhsCase: ablationInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "natario_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "ablation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: natarioFeatures,
        target: ablationFeatures,
      }).distance,
    });
    const comparisonToAlcubierre = await buildGenericComparisonPairMetric({
      pairId: `${spec.ablation_id}-vs-alcubierre_control`,
      lhsCase: ablationInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "alcubierre_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "ablation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: alcubierreFeatures,
        target: ablationFeatures,
      }).distance,
    });
    const comparisonToFlat = await buildGenericComparisonPairMetric({
      pairId: `${spec.ablation_id}-vs-flat_space_zero_theta`,
      lhsCase: ablationInput,
      rhsCase: zeroInput,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "ablation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: flatFeatures,
        target: ablationFeatures,
      }).distance,
    });
    blockingFindings.push(
      ...comparisonToNhm2.blockingFindings,
      ...comparisonToNatario.blockingFindings,
      ...comparisonToAlcubierre.blockingFindings,
      ...comparisonToFlat.blockingFindings,
    );
    collisionRecords.push(
      ...comparisonToNhm2.collisionRecords,
      ...comparisonToNatario.collisionRecords,
      ...comparisonToAlcubierre.collisionRecords,
      ...comparisonToFlat.collisionRecords,
    );
    const movement = classifyAblationMovement({
      ablationId: spec.ablation_id,
      baselineDistances,
      ablationDistances: {
        natario: comparisonToNatario.metric.raw_control_distance,
        alcubierre: comparisonToAlcubierre.metric.raw_control_distance,
        flat: comparisonToFlat.metric.raw_control_distance,
      },
      baselinePrimaryPixelRms,
      ablationPrimaryPixelRms: {
        natario: getPrimaryViewMetric(comparisonToNatario.metric)?.pixel_rms ?? null,
        alcubierre: getPrimaryViewMetric(comparisonToAlcubierre.metric)?.pixel_rms ?? null,
        flat: getPrimaryViewMetric(comparisonToFlat.metric)?.pixel_rms ?? null,
      },
      baselineSignedLobeSummary:
        renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.signed_lobe_summary ??
        null,
      ablationSignedLobeSummary:
        renderedPanel.caseExportByKey.get(`${spec.ablation_id}:york-surface-3p1`)?.signed_lobe_summary ??
        null,
      baselineSignCounts: {
        positive:
          renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.positive_count ??
          null,
        negative:
          renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.negative_count ??
          null,
      },
      ablationSignCounts: {
        positive:
          renderedPanel.caseExportByKey.get(`${spec.ablation_id}:york-surface-3p1`)?.positive_count ??
          null,
        negative:
          renderedPanel.caseExportByKey.get(`${spec.ablation_id}:york-surface-3p1`)?.negative_count ??
          null,
      },
    });
    comparisons.push({
      ablation_id: spec.ablation_id,
      case_id: spec.ablation_id,
      label: spec.label,
      status: "available",
      reason: spec.reason,
      metricT00Ref: spec.selectors.metricT00Ref,
      metricT00Source: spec.selectors.metricT00Source,
      metricRefHash: derivedCase.metricRefHash,
      metricVolumeRefUrl: spec.metricVolumeRef.url,
      sourceSelectors: spec.selectors,
      couplingToggles: spec.couplingToggles,
      hullSupportToggles: spec.hullSupportToggles,
      derivationNote: spec.derivationNote,
      caseViews:
        renderedPanel.caseExports.find((entry) => entry.case_id === spec.ablation_id)?.views ?? [],
      comparison_to_nhm2: comparisonToNhm2.metric,
      comparison_to_natario: comparisonToNatario.metric,
      comparison_to_alcubierre: comparisonToAlcubierre.metric,
      comparison_to_flat: comparisonToFlat.metric,
      topology_view_delta:
        comparisonToNhm2.metric.views.find((entry) => entry.view_id === "york-topology-normalized-3p1")
          ?.pixel_rms ?? null,
      ...movement,
    });
  }
  const uniqueBlockingFindings = Array.from(new Set(blockingFindings));
  if (uniqueBlockingFindings.length > 0) {
    throw new Error(
      `ablation_export_integrity_failed:${uniqueBlockingFindings.join(",")}:${collisionRecords
        .map((entry) => `${entry.record_id}:${entry.finding_code}`)
        .join(",")}`,
    );
  }
  const availableComparisons = comparisons.filter((entry) => entry.status === "available");
  let dominantSensitivityCause: AblationDominantSensitivityCause = "inconclusive";
  let ablationDecision: AblationDecision = "no_single_ablation_explains_morphology";
  const strongest = [...availableComparisons]
    .sort((lhs, rhs) => (rhs.movementMagnitude ?? 0) - (lhs.movementMagnitude ?? 0))[0] ?? null;
  if (availableComparisons.length === 0) {
    dominantSensitivityCause = "support_mask_display_only";
    ablationDecision = "no_available_nhm2_ablations";
  } else if (
    availableComparisons.find(
      (entry) =>
        entry.ablation_id === "nhm2_without_hull_coupling" &&
        entry.movementClass === "toward_alcubierre" &&
        (entry.movementMagnitude ?? 0) >= 0.01,
    )
  ) {
    dominantSensitivityCause = "hull_coupling";
    ablationDecision = "hull_coupling_drives_low_expansion_class";
  } else if (
    strongest?.ablation_id === "nhm2_simplified_source" &&
    (strongest.movementMagnitude ?? 0) >= 0.01
  ) {
    dominantSensitivityCause = "source_shaping";
    ablationDecision = "source_shaping_dominates_current_morphology";
  } else if (
    availableComparisons.find(
      (entry) =>
        entry.ablation_id === "nhm2_without_casimir_drive" &&
        entry.movementClass === "no_meaningful_shift",
    )
  ) {
    dominantSensitivityCause = "casimir_drive";
    ablationDecision = "casimir_drive_is_not_primary_morphology_driver";
  } else if (
    comparisons.find(
      (entry) =>
        entry.ablation_id === "nhm2_support_mask_off" && entry.status === "unavailable",
    )
  ) {
    dominantSensitivityCause = strongest?.ablation_id === "nhm2_without_hull_coupling"
      ? "hull_coupling"
      : strongest?.ablation_id === "nhm2_simplified_source"
        ? "source_shaping"
        : strongest?.ablation_id === "nhm2_without_casimir_drive"
          ? "casimir_drive"
          : "support_mask_display_only";
    ablationDecision = strongest ? "no_single_ablation_explains_morphology" : "support_mask_is_display_only_not_solve_driver";
  }
  return {
    ablationComparisons: comparisons,
    dominantSensitivityCause,
    ablationDecision,
  };
};

export const buildNhm2YorkAblationPanelArtifact = (args: {
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  sourceAuditArtifactPath: string;
  canonicalCalibrationArtifactPath: string;
  exportDirectory: string;
  ablationComparisons: Nhm2AblationComparisonRecord[];
  dominantSensitivityCause: AblationDominantSensitivityCause;
  ablationDecision: AblationDecision;
}): Nhm2YorkAblationPanelArtifact => {
  const implementedAblations = args.ablationComparisons
    .filter((entry) => entry.status === "available")
    .map((entry) => entry.ablation_id);
  const stillUnavailableAblations = args.ablationComparisons
    .filter((entry) => entry.status === "unavailable")
    .map((entry) => ({
      ablation_id: entry.ablation_id,
      reason: entry.reason,
    }));
  const artifactBase: Nhm2YorkAblationPanelArtifact = {
    artifactType: "nhm2_york_ablation_panel/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This ablation panel localizes which NHM2 subsystem most strongly drives the current Lane A morphology under the same fixed-scale render contract used for canonical controls.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    canonicalCalibrationArtifactPath: normalizePath(args.canonicalCalibrationArtifactPath),
    exportDirectory: normalizePath(args.exportDirectory),
    comparisonContract: args.canonicalCalibrationArtifact.comparisonContract,
    current_case_id: "nhm2_certified",
    nhm2_current_class: args.canonicalCalibrationArtifact.nhm2CurrentClass,
    implementedAblations,
    stillUnavailableAblations,
    ablationComparisons: args.ablationComparisons,
    dominantSensitivityCause: args.dominantSensitivityCause,
    ablationDecision: args.ablationDecision,
    notes: [
      `calibration_verdict=${args.canonicalCalibrationArtifact.decisionGate.calibration_verdict}`,
      `control_validation_status=${args.canonicalCalibrationArtifact.controlValidation.control_validation_status}`,
      `implemented_ablations=${implementedAblations.join(",") || "none"}`,
      `still_unavailable=${stillUnavailableAblations.map((entry) => entry.ablation_id).join(",") || "none"}`,
      "Canonical controls validate the current Lane A render contract before any NHM2-local blame assignment.",
      "Visual metrics in this ablation panel are computed from the corrected pre-PNG color buffer under the shared fixed-scale policy.",
    ],
  };
  return {
    ...artifactBase,
    checksum: computeAblationPanelChecksum(artifactBase),
  };
};

export const renderNhm2YorkAblationPanelMarkdown = (
  payload: Nhm2YorkAblationPanelArtifact,
): string => {
  const rows = payload.ablationComparisons
    .map(
      (entry) =>
        `| ${entry.ablation_id} | ${entry.status} | ${entry.movementClass} | ${entry.movementMagnitude ?? "null"} | ${entry.metricT00Ref ?? "null"} | ${entry.metricT00Source ?? "null"} | ${entry.dominantShift} | ${entry.likelySubsystemImplication} | ${entry.reason} |`,
    )
    .join("\n");
  const notes = payload.notes.length
    ? payload.notes.map((entry) => `- ${entry}`).join("\n")
    : "- none";
  return `# NHM2 York Ablation Panel (${payload.generatedOn})

"${payload.boundaryStatement}"

## Comparison Contract
| field | value |
|---|---|
| laneUsed | ${payload.comparisonContract.laneUsed} |
| observer | ${payload.comparisonContract.observer} |
| foliation | ${payload.comparisonContract.foliation} |
| thetaDefinition | ${payload.comparisonContract.thetaDefinition} |
| fixedScalePolicy | ${payload.comparisonContract.fixedScalePolicy} |
| visualMetricSourceStage | ${payload.comparisonContract.visualMetricSourceStage} |
| exportDirectory | ${payload.exportDirectory} |

## NHM2 Current Status
| field | value |
|---|---|
| current_case_id | ${payload.current_case_id} |
| nhm2_current_class | ${payload.nhm2_current_class} |
| dominantSensitivityCause | ${payload.dominantSensitivityCause} |
| ablationDecision | ${payload.ablationDecision} |
| implementedAblations | ${payload.implementedAblations.join(", ") || "none"} |
| stillUnavailableAblations | ${payload.stillUnavailableAblations.map((entry) => entry.ablation_id).join(", ") || "none"} |

## Ablation Comparisons
| ablation_id | status | movementClass | movementMagnitude | metricT00Ref | metricT00Source | dominantShift | likelySubsystemImplication | reason |
|---|---|---|---:|---|---|---|---|---|
${rows}

## Notes
${notes}
`;
};

export const buildNhm2SourceRedesignSpecs = (args: {
  baseUrl: string;
  baselineMetricVolumeRef: HullMetricVolumeRefV1;
}): Array<{
  redesign_id: Nhm2SourceRedesignId;
  label: string;
  hypothesis: string;
  derivationNote: string;
  metricVolumeRef: HullMetricVolumeRefV1;
  selectors: Nhm2AblationSelectorRecord;
  redesignToggles: Record<string, boolean | number | string | null>;
}> => {
  const build = (
    redesign_id: Nhm2SourceRedesignId,
    label: string,
    hypothesis: string,
    sourceRedesignMode: Nhm2SourceRedesignMode,
    redesignToggles: Record<string, boolean | number | string | null>,
  ) => {
    const derived = buildDerivedMetricVolumeRef({
      baseUrl: args.baseUrl,
      baselineMetricVolumeRef: args.baselineMetricVolumeRef,
      derivedSource: `york-redesign.${redesign_id}`,
      overrides: {
        sourceRedesignMode,
        requireCongruentSolve: false,
        requireNhm2CongruentFullSolve: false,
      },
    });
    return {
      redesign_id,
      label,
      hypothesis,
      derivationNote:
        "Derived from the live NHM2 gr-evolve-brick request by applying a named source/coupling redesign mode while preserving the canonical Lane A comparison contract.",
      metricVolumeRef: derived.metricVolumeRef,
      selectors: derived.selectors,
      redesignToggles,
    };
  };
  return [
    build(
      "nhm2_redesign_signed_shell_bias",
      "NHM2 redesign: signed shell bias",
      "A stronger signed fore/aft shell bias may unlock Alcubierre-like signed lobes that the current NHM2 shell family suppresses.",
      "signed_shell_bias",
      {
        source_redesign_mode: "signed_shell_bias",
        signed_fore_aft_bias: true,
        shell_asymmetry_strengthened: true,
      },
    ),
    build(
      "nhm2_redesign_coupling_localization",
      "NHM2 redesign: coupling localization",
      "Tighter shell-localized coupling may reduce the diffuse low-expansion behavior that keeps NHM2 in the current Natario-like class.",
      "coupling_localization",
      {
        source_redesign_mode: "coupling_localization",
        shell_localization_strengthened: true,
        coupling_spread_reduced: true,
      },
    ),
    build(
      "nhm2_redesign_drive_vs_geometry_split",
      "NHM2 redesign: drive vs geometry split",
      "Changing the structural mix between geometry-normal coupling and drive-direction coupling may create a more signed longitudinal lobe pattern.",
      "drive_vs_geometry_split",
      {
        source_redesign_mode: "drive_vs_geometry_split",
        drive_direction_weight_upweighted: true,
        geometry_normal_weight_reduced: true,
      },
    ),
    build(
      "nhm2_redesign_source_profile_simplified_signed",
      "NHM2 redesign: simplified signed profile",
      "A simpler signed diagnostic shell profile can test whether higher-order NHM2 shaping is what keeps the baseline morphology Natario-like.",
      "source_profile_simplified_signed",
      {
        source_redesign_mode: "source_profile_simplified_signed",
        signed_profile_simplified: true,
        higher_order_shaping_reduced: true,
      },
    ),
  ];
};

const summarizeAuthoritativeRedesignComparison = (args: {
  comparisonToNhm2: GenericComparisonPairMetric;
  redesignCaseViews: CalibrationViewExport[];
  baselineCaseViews: CalibrationViewExport[];
  redesignSelectors: Nhm2AblationSelectorRecord;
  baselineSelectors: Nhm2AblationSelectorRecord;
  redesignMetricVolumeRefUrl: string;
  baselineMetricVolumeRefUrl: string;
  redesignSnapshotEvidence: DerivedYorkComparisonCase["snapshotEvidence"];
  baselineSnapshotEvidence: DerivedYorkComparisonCase["snapshotEvidence"];
}): Pick<
  Nhm2SourceRedesignComparisonRecord,
  | "authoritativeMorphologyChanged"
  | "movementBasis"
  | "redesignRealizationStatus"
  | "dropStage"
  | "realizationNote"
  | "realizationTrace"
  | "authoritativeComparisonSummary"
> => {
  const authoritativeComparisonSummary: Nhm2SourceRedesignAuthoritativeViewComparison[] =
    FIXED_SCALE_VIEW_IDS.map((viewId) => {
      const lhsView = args.redesignCaseViews.find((entry) => entry.view_id === viewId);
      const rhsView = args.baselineCaseViews.find((entry) => entry.view_id === viewId);
      const metricView = args.comparisonToNhm2.views.find((entry) => entry.view_id === viewId);
      if (!lhsView || !rhsView || !metricView) {
        throw new Error(`source_coupling_redesign_authoritative_view_missing:${viewId}`);
      }
      return {
        view_id: viewId,
        lhs_slice_hash: lhsView.slice_hash,
        rhs_slice_hash: rhsView.slice_hash,
        lhs_display_buffer_hash: metricView.lhs_display_buffer_hash,
        rhs_display_buffer_hash: metricView.rhs_display_buffer_hash,
        lhs_color_buffer_hash: metricView.lhs_color_buffer_hash,
        rhs_color_buffer_hash: metricView.rhs_color_buffer_hash,
        pixel_rms: metricView.pixel_rms,
        changed_pixel_fraction: metricView.changed_pixel_fraction,
        diff_abs_max: metricView.diff_abs_max,
      };
    });
  const primaryRedesignView = args.redesignCaseViews.find(
    (entry) => entry.view_id === "york-surface-3p1",
  );
  const primaryBaselineView = args.baselineCaseViews.find(
    (entry) => entry.view_id === "york-surface-3p1",
  );
  if (!primaryRedesignView || !primaryBaselineView) {
    throw new Error("source_coupling_redesign_primary_view_missing");
  }
  const authoritativeMorphologyChanged = authoritativeComparisonSummary.some(
    (entry) =>
      (entry.pixel_rms ?? 0) > 0 ||
      (entry.changed_pixel_fraction ?? 0) > 0 ||
      (entry.diff_abs_max ?? 0) > 0 ||
      entry.lhs_display_buffer_hash !== entry.rhs_display_buffer_hash ||
      entry.lhs_color_buffer_hash !== entry.rhs_color_buffer_hash,
  );
  const realizationTrace: Nhm2SourceRedesignRealizationTrace = {
    primary_view_id: "york-surface-3p1",
    inputSelectorHash: computeDeterministicHash(args.redesignSelectors),
    baselineInputSelectorHash: computeDeterministicHash(args.baselineSelectors),
    normalizedSelectorHash: computeDeterministicHash(args.redesignSelectors),
    baselineNormalizedSelectorHash: computeDeterministicHash(args.baselineSelectors),
    promotedProfileHash: args.redesignSnapshotEvidence.sourceFamilyHash,
    baselinePromotedProfileHash: args.baselineSnapshotEvidence.sourceFamilyHash,
    brickRequestHash: computeDeterministicHash(args.redesignMetricVolumeRefUrl),
    baselineBrickRequestHash: computeDeterministicHash(args.baselineMetricVolumeRefUrl),
    metricRefHash: args.redesignSnapshotEvidence.metricRefHash,
    baselineMetricRefHash: args.baselineSnapshotEvidence.metricRefHash,
    metricVolumeHash: args.redesignSnapshotEvidence.metricVolumeHash,
    baselineMetricVolumeHash: args.baselineSnapshotEvidence.metricVolumeHash,
    matterChannelHash: args.redesignSnapshotEvidence.matterChannelHash,
    baselineMatterChannelHash: args.baselineSnapshotEvidence.matterChannelHash,
    geometryChannelHash: args.redesignSnapshotEvidence.geometryChannelHash,
    baselineGeometryChannelHash: args.baselineSnapshotEvidence.geometryChannelHash,
    laneAFieldHash: args.redesignSnapshotEvidence.laneAFieldHash,
    baselineLaneAFieldHash: args.baselineSnapshotEvidence.laneAFieldHash,
    thetaChannelHash: args.redesignSnapshotEvidence.thetaChannelHash,
    baselineThetaChannelHash: args.baselineSnapshotEvidence.thetaChannelHash,
    kTraceChannelHash: args.redesignSnapshotEvidence.kTraceChannelHash,
    baselineKTraceChannelHash: args.baselineSnapshotEvidence.kTraceChannelHash,
    laneASliceHash: primaryRedesignView.slice_hash,
    baselineLaneASliceHash: primaryBaselineView.slice_hash,
    laneADisplayHash: primaryRedesignView.display_buffer_hash,
    baselineLaneADisplayHash: primaryBaselineView.display_buffer_hash,
    laneAColorHash: primaryRedesignView.color_buffer_hash,
    baselineLaneAColorHash: primaryBaselineView.color_buffer_hash,
    selectorChanged: false,
    normalizedSelectorChanged: false,
    promotedProfileChanged: false,
    brickRequestChanged: false,
    metricRefChanged: false,
    metricVolumeChanged: false,
    matterChannelsChanged: false,
    geometryChannelsChanged: false,
    laneAFieldChanged: false,
    thetaChannelChanged: false,
    kTraceChannelChanged: false,
    laneASliceChanged: false,
    laneADisplayChanged: false,
    laneAColorChanged: false,
  };
  realizationTrace.selectorChanged =
    realizationTrace.inputSelectorHash !== realizationTrace.baselineInputSelectorHash;
  realizationTrace.normalizedSelectorChanged =
    realizationTrace.normalizedSelectorHash !== realizationTrace.baselineNormalizedSelectorHash;
  realizationTrace.promotedProfileChanged =
    realizationTrace.promotedProfileHash !== realizationTrace.baselinePromotedProfileHash;
  realizationTrace.brickRequestChanged =
    realizationTrace.brickRequestHash !== realizationTrace.baselineBrickRequestHash;
  realizationTrace.metricRefChanged =
    realizationTrace.metricRefHash !== realizationTrace.baselineMetricRefHash;
  realizationTrace.metricVolumeChanged =
    realizationTrace.metricVolumeHash !== realizationTrace.baselineMetricVolumeHash;
  realizationTrace.matterChannelsChanged =
    realizationTrace.matterChannelHash !== realizationTrace.baselineMatterChannelHash;
  realizationTrace.geometryChannelsChanged =
    realizationTrace.geometryChannelHash !== realizationTrace.baselineGeometryChannelHash;
  realizationTrace.laneAFieldChanged =
    realizationTrace.laneAFieldHash !== realizationTrace.baselineLaneAFieldHash;
  realizationTrace.thetaChannelChanged =
    realizationTrace.thetaChannelHash !== realizationTrace.baselineThetaChannelHash;
  realizationTrace.kTraceChannelChanged =
    realizationTrace.kTraceChannelHash !== realizationTrace.baselineKTraceChannelHash;
  realizationTrace.laneASliceChanged =
    realizationTrace.laneASliceHash !== realizationTrace.baselineLaneASliceHash;
  realizationTrace.laneADisplayChanged =
    realizationTrace.laneADisplayHash !== realizationTrace.baselineLaneADisplayHash;
  realizationTrace.laneAColorChanged =
    realizationTrace.laneAColorHash !== realizationTrace.baselineLaneAColorHash;
  let redesignRealizationStatus: Nhm2SourceRedesignRealizationStatus =
    "unrealized_unknown";
  let dropStage: Nhm2SourceRedesignDropStage | null = "unknown";
  let realizationNote =
    "The redesign path diverged somewhere upstream, but the current trace could not yet isolate a single authoritative drop stage.";
  if (authoritativeMorphologyChanged) {
    redesignRealizationStatus = "realized_in_lane_a";
    dropStage = null;
    realizationNote =
      "This redesign mode changes the authoritative Lane A render contract and can be used in morphology ranking.";
  } else if (realizationTrace.selectorChanged && !realizationTrace.normalizedSelectorChanged) {
    redesignRealizationStatus = "selector_changed_but_normalized_away";
    dropStage = "selector_normalization";
    realizationNote =
      "The redesign selector changed at input but normalized back to the baseline selector bundle before the live source path.";
  } else if (
    realizationTrace.normalizedSelectorChanged &&
    !realizationTrace.brickRequestChanged
  ) {
    redesignRealizationStatus = "selector_changed_but_brick_request_unchanged";
    dropStage = "brick_request";
    realizationNote =
      "The normalized redesign selector differs from baseline, but the live brick request remained identical, so the redesign never reached the source solve request.";
  } else if (
    realizationTrace.brickRequestChanged &&
    !realizationTrace.metricVolumeChanged &&
    !realizationTrace.promotedProfileChanged &&
    !realizationTrace.matterChannelsChanged &&
    !realizationTrace.geometryChannelsChanged &&
    !realizationTrace.laneAFieldChanged
  ) {
    redesignRealizationStatus = "brick_request_changed_but_metric_volume_unchanged";
    dropStage = "metric_volume";
    realizationNote =
      "The redesign changed the live brick request, but the decoded snapshot content remained identical to baseline.";
  } else if (
    realizationTrace.promotedProfileChanged &&
    !realizationTrace.matterChannelsChanged &&
    !realizationTrace.geometryChannelsChanged &&
    !realizationTrace.laneAFieldChanged
  ) {
    redesignRealizationStatus = "brick_request_changed_but_metric_volume_unchanged";
    dropStage = "matter_channels";
    realizationNote =
      "The redesign survives into decoded source metadata, but the solved matter channels remain identical to baseline.";
  } else if (
    (realizationTrace.matterChannelsChanged || realizationTrace.promotedProfileChanged) &&
    !realizationTrace.geometryChannelsChanged &&
    !realizationTrace.laneAFieldChanged &&
    !realizationTrace.laneASliceChanged &&
    !realizationTrace.laneADisplayChanged &&
    !realizationTrace.laneAColorChanged
  ) {
    redesignRealizationStatus = "metric_volume_changed_but_lane_a_unchanged";
    dropStage = "geometry_channels";
    realizationNote =
      "The redesign survives into decoded source or matter channels, but the solved geometry channels remain identical to baseline.";
  } else if (
    realizationTrace.geometryChannelsChanged &&
    !realizationTrace.laneAFieldChanged &&
    !realizationTrace.laneASliceChanged &&
    !realizationTrace.laneADisplayChanged &&
    !realizationTrace.laneAColorChanged
  ) {
    redesignRealizationStatus = "metric_volume_changed_but_lane_a_unchanged";
    dropStage = "lane_a_field";
    realizationNote =
      "The redesign changes decoded geometry channels, but the full authoritative Lane A field remains identical to baseline.";
  } else if (
    (realizationTrace.metricVolumeChanged || realizationTrace.laneAFieldChanged) &&
    !realizationTrace.laneASliceChanged &&
    !realizationTrace.laneADisplayChanged &&
    !realizationTrace.laneAColorChanged
  ) {
    redesignRealizationStatus = "metric_volume_changed_but_lane_a_unchanged";
    dropStage = "lane_a_surface";
    realizationNote =
      "The redesign changes the full authoritative Lane A field upstream, but the declared Lane A comparison surfaces and render buffers still collapse to baseline.";
  } else if (
    realizationTrace.metricVolumeChanged ||
    realizationTrace.promotedProfileChanged ||
    realizationTrace.matterChannelsChanged ||
    realizationTrace.geometryChannelsChanged
  ) {
    redesignRealizationStatus = "unrealized_unknown";
    dropStage = "unknown";
    realizationNote =
      "The redesign changed upstream decoded content, but the current trace could not isolate a single authoritative Lane A realization boundary.";
  }
  return {
    authoritativeMorphologyChanged,
    movementBasis: authoritativeMorphologyChanged
      ? "authoritative_lane_pairwise_metric"
      : "authoritative_lane_no_change_gate",
    redesignRealizationStatus,
    dropStage,
    realizationNote,
    realizationTrace,
    authoritativeComparisonSummary,
  };
};

export const classifySourceRedesignMovement = (args: {
  redesignId: Nhm2SourceRedesignId;
  baselineDistances: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  redesignDistances: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  baselinePrimaryPixelRms: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  redesignPrimaryPixelRms: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  baselineSignedLobeSummary: YorkSignedLobeSummary | null;
  redesignSignedLobeSummary: YorkSignedLobeSummary | null;
  baselineSignCounts: { positive: number | null; negative: number | null };
  redesignSignCounts: { positive: number | null; negative: number | null };
  authoritativeMorphologyChanged: boolean;
  redesignRealizationStatus: Nhm2SourceRedesignRealizationStatus;
}): Pick<
  Nhm2SourceRedesignComparisonRecord,
  | "movementClass"
  | "movementMagnitude"
  | "dominantShift"
  | "likelySubsystemImplication"
  | "signed_lobe_summary_change"
  | "raw_control_distance_delta"
  | "pixel_rms_delta"
  | "sign_count_delta"
> => {
  const towardNatario = safeSubtract(args.baselineDistances.natario, args.redesignDistances.natario);
  const towardAlcubierre = safeSubtract(
    args.baselineDistances.alcubierre,
    args.redesignDistances.alcubierre,
  );
  const towardFlat = safeSubtract(args.baselineDistances.flat, args.redesignDistances.flat);
  const pixelTowardNatario = safeSubtract(
    args.baselinePrimaryPixelRms.natario,
    args.redesignPrimaryPixelRms.natario,
  );
  const pixelTowardAlcubierre = safeSubtract(
    args.baselinePrimaryPixelRms.alcubierre,
    args.redesignPrimaryPixelRms.alcubierre,
  );
  const pixelTowardFlat = safeSubtract(
    args.baselinePrimaryPixelRms.flat,
    args.redesignPrimaryPixelRms.flat,
  );
  const rawCandidates: Array<{ movement: Nhm2SourceRedesignMovementClass; gain: number }> = [
    {
      movement: "toward_natario",
      gain: Math.max(towardNatario ?? Number.NEGATIVE_INFINITY, 0),
    },
    {
      movement: "toward_alcubierre",
      gain: Math.max(towardAlcubierre ?? Number.NEGATIVE_INFINITY, 0),
    },
    {
      movement: "toward_flat_or_degenerate",
      gain: Math.max(towardFlat ?? Number.NEGATIVE_INFINITY, 0),
    },
  ];
  rawCandidates.sort((lhs, rhs) => rhs.gain - lhs.gain);
  const best = rawCandidates[0] ?? { movement: "no_material_change" as const, gain: 0 };
  const movementClass: Nhm2SourceRedesignMovementClass =
    best.gain >= 0.01 ? best.movement : "no_material_change";
  const signedLobeSummaryChange =
    args.baselineSignedLobeSummary === args.redesignSignedLobeSummary
      ? "unchanged"
      : `${args.baselineSignedLobeSummary ?? "null"} -> ${args.redesignSignedLobeSummary ?? "null"}`;
  const signCountDelta = {
    positive: safeSubtract(
      args.redesignSignCounts.positive,
      args.baselineSignCounts.positive,
    ),
    negative: safeSubtract(
      args.redesignSignCounts.negative,
      args.baselineSignCounts.negative,
    ),
  };
  if (!args.authoritativeMorphologyChanged) {
    const dominantShift =
      args.redesignRealizationStatus === "metric_volume_changed_but_lane_a_unchanged"
        ? "Redesign selectors changed upstream, but the declared Lane A render contract did not realize a morphology difference."
        : "Redesign selectors changed, but the authoritative Lane A output remained identical to the NHM2 baseline.";
    const likelySubsystemImplication =
      args.redesignRealizationStatus === "metric_volume_changed_but_lane_a_unchanged"
        ? "The redesign path is not yet realized under the authoritative Lane A comparison contract and should be treated as a render-contract collapse, not as morphology movement."
        : "This redesign mode currently behaves like a selector-only change for Lane A; fix redesign realization before using it to justify model-side conclusions.";
    return {
      movementClass: "no_authoritative_morphology_change",
      movementMagnitude: 0,
      dominantShift,
      likelySubsystemImplication,
      signed_lobe_summary_change: signedLobeSummaryChange,
      raw_control_distance_delta: {
        toward_natario: towardNatario,
        toward_alcubierre: towardAlcubierre,
        toward_flat: towardFlat,
      },
      pixel_rms_delta: {
        toward_natario: pixelTowardNatario,
        toward_alcubierre: pixelTowardAlcubierre,
        toward_flat: pixelTowardFlat,
      },
      sign_count_delta: signCountDelta,
    };
  }
  let dominantShift = "No material morphology change under the configured redesign variant.";
  let likelySubsystemImplication =
    "This redesign variant does not yet isolate a stronger next architecture target than the existing ablation and sweep evidence.";
  if (movementClass === "toward_alcubierre") {
    dominantShift = "Redesign variant moved NHM2 toward the Alcubierre control under the canonical Lane A contract.";
    likelySubsystemImplication =
      args.redesignId === "nhm2_redesign_signed_shell_bias"
        ? "The baseline NHM2 source likely under-expresses signed fore/aft shell asymmetry."
        : args.redesignId === "nhm2_redesign_coupling_localization"
          ? "Diffuse hull/service coupling is likely suppressing stronger signed-lobe structure."
          : args.redesignId === "nhm2_redesign_drive_vs_geometry_split"
            ? "The baseline drive-vs-geometry coupling mix is likely damping signed longitudinal morphology."
            : "Higher-order NHM2 source shaping is likely suppressing a simpler signed-lobe regime.";
  } else if (movementClass === "toward_natario") {
    dominantShift = "Redesign variant reinforced the existing Natario-like low-expansion class.";
    likelySubsystemImplication =
      "This redesign direction does not loosen the current Natario-like morphology lock and should not be treated as the primary route toward signed fore/aft lobes.";
  } else if (movementClass === "toward_flat_or_degenerate") {
    dominantShift = "Redesign variant collapses part of the current morphology toward flat or degenerate output.";
    likelySubsystemImplication =
      args.redesignId === "nhm2_redesign_coupling_localization"
        ? "The localized-coupling redesign is over-constraining the shell and shedding too much morphology amplitude."
        : "This redesign direction is structurally too destructive and is removing morphology amplitude faster than it creates signed-lobe structure.";
  } else if (signedLobeSummaryChange !== "unchanged") {
    dominantShift = "Redesign variant changed the signed-lobe presentation without producing a large control-distance gain.";
    likelySubsystemImplication =
      "This may indicate a boundary-like morphology shift that still needs a stronger structural redesign before it becomes class-level change.";
  }
  return {
    movementClass,
    movementMagnitude: best.gain,
    dominantShift,
    likelySubsystemImplication,
    signed_lobe_summary_change: signedLobeSummaryChange,
    raw_control_distance_delta: {
      toward_natario: towardNatario,
      toward_alcubierre: towardAlcubierre,
      toward_flat: towardFlat,
    },
    pixel_rms_delta: {
      toward_natario: pixelTowardNatario,
      toward_alcubierre: pixelTowardAlcubierre,
      toward_flat: pixelTowardFlat,
    },
    sign_count_delta: signCountDelta,
  };
};

export const decideNhm2SourceCouplingRedesignVerdict = (args: {
  redesignComparisons: Nhm2SourceRedesignComparisonRecord[];
}): {
  redesignVerdict: Nhm2SourceRedesignVerdict;
  authoritativeMorphologyChangeObserved: "yes" | "no";
  bestRedesignVariant: Nhm2SourceRedesignId | null;
  strongestMorphologyShift: Nhm2SourceCouplingRedesignArtifact["strongestMorphologyShift"];
  alcubierreLikeTransitionObserved: "yes" | "no";
  recommendedNextAction: string;
} => {
  const realizedComparisons = args.redesignComparisons.filter(
    (entry) => entry.authoritativeMorphologyChanged,
  );
  const firstDropStage = pickFirstRedesignDropStage(args.redesignComparisons);
  if (realizedComparisons.length === 0) {
    const partiallyRealized = args.redesignComparisons.filter(
      (entry) =>
        entry.redesignRealizationStatus === "metric_volume_changed_but_lane_a_unchanged" ||
        entry.dropStage === "matter_channels" ||
        entry.dropStage === "geometry_channels" ||
        entry.dropStage === "lane_a_field" ||
        entry.dropStage === "lane_a_surface",
    );
    return {
      redesignVerdict:
        partiallyRealized.length > 0
          ? "source_coupling_redesign_partially_realized_inconclusive"
          : "source_coupling_redesign_not_realized_in_authoritative_lane",
      authoritativeMorphologyChangeObserved: "no",
      bestRedesignVariant: null,
      strongestMorphologyShift: null,
      alcubierreLikeTransitionObserved: "no",
      recommendedNextAction:
        partiallyRealized.length > 0
          ? "The redesign path now survives into decoded source or geometry evidence, but it still does not move the authoritative Lane A output. Fix the geometry-to-Lane-A realization stage before treating redesign results as model-side morphology evidence."
          : firstDropStage === "metric_volume"
            ? "Fix metric-volume realization ownership first: the redesign selector changes the live brick request, but the decoded metric volume remains identical to baseline."
            : firstDropStage === "brick_request"
              ? "Fix brick-request ownership first: the redesign selector is normalized but never changes the live solve request."
          : "Fix redesign realization/wiring first: the current redesign selectors do not change the authoritative Lane A output, so deeper reformulation is not yet justified by this redesign layer.",
    };
  }
  const strongest =
    [...realizedComparisons].sort(
      (lhs, rhs) => (rhs.movementMagnitude ?? 0) - (lhs.movementMagnitude ?? 0),
    )[0] ?? null;
  const boundaryCase =
    [...realizedComparisons]
      .filter((entry) => {
        const alc = entry.comparison_to_alcubierre.raw_control_distance ?? Number.POSITIVE_INFINITY;
        const nat = entry.comparison_to_natario.raw_control_distance ?? Number.POSITIVE_INFINITY;
        const signed =
          entry.caseViews.find((view) => view.view_id === "york-surface-3p1")?.signed_lobe_summary ??
          "mixed_or_flat";
        return signed !== "mixed_or_flat" && alc <= nat;
      })
      .sort(
        (lhs, rhs) =>
          (lhs.comparison_to_alcubierre.raw_control_distance ?? Number.POSITIVE_INFINITY) -
          (rhs.comparison_to_alcubierre.raw_control_distance ?? Number.POSITIVE_INFINITY),
      )[0] ?? null;
  const anyTowardAlcubierre = realizedComparisons.some(
    (entry) =>
      entry.movementClass === "toward_alcubierre" && (entry.movementMagnitude ?? 0) >= 0.01,
  );
  const alcubierreLikeTransitionObserved: "yes" | "no" = boundaryCase ? "yes" : "no";
  let redesignVerdict: Nhm2SourceRedesignVerdict =
    "source_coupling_redesign_partially_realized_inconclusive";
  let recommendedNextAction =
    "Review the redesign variants for stronger structural separation before using them to guide the next NHM2 architecture pass.";
  if (boundaryCase) {
    redesignVerdict = "source_coupling_redesign_finds_boundary_case";
    recommendedNextAction =
      "Promote the boundary-like redesign into a narrower follow-up architecture pass and test whether its signed-lobe shift can be preserved without reopening the closed Lane A contract.";
  } else if (anyTowardAlcubierre) {
    redesignVerdict = "source_coupling_redesign_moves_toward_alcubierre_but_not_enough";
    recommendedNextAction =
      "Iterate on the best redesign direction with bounded structural follow-up; do not fall back to blind scalar tuning.";
  } else if (
    realizedComparisons.every((entry) =>
      entry.movementClass === "toward_natario" ||
      entry.movementClass === "toward_flat_or_degenerate" ||
      entry.movementClass === "no_material_change",
    )
  ) {
    redesignVerdict = "source_coupling_redesign_still_natario_locked";
    recommendedNextAction =
      "Modest source/coupling redesign remains Natario-locked; prioritize deeper NHM2 model reformulation over additional local tuning.";
  }
  return {
    redesignVerdict,
    authoritativeMorphologyChangeObserved: "yes",
    bestRedesignVariant: strongest?.redesign_id ?? null,
    strongestMorphologyShift:
      strongest == null
        ? null
        : {
            redesign_id: strongest.redesign_id,
            movementClass: strongest.movementClass,
            movementMagnitude: strongest.movementMagnitude,
            dominantShift: strongest.dominantShift,
          },
    alcubierreLikeTransitionObserved,
    recommendedNextAction,
  };
};

const buildNhm2SourceCouplingRedesignData = async (args: {
  baseUrl: string;
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  canonicalCaseInputs: YorkFixedScaleInputCase[];
  nhm2MetricVolumeRef: HullMetricVolumeRefV1;
  diagnosticLane: YorkDiagnosticLane;
  exportDirectory: string;
  frameSize: { width: number; height: number };
}): Promise<{
  redesignComparisons: Nhm2SourceRedesignComparisonRecord[];
  redesignVerdict: Nhm2SourceRedesignVerdict;
  authoritativeMorphologyChangeObserved: "yes" | "no";
  bestRedesignVariant: Nhm2SourceRedesignId | null;
  strongestMorphologyShift: Nhm2SourceCouplingRedesignArtifact["strongestMorphologyShift"];
  alcubierreLikeTransitionObserved: "yes" | "no";
  recommendedNextAction: string;
}> => {
  const canonicalById = new Map(args.canonicalCaseInputs.map((entry) => [entry.case_id, entry]));
  const nhm2Input = canonicalById.get("nhm2_certified");
  const natarioInput = canonicalById.get("natario_control");
  const alcubierreInput = canonicalById.get("alcubierre_control");
  if (!nhm2Input || !natarioInput || !alcubierreInput) {
    throw new Error("source_coupling_redesign_case_inputs_missing");
  }
  const zeroInput = buildSyntheticZeroCalibrationCase(nhm2Input);
  const baselineSelectorBundle = readMetricVolumeRefSelectorBundle(args.nhm2MetricVolumeRef);
  const baselineSnapshot = await loadProofPackSnapshot(
    args.nhm2MetricVolumeRef,
    PROOF_PACK_SNAPSHOT_TIMEOUT_MS,
  );
  const baselineSourceFamily = readSourceFamilyEvidence(baselineSnapshot);
  const baselineLaneField = computeYorkDiagnosticLaneField({
    laneId: args.diagnosticLane.lane_id as YorkDiagnosticLaneId,
    dims: baselineSnapshot.dims,
    voxelSizeM: baselineSnapshot.voxelSize_m,
    theta:
      baselineSnapshot.channels.theta?.data instanceof Float32Array
        ? baselineSnapshot.channels.theta.data
        : null,
    kTrace:
      baselineSnapshot.channels.K_trace?.data instanceof Float32Array
        ? baselineSnapshot.channels.K_trace.data
        : null,
    betaX:
      baselineSnapshot.channels.beta_x?.data instanceof Float32Array
        ? baselineSnapshot.channels.beta_x.data
        : null,
    betaY:
      baselineSnapshot.channels.beta_y?.data instanceof Float32Array
        ? baselineSnapshot.channels.beta_y.data
        : null,
    betaZ:
      baselineSnapshot.channels.beta_z?.data instanceof Float32Array
        ? baselineSnapshot.channels.beta_z.data
        : null,
    alpha:
      baselineSnapshot.channels.alpha?.data instanceof Float32Array
        ? baselineSnapshot.channels.alpha.data
        : null,
    gammaXX:
      baselineSnapshot.channels.gamma_xx?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_xx.data
        : null,
    gammaXY:
      baselineSnapshot.channels.gamma_xy?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_xy.data
        : null,
    gammaXZ:
      baselineSnapshot.channels.gamma_xz?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_xz.data
        : null,
    gammaYY:
      baselineSnapshot.channels.gamma_yy?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_yy.data
        : null,
    gammaYZ:
      baselineSnapshot.channels.gamma_yz?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_yz.data
        : null,
    gammaZZ:
      baselineSnapshot.channels.gamma_zz?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_zz.data
        : null,
  });
  if (!baselineLaneField.ok) {
    throw new Error(
      `source_coupling_redesign_baseline_lane_field_missing:${baselineLaneField.error}`,
    );
  }
  const baselineSnapshotEvidence = {
    sourceFamilyHash: computeSourceFamilyEvidenceHash(baselineSourceFamily),
    metricRefHash: baselineSnapshot.metricRefHash ?? resolveMetricRefHash(args.nhm2MetricVolumeRef),
    metricVolumeHash: computeSnapshotChannelSetHash(
      baselineSnapshot,
      Object.keys(baselineSnapshot.channels),
    ),
    matterChannelHash: computeSnapshotChannelSetHash(
      baselineSnapshot,
      REDESIGN_MATTER_CHANNEL_IDS,
    ),
    geometryChannelHash: computeSnapshotChannelSetHash(
      baselineSnapshot,
      REDESIGN_GEOMETRY_CHANNEL_IDS,
    ),
    laneAFieldHash: computeOptionalFloat32Hash(baselineLaneField.theta),
    thetaChannelHash: computeOptionalFloat32Hash(
      baselineSnapshot.channels.theta?.data instanceof Float32Array
        ? baselineSnapshot.channels.theta.data
        : null,
    ),
    kTraceChannelHash: computeOptionalFloat32Hash(
      baselineSnapshot.channels.K_trace?.data instanceof Float32Array
        ? baselineSnapshot.channels.K_trace.data
        : null,
    ),
  };
  const specs = buildNhm2SourceRedesignSpecs({
    baseUrl: args.baseUrl,
    baselineMetricVolumeRef: args.nhm2MetricVolumeRef,
  });
  const derivedAvailable = await Promise.all(
    specs.map((entry) =>
      buildDerivedYorkComparisonCase({
        caseId: entry.redesign_id,
        label: entry.label,
        metricVolumeRef: entry.metricVolumeRef,
        diagnosticLane: args.diagnosticLane,
      }),
    ),
  );
  const derivedById = new Map(derivedAvailable.map((entry) => [entry.case_id, entry]));
  const comparisonInputs: CalibrationInputCase[] = [
    zeroInput,
    toCalibrationInputCase(alcubierreInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(natarioInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(nhm2Input, "nhm2_current", "proof_pack_case"),
    ...derivedAvailable.map((entry) =>
      toCalibrationInputCase(entry.inputCase, "nhm2_redesign", "derived_redesign_case"),
    ),
  ];
  const viewPolicies = buildSharedComparisonViewPolicies({
    inputCases: comparisonInputs,
    frameSize: args.frameSize,
  });
  const renderedPanel = await renderComparisonPanelCases({
    inputCases: comparisonInputs,
    viewPolicies,
    exportDirectory: args.exportDirectory,
    frameSize: args.frameSize,
    collisionPrefix: "source-redesign",
  });
  const featuresById = new Map<CalibrationPanelCaseId, CaseClassificationFeatures>();
  for (const inputCase of comparisonInputs) {
    featuresById.set(
      inputCase.case_id,
      buildCalibrationClassificationFeatures({
        inputCase,
        viewPolicies,
      }),
    );
  }
  const baselineFeatures = featuresById.get("nhm2_certified");
  const natarioFeatures = featuresById.get("natario_control");
  const alcubierreFeatures = featuresById.get("alcubierre_control");
  const flatFeatures = featuresById.get("flat_space_zero_theta");
  if (!baselineFeatures || !natarioFeatures || !alcubierreFeatures || !flatFeatures) {
    throw new Error("source_coupling_redesign_reference_features_missing");
  }
  const baselineDistances = {
    natario: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: natarioFeatures,
      target: baselineFeatures,
    }).distance,
    alcubierre: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: alcubierreFeatures,
      target: baselineFeatures,
    }).distance,
    flat: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: flatFeatures,
      target: baselineFeatures,
    }).distance,
  };
  const baselinePrimaryPixelRms = {
    natario:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "nhm2_vs_natario",
        ) ?? null,
      )?.pixel_rms ?? null,
    alcubierre:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "nhm2_vs_alcubierre",
        ) ?? null,
      )?.pixel_rms ?? null,
    flat:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "flat_vs_nhm2",
        ) ?? null,
      )?.pixel_rms ?? null,
  };
  const blockingFindings = [...renderedPanel.blockingFindings];
  const collisionRecords = [...renderedPanel.collisionRecords];
  const redesignComparisons: Nhm2SourceRedesignComparisonRecord[] = [];
  const baselineCaseViews =
    renderedPanel.caseExports.find((entry) => entry.case_id === "nhm2_certified")?.views ?? [];
  for (const spec of specs) {
    const derivedCase = derivedById.get(spec.redesign_id);
    if (!derivedCase) {
      throw new Error(`source_coupling_redesign_case_missing:${spec.redesign_id}`);
    }
    const redesignInput = comparisonInputs.find((entry) => entry.case_id === spec.redesign_id);
    if (!redesignInput) throw new Error(`source_coupling_redesign_input_missing:${spec.redesign_id}`);
    const redesignFeatures = featuresById.get(spec.redesign_id);
    if (!redesignFeatures) {
      throw new Error(`source_coupling_redesign_features_missing:${spec.redesign_id}`);
    }
    const comparisonToNhm2 = await buildGenericComparisonPairMetric({
      pairId: `${spec.redesign_id}-vs-nhm2_certified`,
      lhsCase: redesignInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "nhm2_certified")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "source-redesign-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: baselineFeatures,
        target: redesignFeatures,
      }).distance,
    });
    const comparisonToNatario = await buildGenericComparisonPairMetric({
      pairId: `${spec.redesign_id}-vs-natario_control`,
      lhsCase: redesignInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "natario_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "source-redesign-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: natarioFeatures,
        target: redesignFeatures,
      }).distance,
    });
    const comparisonToAlcubierre = await buildGenericComparisonPairMetric({
      pairId: `${spec.redesign_id}-vs-alcubierre_control`,
      lhsCase: redesignInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "alcubierre_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "source-redesign-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: alcubierreFeatures,
        target: redesignFeatures,
      }).distance,
    });
    const comparisonToFlat = await buildGenericComparisonPairMetric({
      pairId: `${spec.redesign_id}-vs-flat_space_zero_theta`,
      lhsCase: redesignInput,
      rhsCase: zeroInput,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "source-redesign-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: flatFeatures,
        target: redesignFeatures,
      }).distance,
    });
    blockingFindings.push(
      ...comparisonToNhm2.blockingFindings,
      ...comparisonToNatario.blockingFindings,
      ...comparisonToAlcubierre.blockingFindings,
      ...comparisonToFlat.blockingFindings,
    );
    collisionRecords.push(
      ...comparisonToNhm2.collisionRecords,
      ...comparisonToNatario.collisionRecords,
      ...comparisonToAlcubierre.collisionRecords,
      ...comparisonToFlat.collisionRecords,
    );
    const redesignCaseViews =
      renderedPanel.caseExports.find((entry) => entry.case_id === spec.redesign_id)?.views ?? [];
    const authoritativeSummary = summarizeAuthoritativeRedesignComparison({
      comparisonToNhm2: comparisonToNhm2.metric,
      redesignCaseViews,
      baselineCaseViews,
      redesignSelectors: spec.selectors,
      baselineSelectors: baselineSelectorBundle.selectors,
      redesignMetricVolumeRefUrl: spec.metricVolumeRef.url,
      baselineMetricVolumeRefUrl: args.nhm2MetricVolumeRef.url,
      redesignSnapshotEvidence: derivedCase.snapshotEvidence,
      baselineSnapshotEvidence,
    });
    const finalizedMovement = classifySourceRedesignMovement({
      redesignId: spec.redesign_id,
      baselineDistances,
      redesignDistances: {
        natario: comparisonToNatario.metric.raw_control_distance,
        alcubierre: comparisonToAlcubierre.metric.raw_control_distance,
        flat: comparisonToFlat.metric.raw_control_distance,
      },
      baselinePrimaryPixelRms,
      redesignPrimaryPixelRms: {
        natario: getPrimaryViewMetric(comparisonToNatario.metric)?.pixel_rms ?? null,
        alcubierre: getPrimaryViewMetric(comparisonToAlcubierre.metric)?.pixel_rms ?? null,
        flat: getPrimaryViewMetric(comparisonToFlat.metric)?.pixel_rms ?? null,
      },
      baselineSignedLobeSummary:
        renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.signed_lobe_summary ??
        null,
      redesignSignedLobeSummary:
        renderedPanel.caseExportByKey.get(`${spec.redesign_id}:york-surface-3p1`)?.signed_lobe_summary ??
        null,
      baselineSignCounts: {
        positive:
          renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.positive_count ??
          null,
        negative:
          renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.negative_count ??
          null,
      },
      redesignSignCounts: {
        positive:
          renderedPanel.caseExportByKey.get(`${spec.redesign_id}:york-surface-3p1`)?.positive_count ??
          null,
        negative:
          renderedPanel.caseExportByKey.get(`${spec.redesign_id}:york-surface-3p1`)?.negative_count ??
          null,
      },
      authoritativeMorphologyChanged: authoritativeSummary.authoritativeMorphologyChanged,
      redesignRealizationStatus: authoritativeSummary.redesignRealizationStatus,
    });
    redesignComparisons.push({
      redesign_id: spec.redesign_id,
      case_id: spec.redesign_id,
      label: spec.label,
      hypothesis: spec.hypothesis,
      metricT00Ref: spec.selectors.metricT00Ref,
      metricT00Source: spec.selectors.metricT00Source,
      metricRefHash: derivedCase.metricRefHash,
      metricVolumeRefUrl: spec.metricVolumeRef.url,
      sourceSelectors: spec.selectors,
      redesignToggles: spec.redesignToggles,
      derivationNote: spec.derivationNote,
      caseViews: redesignCaseViews,
      comparison_to_nhm2: comparisonToNhm2.metric,
      comparison_to_natario: comparisonToNatario.metric,
      comparison_to_alcubierre: comparisonToAlcubierre.metric,
      comparison_to_flat: comparisonToFlat.metric,
      authoritativeMorphologyChanged: authoritativeSummary.authoritativeMorphologyChanged,
      movementBasis: authoritativeSummary.movementBasis,
      redesignRealizationStatus: authoritativeSummary.redesignRealizationStatus,
      dropStage: authoritativeSummary.dropStage,
      realizationNote: authoritativeSummary.realizationNote,
      realizationTrace: authoritativeSummary.realizationTrace,
      authoritativeComparisonSummary: authoritativeSummary.authoritativeComparisonSummary,
      topology_view_delta:
        comparisonToNhm2.metric.views.find((entry) => entry.view_id === "york-topology-normalized-3p1")
          ?.pixel_rms ?? null,
      ...finalizedMovement,
    });
  }
  const uniqueBlockingFindings = Array.from(new Set(blockingFindings));
  if (uniqueBlockingFindings.length > 0) {
    throw new Error(
      `source_coupling_redesign_export_integrity_failed:${uniqueBlockingFindings.join(",")}:${collisionRecords
        .map((entry) => `${entry.record_id}:${entry.finding_code}`)
        .join(",")}`,
    );
  }
  return {
    redesignComparisons,
    ...decideNhm2SourceCouplingRedesignVerdict({
      redesignComparisons,
    }),
  };
};

export const buildNhm2SourceCouplingRedesignArtifact = (args: {
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  ablationArtifact: Nhm2YorkAblationPanelArtifact;
  parameterSweepArtifact: Nhm2ParameterSweepArtifact;
  sourceAuditArtifactPath: string;
  canonicalCalibrationArtifactPath: string;
  ablationArtifactPath: string;
  parameterSweepArtifactPath: string;
  exportDirectory: string;
  redesignComparisons: Nhm2SourceRedesignComparisonRecord[];
  redesignVerdict: Nhm2SourceRedesignVerdict;
  authoritativeMorphologyChangeObserved: "yes" | "no";
  bestRedesignVariant: Nhm2SourceRedesignId | null;
  strongestMorphologyShift: Nhm2SourceCouplingRedesignArtifact["strongestMorphologyShift"];
  alcubierreLikeTransitionObserved: "yes" | "no";
  recommendedNextAction: string;
}): Nhm2SourceCouplingRedesignArtifact => {
  const artifactBase: Nhm2SourceCouplingRedesignArtifact = {
    artifactType: "nhm2_source_coupling_redesign/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This source/coupling redesign panel tests whether modest NHM2 architecture changes can move the current Lane A morphology away from the Natario-like low-expansion class under the canonical render contract.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    canonicalCalibrationArtifactPath: normalizePath(args.canonicalCalibrationArtifactPath),
    ablationArtifactPath: normalizePath(args.ablationArtifactPath),
    parameterSweepArtifactPath: normalizePath(args.parameterSweepArtifactPath),
    exportDirectory: normalizePath(args.exportDirectory),
    comparisonContract: args.canonicalCalibrationArtifact.comparisonContract,
    current_case_id: "nhm2_certified",
    nhm2_current_class: args.canonicalCalibrationArtifact.nhm2CurrentClass,
    authoritativeMorphologyChangeObserved: args.authoritativeMorphologyChangeObserved,
    redesignComparisons: args.redesignComparisons,
    redesignVerdict: args.redesignVerdict,
    bestRedesignVariant: args.bestRedesignVariant,
    strongestMorphologyShift: args.strongestMorphologyShift,
    alcubierreLikeTransitionObserved: args.alcubierreLikeTransitionObserved,
    recommendedNextAction: args.recommendedNextAction,
    notes: [
      `calibration_verdict=${args.canonicalCalibrationArtifact.decisionGate.calibration_verdict}`,
      `ablation_decision=${args.ablationArtifact.ablationDecision}`,
      `parameter_sweep_verdict=${args.parameterSweepArtifact.sweepVerdict}`,
      `visual_metric_source_stage=${args.canonicalCalibrationArtifact.comparisonContract.visualMetricSourceStage}`,
      `authoritative_morphology_change_observed=${args.authoritativeMorphologyChangeObserved}`,
      "Chronology: canonical controls validated first, then NHM2 ablations, then bounded selector sweep, then this source/coupling redesign pass.",
      "Redesign comparisons use the corrected pre-PNG color buffer metric source stage under the shared fixed-scale policy.",
    ],
  };
  return {
    ...artifactBase,
    checksum: crypto
      .createHash("sha256")
      .update(stableStringify({ ...artifactBase, generatedAt: undefined, checksum: undefined }))
      .digest("hex"),
  };
};

const REDESIGN_DROP_STAGE_ORDER: Nhm2SourceRedesignDropStage[] = [
  "selector_normalization",
  "brick_request",
  "metric_volume",
  "matter_channels",
  "geometry_channels",
  "lane_a_field",
  "lane_a_surface",
  "unknown",
];

const pickFirstRedesignDropStage = (
  entries: Nhm2SourceRedesignComparisonRecord[],
): Nhm2SourceRedesignDropStage | null => {
  for (const stage of REDESIGN_DROP_STAGE_ORDER) {
    if (entries.some((entry) => entry.dropStage === stage)) {
      return stage;
    }
  }
  return null;
};

export const buildNhm2SourceCouplingRedesignRealizationArtifact = (args: {
  redesignArtifact: Nhm2SourceCouplingRedesignArtifact;
  redesignArtifactPath: string;
}): Nhm2SourceCouplingRedesignRealizationArtifact => {
  const realizedModes = args.redesignArtifact.redesignComparisons
    .filter((entry) => entry.redesignRealizationStatus === "realized_in_lane_a")
    .map((entry) => entry.redesign_id);
  const unrealizedEntries = args.redesignArtifact.redesignComparisons.filter(
    (entry) => entry.redesignRealizationStatus !== "realized_in_lane_a",
  );
  const artifactBase: Nhm2SourceCouplingRedesignRealizationArtifact = {
    artifactType: "nhm2_source_coupling_redesign_realization/v1",
    generatedOn: args.redesignArtifact.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This realization trace records whether named NHM2 source/coupling redesign modes survive from selector input through the authoritative Lane A render contract.",
    redesignArtifactPath: normalizePath(args.redesignArtifactPath),
    exportDirectory: args.redesignArtifact.exportDirectory,
    comparisonContract: args.redesignArtifact.comparisonContract,
    baselineCaseId: "nhm2_certified",
    redesignRealizationVerdict: args.redesignArtifact.redesignVerdict,
    authoritativeMorphologyChangeObserved:
      args.redesignArtifact.authoritativeMorphologyChangeObserved,
    realizedModes,
    unrealizedModes: unrealizedEntries.map((entry) => ({
      redesign_id: entry.redesign_id,
      redesignRealizationStatus: entry.redesignRealizationStatus,
      dropStage: entry.dropStage,
      realizationNote: entry.realizationNote,
    })),
    firstDropStage: pickFirstRedesignDropStage(unrealizedEntries),
    bestRealizedVariant: args.redesignArtifact.bestRedesignVariant,
    propagationTraces: args.redesignArtifact.redesignComparisons.map((entry) => ({
      redesign_id: entry.redesign_id,
      label: entry.label,
      hypothesis: entry.hypothesis,
      sourceRedesignMode: entry.sourceSelectors.sourceRedesignMode,
      redesignRealizationStatus: entry.redesignRealizationStatus,
      dropStage: entry.dropStage,
      authoritativeMorphologyChanged: entry.authoritativeMorphologyChanged,
      movementClass: entry.movementClass,
      movementMagnitude: entry.movementMagnitude,
      realizationNote: entry.realizationNote,
      trace: entry.realizationTrace,
    })),
    recommendedNextAction: args.redesignArtifact.recommendedNextAction,
    notes: [
      `redesign_verdict=${args.redesignArtifact.redesignVerdict}`,
      `authoritative_morphology_change_observed=${args.redesignArtifact.authoritativeMorphologyChangeObserved}`,
      `best_realized_variant=${args.redesignArtifact.bestRedesignVariant ?? "none"}`,
      "Trace fields are compared against the baseline nhm2_certified case under the canonical Lane A contract.",
      "Brick request hashes are computed from the live gr-evolve-brick request URL, not from display-only render state.",
    ],
  };
  return {
    ...artifactBase,
    checksum: crypto
      .createHash("sha256")
      .update(stableStringify({ ...artifactBase, generatedAt: undefined, checksum: undefined }))
      .digest("hex"),
  };
};

export const formatSourceCouplingRedesignProofPackSummary = (args: {
  calibrationVerdict: WarpYorkCanonicalCalibrationArtifact["decisionGate"]["calibration_verdict"];
  nhm2CurrentClass: WarpYorkCanonicalCalibrationArtifact["nhm2CurrentClass"];
  ablationDecision: Nhm2YorkAblationPanelArtifact["ablationDecision"];
  parameterSweepVerdict: Nhm2ParameterSweepArtifact["sweepVerdict"];
  sourceCouplingRedesignArtifact: Nhm2SourceCouplingRedesignArtifact;
}): string => {
  const redesignArtifact = args.sourceCouplingRedesignArtifact;
  const firstDropStage = pickFirstRedesignDropStage(redesignArtifact.redesignComparisons);
  const redesignActionTag =
    redesignArtifact.authoritativeMorphologyChangeObserved === "yes"
      ? "use_realized_lane_a_redesign_evidence"
      : redesignArtifact.redesignVerdict ===
            "source_coupling_redesign_partially_realized_inconclusive"
        ? "fix_geometry_to_lane_a_realization_stage"
      : "fix_redesign_realization_wiring_first";
  return `york_calibration_verdict=${args.calibrationVerdict} nhm2_current_class=${args.nhm2CurrentClass} ablation_decision=${args.ablationDecision} parameter_sweep_verdict=${args.parameterSweepVerdict} source_coupling_redesign_verdict=${redesignArtifact.redesignVerdict} authoritative_morphology_change_observed=${redesignArtifact.authoritativeMorphologyChangeObserved} best_redesign_variant=${redesignArtifact.bestRedesignVariant ?? "none"} redesign_first_drop_stage=${firstDropStage ?? "none"} redesign_next_action=${redesignActionTag}`;
};

