export const buildNhm2DeeperReformulationSpecs = (args: {
  baseUrl: string;
  baselineMetricVolumeRef: HullMetricVolumeRefV1;
}): Array<{
  reformulation_id: Nhm2SourceReformulationId;
  label: string;
  hypothesis: string;
  derivationNote: string;
  metricVolumeRef: HullMetricVolumeRefV1;
  selectors: Nhm2AblationSelectorRecord;
  reformulationToggles: Record<string, boolean | number | string | null>;
}> => {
  const build = (
    reformulation_id: Nhm2SourceReformulationId,
    label: string,
    hypothesis: string,
    sourceReformulationMode: Nhm2SourceReformulationMode,
    reformulationToggles: Record<string, boolean | number | string | null>,
  ) => {
    const derived = buildDerivedMetricVolumeRef({
      baseUrl: args.baseUrl,
      baselineMetricVolumeRef: args.baselineMetricVolumeRef,
      derivedSource: `york-reformulation.${reformulation_id}`,
      overrides: {
        sourceRedesignMode: null,
        sourceReformulationMode,
        requireCongruentSolve: false,
        requireNhm2CongruentFullSolve: false,
      },
    });
    return {
      reformulation_id,
      label,
      hypothesis,
      derivationNote:
        "Derived from the live NHM2 gr-evolve-brick request by applying a named deeper source reformulation family while preserving the canonical Lane A comparison contract.",
      metricVolumeRef: derived.metricVolumeRef,
      selectors: derived.selectors,
      reformulationToggles,
    };
  };
  return [
    build(
      "nhm2_reform_volume_driven_signed_source",
      "NHM2 reformulation: volume-driven signed source",
      "A volume-distributed signed source may break the current shell-dominant morphology lock and allow stronger signed longitudinal structure.",
      "volume_driven_signed_source",
      {
        source_reformulation_mode: "volume_driven_signed_source",
        shell_dominance_reduced: true,
        signed_volume_support_enabled: true,
      },
    ),
    build(
      "nhm2_reform_fore_aft_antisymmetric_driver",
      "NHM2 reformulation: fore/aft antisymmetric driver",
      "A model-form antisymmetric fore/aft driver may produce stronger signed lobe separation than the current coupled shell family can support.",
      "fore_aft_antisymmetric_driver",
      {
        source_reformulation_mode: "fore_aft_antisymmetric_driver",
        antisymmetric_driver_imposed: true,
        longitudinal_sign_structure_strengthened: true,
      },
    ),
    build(
      "nhm2_reform_geometry_source_decoupling",
      "NHM2 reformulation: geometry/source decoupling",
      "More explicit geometry-source decoupling may reveal whether the current morphology lock is caused by the present shell-coupled source assembly.",
      "geometry_source_decoupling",
      {
        source_reformulation_mode: "geometry_source_decoupling",
        geometry_source_coupling_reduced: true,
        source_volume_support_reweighted: true,
      },
    ),
    build(
      "nhm2_reform_shell_to_dual_layer_family",
      "NHM2 reformulation: shell to dual-layer family",
      "Replacing the single-shell dominant family with a dual-layer signed support family may uncover a boundary between the current Natario-like regime and a stronger signed-lobe class.",
      "shell_to_dual_layer_family",
      {
        source_reformulation_mode: "shell_to_dual_layer_family",
        dual_layer_support_enabled: true,
        inner_outer_shell_split_enabled: true,
      },
    ),
  ];
};

const summarizeAuthoritativeReformulationComparison = (args: {
  comparisonToNhm2: GenericComparisonPairMetric;
  reformulationCaseViews: CalibrationViewExport[];
  baselineCaseViews: CalibrationViewExport[];
  reformulationSelectors: Nhm2AblationSelectorRecord;
  baselineSelectors: Nhm2AblationSelectorRecord;
  reformulationMetricVolumeRefUrl: string;
  baselineMetricVolumeRefUrl: string;
  reformulationSnapshotEvidence: DerivedYorkComparisonCase["snapshotEvidence"];
  baselineSnapshotEvidence: DerivedYorkComparisonCase["snapshotEvidence"];
}): Pick<
  Nhm2DeeperReformulationComparisonRecord,
  | "authoritativeMorphologyChanged"
  | "movementBasis"
  | "reformulationRealizationStatus"
  | "dropStage"
  | "realizationNote"
  | "realizationTrace"
  | "authoritativeComparisonSummary"
> => {
  const summary = summarizeAuthoritativeRedesignComparison({
    comparisonToNhm2: args.comparisonToNhm2,
    redesignCaseViews: args.reformulationCaseViews,
    baselineCaseViews: args.baselineCaseViews,
    redesignSelectors: args.reformulationSelectors,
    baselineSelectors: args.baselineSelectors,
    redesignMetricVolumeRefUrl: args.reformulationMetricVolumeRefUrl,
    baselineMetricVolumeRefUrl: args.baselineMetricVolumeRefUrl,
    redesignSnapshotEvidence: args.reformulationSnapshotEvidence,
    baselineSnapshotEvidence: args.baselineSnapshotEvidence,
  });
  return {
    authoritativeMorphologyChanged: summary.authoritativeMorphologyChanged,
    movementBasis: summary.movementBasis,
    reformulationRealizationStatus: summary.redesignRealizationStatus,
    dropStage: summary.dropStage,
    realizationNote: summary.realizationNote,
    realizationTrace: summary.realizationTrace,
    authoritativeComparisonSummary: summary.authoritativeComparisonSummary,
  };
};

export const classifySourceReformulationMovement = (args: {
  reformulationId: Nhm2SourceReformulationId;
  baselineDistances: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  reformulationDistances: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  baselinePrimaryPixelRms: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  reformulationPrimaryPixelRms: {
    natario: number | null;
    alcubierre: number | null;
    flat: number | null;
  };
  baselineSignedLobeSummary: YorkSignedLobeSummary | null;
  reformulationSignedLobeSummary: YorkSignedLobeSummary | null;
  baselineSignCounts: { positive: number | null; negative: number | null };
  reformulationSignCounts: { positive: number | null; negative: number | null };
  authoritativeMorphologyChanged: boolean;
}): Pick<
  Nhm2DeeperReformulationComparisonRecord,
  | "movementClass"
  | "movementMagnitude"
  | "dominantShift"
  | "likelySubsystemImplication"
  | "signed_lobe_summary_change"
  | "raw_control_distance_delta"
  | "pixel_rms_delta"
  | "sign_count_delta"
> => {
  const towardNatario = safeSubtract(
    args.baselineDistances.natario,
    args.reformulationDistances.natario,
  );
  const towardAlcubierre = safeSubtract(
    args.baselineDistances.alcubierre,
    args.reformulationDistances.alcubierre,
  );
  const towardFlat = safeSubtract(
    args.baselineDistances.flat,
    args.reformulationDistances.flat,
  );
  const pixelTowardNatario = safeSubtract(
    args.baselinePrimaryPixelRms.natario,
    args.reformulationPrimaryPixelRms.natario,
  );
  const pixelTowardAlcubierre = safeSubtract(
    args.baselinePrimaryPixelRms.alcubierre,
    args.reformulationPrimaryPixelRms.alcubierre,
  );
  const pixelTowardFlat = safeSubtract(
    args.baselinePrimaryPixelRms.flat,
    args.reformulationPrimaryPixelRms.flat,
  );
  const signedLobeSummaryChange =
    args.baselineSignedLobeSummary === args.reformulationSignedLobeSummary
      ? "unchanged"
      : `${args.baselineSignedLobeSummary ?? "null"} -> ${args.reformulationSignedLobeSummary ?? "null"}`;
  const signCountDelta = {
    positive: safeSubtract(
      args.reformulationSignCounts.positive,
      args.baselineSignCounts.positive,
    ),
    negative: safeSubtract(
      args.reformulationSignCounts.negative,
      args.baselineSignCounts.negative,
    ),
  };
  if (!args.authoritativeMorphologyChanged) {
    return {
      movementClass: "no_material_change",
      movementMagnitude: 0,
      dominantShift:
        "This reformulation selector does not change the authoritative Lane A output under the current live solve path.",
      likelySubsystemImplication:
        "Treat this as non-realized reformulation evidence; it should remain visible in traces but excluded from morphology ranking.",
      signed_lobe_summary_change: signedLobeSummaryChange,
      raw_control_distance_delta: {
        toward_natario: towardNatario,
        toward_alcubierre: towardAlcubierre,
        toward_flat: towardFlat,
      },
      pixel_rms_delta: {
        toward_natario: pixelTowardNatario,
        toward_alcubierre: pixelTowardAlcubierre,
        toward_flat: pixelTowardFlat,
      },
      sign_count_delta: signCountDelta,
    };
  }
  const rawCandidates: Array<{
    movement: Extract<
      Nhm2SourceReformulationMovementClass,
      "toward_natario" | "toward_alcubierre" | "toward_flat_or_degenerate"
    >;
    gain: number;
  }> = [
    { movement: "toward_natario", gain: Math.max(towardNatario ?? Number.NEGATIVE_INFINITY, 0) },
    {
      movement: "toward_alcubierre",
      gain: Math.max(towardAlcubierre ?? Number.NEGATIVE_INFINITY, 0),
    },
    {
      movement: "toward_flat_or_degenerate",
      gain: Math.max(towardFlat ?? Number.NEGATIVE_INFINITY, 0),
    },
  ];
  rawCandidates.sort((lhs, rhs) => rhs.gain - lhs.gain);
  const best = rawCandidates[0] ?? { movement: "toward_natario" as const, gain: 0 };
  const fallbackMagnitude = Math.max(
    Math.abs(towardNatario ?? 0),
    Math.abs(towardAlcubierre ?? 0),
    Math.abs(towardFlat ?? 0),
    Math.abs(pixelTowardNatario ?? 0),
    Math.abs(pixelTowardAlcubierre ?? 0),
    Math.abs(pixelTowardFlat ?? 0),
  );
  let movementClass: Nhm2SourceReformulationMovementClass =
    best.gain >= 0.01 ? best.movement : "no_material_change";
  let movementMagnitude = best.gain >= 0.01 ? best.gain : 0;
  if (
    movementClass === "no_material_change" &&
    (signedLobeSummaryChange !== "unchanged" ||
      Math.abs(signCountDelta.positive ?? 0) > 0 ||
      Math.abs(signCountDelta.negative ?? 0) > 0) &&
    fallbackMagnitude > 0
  ) {
    movementClass = "new_intermediate_class";
    movementMagnitude = fallbackMagnitude;
  }
  let dominantShift = "No material morphology change under the configured reformulation family.";
  let likelySubsystemImplication =
    "This reformulation family does not yet isolate a stronger architectural direction than the existing redesign evidence.";
  if (movementClass === "toward_alcubierre") {
    dominantShift =
      "Reformulation family moved NHM2 toward the Alcubierre control under the canonical Lane A contract.";
    likelySubsystemImplication =
      args.reformulationId === "nhm2_reform_volume_driven_signed_source"
        ? "Shell-dominant support appears to be suppressing signed volume structure in the baseline NHM2 family."
        : args.reformulationId === "nhm2_reform_fore_aft_antisymmetric_driver"
          ? "The baseline model form likely under-expresses fore/aft antisymmetric drive structure."
          : args.reformulationId === "nhm2_reform_geometry_source_decoupling"
            ? "The current geometry-source coupling is likely damping a stronger signed-lobe morphology."
            : "A dual-layer support family appears more capable of producing signed-lobe structure than the current single-shell family.";
  } else if (movementClass === "toward_natario") {
    dominantShift =
      "Reformulation family reinforced the existing Natario-like low-expansion class.";
    likelySubsystemImplication =
      "This architectural direction does not loosen the current Natario-like morphology lock.";
  } else if (movementClass === "toward_flat_or_degenerate") {
    dominantShift =
      "Reformulation family collapses part of the current morphology toward flat or degenerate output.";
    likelySubsystemImplication =
      "This model-form change is too destructive in its current form and removes morphology amplitude faster than it creates signed-lobe structure.";
  } else if (movementClass === "new_intermediate_class") {
    dominantShift =
      "Reformulation family changed signed-lobe presentation without delivering a clean control-class gain.";
    likelySubsystemImplication =
      "This may be a boundary case worth refining if it is the strongest realized non-destructive shift.";
  }
  return {
    movementClass,
    movementMagnitude,
    dominantShift,
    likelySubsystemImplication,
    signed_lobe_summary_change: signedLobeSummaryChange,
    raw_control_distance_delta: {
      toward_natario: towardNatario,
      toward_alcubierre: towardAlcubierre,
      toward_flat: towardFlat,
    },
    pixel_rms_delta: {
      toward_natario: pixelTowardNatario,
      toward_alcubierre: pixelTowardAlcubierre,
      toward_flat: pixelTowardFlat,
    },
    sign_count_delta: signCountDelta,
  };
};

export const decideNhm2DeeperReformulationVerdict = (args: {
  reformulationComparisons: Nhm2DeeperReformulationComparisonRecord[];
}): {
  reformulationVerdict: Nhm2DeeperReformulationVerdict;
  authoritativeMorphologyChangeObserved: "yes" | "no";
  bestReformulationVariant: Nhm2SourceReformulationId | null;
  strongestMorphologyShift: Nhm2DeeperReformulationArtifact["strongestMorphologyShift"];
  alcubierreLikeTransitionObserved: "yes" | "no";
  recommendedNextAction: string;
} => {
  const realizedComparisons = args.reformulationComparisons.filter(
    (entry) => entry.authoritativeMorphologyChanged,
  );
  if (realizedComparisons.length === 0) {
    return {
      reformulationVerdict: "deeper_reformulation_inconclusive",
      authoritativeMorphologyChangeObserved: "no",
      bestReformulationVariant: null,
      strongestMorphologyShift: null,
      alcubierreLikeTransitionObserved: "no",
      recommendedNextAction:
        "Fix reformulation realization/wiring first: the current reformulation families do not yet change the authoritative Lane A output.",
    };
  }
  const strongest =
    [...realizedComparisons].sort((lhs, rhs) => {
      const lhsScore =
        (lhs.movementClass === "toward_alcubierre"
          ? 3
          : lhs.movementClass === "new_intermediate_class"
            ? 2
            : 1) * (lhs.movementMagnitude ?? 0);
      const rhsScore =
        (rhs.movementClass === "toward_alcubierre"
          ? 3
          : rhs.movementClass === "new_intermediate_class"
            ? 2
            : 1) * (rhs.movementMagnitude ?? 0);
      return rhsScore - lhsScore;
    })[0] ?? null;
  const alcubierreLikeTransitionObserved = realizedComparisons.some(
    (entry) =>
      entry.movementClass === "toward_alcubierre" &&
      (entry.comparison_to_alcubierre.raw_control_distance ?? Number.POSITIVE_INFINITY) <
        (entry.comparison_to_natario.raw_control_distance ?? Number.POSITIVE_INFINITY),
  )
    ? "yes"
    : "no";
  if (!strongest) {
    return {
      reformulationVerdict: "deeper_reformulation_inconclusive",
      authoritativeMorphologyChangeObserved: "yes",
      bestReformulationVariant: null,
      strongestMorphologyShift: null,
      alcubierreLikeTransitionObserved,
      recommendedNextAction:
        "Re-run the reformulation panel with a stronger boundary-case criterion; current realized changes are too weak to rank cleanly.",
    };
  }
  let reformulationVerdict: Nhm2DeeperReformulationVerdict =
    "deeper_reformulation_inconclusive";
  let recommendedNextAction =
    "Use the strongest realized reformulation as the next architecture candidate and keep the canonical Lane A contract fixed.";
  if (alcubierreLikeTransitionObserved === "yes") {
    reformulationVerdict = "deeper_reformulation_realizes_alcubierre_like_transition";
    recommendedNextAction =
      "Focus on the realized reformulation family that crossed closest to the Alcubierre-like class and tighten that architecture rather than returning to local tuning.";
  } else if (strongest.movementClass === "toward_alcubierre") {
    reformulationVerdict = "deeper_reformulation_moves_toward_alcubierre_but_not_enough";
    recommendedNextAction =
      "Iterate on the strongest realized reformulation family; it moves in the right direction but still does not cross the morphology boundary.";
  } else if (strongest.movementClass === "new_intermediate_class") {
    reformulationVerdict = "deeper_reformulation_finds_boundary_case";
    recommendedNextAction =
      "Treat the best realized reformulation as a boundary case and refine that architecture before attempting a broader model rewrite.";
  } else {
    reformulationVerdict = "deeper_reformulation_still_natario_locked";
    recommendedNextAction =
      "The current NHM2 family still appears Natario-locked even under deeper realized reformulations; the next step is a broader model reformulation rather than more local selector work.";
  }
  return {
    reformulationVerdict,
    authoritativeMorphologyChangeObserved: "yes",
    bestReformulationVariant: strongest.reformulation_id,
    strongestMorphologyShift: {
      reformulation_id: strongest.reformulation_id,
      movementClass: strongest.movementClass,
      movementMagnitude: strongest.movementMagnitude,
      dominantShift: strongest.dominantShift,
    },
    alcubierreLikeTransitionObserved,
    recommendedNextAction,
  };
};

export const buildNhm2DeeperReformulationData = async (args: {
  baseUrl: string;
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  sourceCouplingRedesignArtifact: Nhm2SourceCouplingRedesignArtifact;
  canonicalCaseInputs: YorkFixedScaleInputCase[];
  nhm2MetricVolumeRef: HullMetricVolumeRefV1;
  diagnosticLane: YorkDiagnosticLane;
  exportDirectory: string;
  frameSize: { width: number; height: number };
}): Promise<{
  reformulationComparisons: Nhm2DeeperReformulationComparisonRecord[];
  reformulationVerdict: Nhm2DeeperReformulationVerdict;
  authoritativeMorphologyChangeObserved: "yes" | "no";
  bestReformulationVariant: Nhm2SourceReformulationId | null;
  strongestMorphologyShift: Nhm2DeeperReformulationArtifact["strongestMorphologyShift"];
  alcubierreLikeTransitionObserved: "yes" | "no";
  recommendedNextAction: string;
}> => {
  const alcubierreInput = args.canonicalCaseInputs.find((entry) => entry.case_id === "alcubierre_control");
  const natarioInput = args.canonicalCaseInputs.find((entry) => entry.case_id === "natario_control");
  const nhm2Input = args.canonicalCaseInputs.find((entry) => entry.case_id === "nhm2_certified");
  if (!alcubierreInput || !natarioInput || !nhm2Input) {
    throw new Error("deeper_reformulation_case_inputs_missing");
  }
  const zeroInput = buildSyntheticZeroCalibrationCase(nhm2Input);
  const baselineSelectorBundle = readMetricVolumeRefSelectorBundle(args.nhm2MetricVolumeRef);
  const baselineSnapshot = await loadProofPackSnapshot(
    args.nhm2MetricVolumeRef,
    PROOF_PACK_SNAPSHOT_TIMEOUT_MS,
  );
  const baselineSourceFamily = readSourceFamilyEvidence(baselineSnapshot);
  const baselineLaneField = computeYorkDiagnosticLaneField({
    laneId: args.diagnosticLane.lane_id as YorkDiagnosticLaneId,
    dims: baselineSnapshot.dims,
    voxelSizeM: baselineSnapshot.voxelSize_m,
    theta:
      baselineSnapshot.channels.theta?.data instanceof Float32Array
        ? baselineSnapshot.channels.theta.data
        : null,
    kTrace:
      baselineSnapshot.channels.K_trace?.data instanceof Float32Array
        ? baselineSnapshot.channels.K_trace.data
        : null,
    betaX:
      baselineSnapshot.channels.beta_x?.data instanceof Float32Array
        ? baselineSnapshot.channels.beta_x.data
        : null,
    betaY:
      baselineSnapshot.channels.beta_y?.data instanceof Float32Array
        ? baselineSnapshot.channels.beta_y.data
        : null,
    betaZ:
      baselineSnapshot.channels.beta_z?.data instanceof Float32Array
        ? baselineSnapshot.channels.beta_z.data
        : null,
    alpha:
      baselineSnapshot.channels.alpha?.data instanceof Float32Array
        ? baselineSnapshot.channels.alpha.data
        : null,
    gammaXX:
      baselineSnapshot.channels.gamma_xx?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_xx.data
        : null,
    gammaXY:
      baselineSnapshot.channels.gamma_xy?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_xy.data
        : null,
    gammaXZ:
      baselineSnapshot.channels.gamma_xz?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_xz.data
        : null,
    gammaYY:
      baselineSnapshot.channels.gamma_yy?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_yy.data
        : null,
    gammaYZ:
      baselineSnapshot.channels.gamma_yz?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_yz.data
        : null,
    gammaZZ:
      baselineSnapshot.channels.gamma_zz?.data instanceof Float32Array
        ? baselineSnapshot.channels.gamma_zz.data
        : null,
  });
  if (!baselineLaneField.ok) {
    throw new Error(
      `deeper_reformulation_baseline_lane_field_missing:${baselineLaneField.error}`,
    );
  }
  const baselineSnapshotEvidence = {
    sourceFamilyHash: computeSourceFamilyEvidenceHash(baselineSourceFamily),
    metricRefHash: baselineSnapshot.metricRefHash ?? resolveMetricRefHash(args.nhm2MetricVolumeRef),
    metricVolumeHash: computeSnapshotChannelSetHash(
      baselineSnapshot,
      Object.keys(baselineSnapshot.channels),
    ),
    matterChannelHash: computeSnapshotChannelSetHash(
      baselineSnapshot,
      REDESIGN_MATTER_CHANNEL_IDS,
    ),
    geometryChannelHash: computeSnapshotChannelSetHash(
      baselineSnapshot,
      REDESIGN_GEOMETRY_CHANNEL_IDS,
    ),
    laneAFieldHash: computeOptionalFloat32Hash(baselineLaneField.theta),
    thetaChannelHash: computeOptionalFloat32Hash(
      baselineSnapshot.channels.theta?.data instanceof Float32Array
        ? baselineSnapshot.channels.theta.data
        : null,
    ),
    kTraceChannelHash: computeOptionalFloat32Hash(
      baselineSnapshot.channels.K_trace?.data instanceof Float32Array
        ? baselineSnapshot.channels.K_trace.data
        : null,
    ),
  };
  const specs = buildNhm2DeeperReformulationSpecs({
    baseUrl: args.baseUrl,
    baselineMetricVolumeRef: args.nhm2MetricVolumeRef,
  });
  const derivedAvailable = await Promise.all(
    specs.map((entry) =>
      buildDerivedYorkComparisonCase({
        caseId: entry.reformulation_id,
        label: entry.label,
        metricVolumeRef: entry.metricVolumeRef,
        diagnosticLane: args.diagnosticLane,
      }),
    ),
  );
  const derivedById = new Map(derivedAvailable.map((entry) => [entry.case_id, entry]));
  const comparisonInputs: CalibrationInputCase[] = [
    zeroInput,
    toCalibrationInputCase(alcubierreInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(natarioInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(nhm2Input, "nhm2_current", "proof_pack_case"),
    ...derivedAvailable.map((entry) =>
      toCalibrationInputCase(
        entry.inputCase,
        "nhm2_reformulation",
        "derived_reformulation_case",
      ),
    ),
  ];
  const viewPolicies = buildSharedComparisonViewPolicies({
    inputCases: comparisonInputs,
    frameSize: args.frameSize,
  });
  const renderedPanel = await renderComparisonPanelCases({
    inputCases: comparisonInputs,
    viewPolicies,
    exportDirectory: args.exportDirectory,
    frameSize: args.frameSize,
    collisionPrefix: "deeper-reformulation",
  });
  const featuresById = new Map<CalibrationPanelCaseId, CaseClassificationFeatures>();
  for (const inputCase of comparisonInputs) {
    featuresById.set(
      inputCase.case_id,
      buildCalibrationClassificationFeatures({
        inputCase,
        viewPolicies,
      }),
    );
  }
  const baselineFeatures = featuresById.get("nhm2_certified");
  const natarioFeatures = featuresById.get("natario_control");
  const alcubierreFeatures = featuresById.get("alcubierre_control");
  const flatFeatures = featuresById.get("flat_space_zero_theta");
  if (!baselineFeatures || !natarioFeatures || !alcubierreFeatures || !flatFeatures) {
    throw new Error("deeper_reformulation_reference_features_missing");
  }
  const baselineDistances = {
    natario: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: natarioFeatures,
      target: baselineFeatures,
    }).distance,
    alcubierre: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: alcubierreFeatures,
      target: baselineFeatures,
    }).distance,
    flat: computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: flatFeatures,
      target: baselineFeatures,
    }).distance,
  };
  const baselinePrimaryPixelRms = {
    natario:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "nhm2_vs_natario",
        ) ?? null,
      )?.pixel_rms ?? null,
    alcubierre:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "nhm2_vs_alcubierre",
        ) ?? null,
      )?.pixel_rms ?? null,
    flat:
      getPrimaryViewMetric(
        args.canonicalCalibrationArtifact.pairwiseMetrics.find(
          (entry) => entry.pair_id === "flat_vs_nhm2",
        ) ?? null,
      )?.pixel_rms ?? null,
  };
  const blockingFindings = [...renderedPanel.blockingFindings];
  const collisionRecords = [...renderedPanel.collisionRecords];
  const reformulationComparisons: Nhm2DeeperReformulationComparisonRecord[] = [];
  const baselineCaseViews =
    renderedPanel.caseExports.find((entry) => entry.case_id === "nhm2_certified")?.views ?? [];
  for (const spec of specs) {
    const derivedCase = derivedById.get(spec.reformulation_id);
    if (!derivedCase) {
      throw new Error(`deeper_reformulation_case_missing:${spec.reformulation_id}`);
    }
    const reformulationInput = comparisonInputs.find(
      (entry) => entry.case_id === spec.reformulation_id,
    );
    if (!reformulationInput) {
      throw new Error(`deeper_reformulation_input_missing:${spec.reformulation_id}`);
    }
    const reformulationFeatures = featuresById.get(spec.reformulation_id);
    if (!reformulationFeatures) {
      throw new Error(`deeper_reformulation_features_missing:${spec.reformulation_id}`);
    }
    const comparisonToNhm2 = await buildGenericComparisonPairMetric({
      pairId: `${spec.reformulation_id}-vs-nhm2_certified`,
      lhsCase: reformulationInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "nhm2_certified")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "deeper-reformulation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: baselineFeatures,
        target: reformulationFeatures,
      }).distance,
    });
    const comparisonToNatario = await buildGenericComparisonPairMetric({
      pairId: `${spec.reformulation_id}-vs-natario_control`,
      lhsCase: reformulationInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "natario_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "deeper-reformulation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: natarioFeatures,
        target: reformulationFeatures,
      }).distance,
    });
    const comparisonToAlcubierre = await buildGenericComparisonPairMetric({
      pairId: `${spec.reformulation_id}-vs-alcubierre_control`,
      lhsCase: reformulationInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "alcubierre_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "deeper-reformulation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: alcubierreFeatures,
        target: reformulationFeatures,
      }).distance,
    });
    const comparisonToFlat = await buildGenericComparisonPairMetric({
      pairId: `${spec.reformulation_id}-vs-flat_space_zero_theta`,
      lhsCase: reformulationInput,
      rhsCase: zeroInput,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "deeper-reformulation-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: flatFeatures,
        target: reformulationFeatures,
      }).distance,
    });
    blockingFindings.push(
      ...comparisonToNhm2.blockingFindings,
      ...comparisonToNatario.blockingFindings,
      ...comparisonToAlcubierre.blockingFindings,
      ...comparisonToFlat.blockingFindings,
    );
    collisionRecords.push(
      ...comparisonToNhm2.collisionRecords,
      ...comparisonToNatario.collisionRecords,
      ...comparisonToAlcubierre.collisionRecords,
      ...comparisonToFlat.collisionRecords,
    );
    const reformulationCaseViews =
      renderedPanel.caseExports.find((entry) => entry.case_id === spec.reformulation_id)?.views ?? [];
    const authoritativeSummary = summarizeAuthoritativeReformulationComparison({
      comparisonToNhm2: comparisonToNhm2.metric,
      reformulationCaseViews,
      baselineCaseViews,
      reformulationSelectors: spec.selectors,
      baselineSelectors: baselineSelectorBundle.selectors,
      reformulationMetricVolumeRefUrl: spec.metricVolumeRef.url,
      baselineMetricVolumeRefUrl: args.nhm2MetricVolumeRef.url,
      reformulationSnapshotEvidence: derivedCase.snapshotEvidence,
      baselineSnapshotEvidence,
    });
    const finalizedMovement = classifySourceReformulationMovement({
      reformulationId: spec.reformulation_id,
      baselineDistances,
      reformulationDistances: {
        natario: comparisonToNatario.metric.raw_control_distance,
        alcubierre: comparisonToAlcubierre.metric.raw_control_distance,
        flat: comparisonToFlat.metric.raw_control_distance,
      },
      baselinePrimaryPixelRms,
      reformulationPrimaryPixelRms: {
        natario: getPrimaryViewMetric(comparisonToNatario.metric)?.pixel_rms ?? null,
        alcubierre: getPrimaryViewMetric(comparisonToAlcubierre.metric)?.pixel_rms ?? null,
        flat: getPrimaryViewMetric(comparisonToFlat.metric)?.pixel_rms ?? null,
      },
      baselineSignedLobeSummary:
        renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.signed_lobe_summary ??
        null,
      reformulationSignedLobeSummary:
        renderedPanel.caseExportByKey.get(`${spec.reformulation_id}:york-surface-3p1`)
          ?.signed_lobe_summary ?? null,
      baselineSignCounts: {
        positive:
          renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.positive_count ??
          null,
        negative:
          renderedPanel.caseExportByKey.get("nhm2_certified:york-surface-3p1")?.negative_count ??
          null,
      },
      reformulationSignCounts: {
        positive:
          renderedPanel.caseExportByKey.get(`${spec.reformulation_id}:york-surface-3p1`)
            ?.positive_count ?? null,
        negative:
          renderedPanel.caseExportByKey.get(`${spec.reformulation_id}:york-surface-3p1`)
            ?.negative_count ?? null,
      },
      authoritativeMorphologyChanged: authoritativeSummary.authoritativeMorphologyChanged,
    });
    reformulationComparisons.push({
      reformulation_id: spec.reformulation_id,
      case_id: spec.reformulation_id,
      label: spec.label,
      hypothesis: spec.hypothesis,
      metricT00Ref: spec.selectors.metricT00Ref,
      metricT00Source: spec.selectors.metricT00Source,
      metricRefHash: derivedCase.metricRefHash,
      metricVolumeRefUrl: spec.metricVolumeRef.url,
      sourceSelectors: spec.selectors,
      reformulationToggles: spec.reformulationToggles,
      derivationNote: spec.derivationNote,
      caseViews: reformulationCaseViews,
      comparison_to_nhm2: comparisonToNhm2.metric,
      comparison_to_natario: comparisonToNatario.metric,
      comparison_to_alcubierre: comparisonToAlcubierre.metric,
      comparison_to_flat: comparisonToFlat.metric,
      authoritativeMorphologyChanged: authoritativeSummary.authoritativeMorphologyChanged,
      movementBasis: authoritativeSummary.movementBasis,
      reformulationRealizationStatus: authoritativeSummary.reformulationRealizationStatus,
      dropStage: authoritativeSummary.dropStage,
      realizationNote: authoritativeSummary.realizationNote,
      realizationTrace: authoritativeSummary.realizationTrace,
      authoritativeComparisonSummary: authoritativeSummary.authoritativeComparisonSummary,
      topology_view_delta:
        comparisonToNhm2.metric.views.find((entry) => entry.view_id === "york-topology-normalized-3p1")
          ?.pixel_rms ?? null,
      ...finalizedMovement,
    });
  }
  const uniqueBlockingFindings = Array.from(new Set(blockingFindings));
  if (uniqueBlockingFindings.length > 0) {
    throw new Error(
      `deeper_reformulation_export_integrity_failed:${uniqueBlockingFindings.join(",")}:${collisionRecords
        .map((entry) => `${entry.record_id}:${entry.finding_code}`)
        .join(",")}`,
    );
  }
  return {
    reformulationComparisons,
    ...decideNhm2DeeperReformulationVerdict({
      reformulationComparisons,
    }),
  };
};

export const buildNhm2DeeperReformulationArtifact = (args: {
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  sourceCouplingRedesignArtifact: Nhm2SourceCouplingRedesignArtifact;
  sourceAuditArtifactPath: string;
  canonicalCalibrationArtifactPath: string;
  redesignArtifactPath: string;
  exportDirectory: string;
  reformulationComparisons: Nhm2DeeperReformulationComparisonRecord[];
  reformulationVerdict: Nhm2DeeperReformulationVerdict;
  authoritativeMorphologyChangeObserved: "yes" | "no";
  bestReformulationVariant: Nhm2SourceReformulationId | null;
  strongestMorphologyShift: Nhm2DeeperReformulationArtifact["strongestMorphologyShift"];
  alcubierreLikeTransitionObserved: "yes" | "no";
  recommendedNextAction: string;
}): Nhm2DeeperReformulationArtifact => {
  const artifactBase: Nhm2DeeperReformulationArtifact = {
    artifactType: "nhm2_deeper_reformulation/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This deeper NHM2 reformulation panel tests whether model-form changes beyond local source/coupling redesign can move the current Lane A morphology away from the Natario-like low-expansion class under the canonical render contract.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    canonicalCalibrationArtifactPath: normalizePath(args.canonicalCalibrationArtifactPath),
    redesignArtifactPath: normalizePath(args.redesignArtifactPath),
    exportDirectory: normalizePath(args.exportDirectory),
    comparisonContract: args.canonicalCalibrationArtifact.comparisonContract,
    current_case_id: "nhm2_certified",
    nhm2_current_class: args.canonicalCalibrationArtifact.nhm2CurrentClass,
    authoritativeMorphologyChangeObserved: args.authoritativeMorphologyChangeObserved,
    reformulationComparisons: args.reformulationComparisons,
    reformulationVerdict: args.reformulationVerdict,
    bestReformulationVariant: args.bestReformulationVariant,
    strongestMorphologyShift: args.strongestMorphologyShift,
    alcubierreLikeTransitionObserved: args.alcubierreLikeTransitionObserved,
    recommendedNextAction: args.recommendedNextAction,
    notes: [
      `calibration_verdict=${args.canonicalCalibrationArtifact.decisionGate.calibration_verdict}`,
      `source_coupling_redesign_verdict=${args.sourceCouplingRedesignArtifact.redesignVerdict}`,
      `visual_metric_source_stage=${args.canonicalCalibrationArtifact.comparisonContract.visualMetricSourceStage}`,
      `authoritative_morphology_change_observed=${args.authoritativeMorphologyChangeObserved}`,
      "Chronology: canonical controls validated first, then bounded tuning, then realized local redesigns, then this deeper reformulation pass.",
      "Reformulation comparisons use the corrected pre-PNG color buffer metric source stage under the shared fixed-scale policy.",
    ],
  };
  return {
    ...artifactBase,
    checksum: crypto
      .createHash("sha256")
      .update(stableStringify({ ...artifactBase, generatedAt: undefined, checksum: undefined }))
      .digest("hex"),
  };
};

export const formatDeeperReformulationProofPackSummary = (args: {
  deeperReformulationArtifact: Nhm2DeeperReformulationArtifact;
}): string => {
  const reformulationArtifact = args.deeperReformulationArtifact;
  const reformulationActionTag =
    reformulationArtifact.authoritativeMorphologyChangeObserved === "yes"
      ? reformulationArtifact.alcubierreLikeTransitionObserved === "yes"
        ? "pursue_realized_alcubierre_direction"
        : "use_realized_reformulation_evidence"
      : "fix_reformulation_realization_wiring_first";
  return `deeper_reformulation_verdict=${reformulationArtifact.reformulationVerdict} authoritative_reformulation_change_observed=${reformulationArtifact.authoritativeMorphologyChangeObserved} best_reformulation_variant=${reformulationArtifact.bestReformulationVariant ?? "none"} reformulation_next_action=${reformulationActionTag}`;
};

export const renderNhm2DeeperReformulationMarkdown = (
  payload: Nhm2DeeperReformulationArtifact,
): string => {
  const rows = payload.reformulationComparisons
    .map(
      (entry) =>
        `| ${entry.reformulation_id} | ${entry.authoritativeMorphologyChanged} | ${entry.reformulationRealizationStatus} | ${entry.dropStage ?? "null"} | ${entry.movementBasis} | ${entry.movementClass} | ${entry.movementMagnitude ?? "null"} | ${entry.hypothesis} | ${entry.metricT00Ref ?? "null"} | ${entry.sourceSelectors.sourceReformulationMode ?? "null"} | ${entry.comparison_to_nhm2.raw_control_distance ?? "null"} | ${entry.comparison_to_natario.raw_control_distance ?? "null"} | ${entry.comparison_to_alcubierre.raw_control_distance ?? "null"} | ${entry.comparison_to_flat.raw_control_distance ?? "null"} | ${entry.realizationNote} | ${entry.dominantShift} | ${entry.likelySubsystemImplication} |`,
    )
    .join("\n");
  const notes = payload.notes.length
    ? payload.notes.map((entry) => `- ${entry}`).join("\n")
    : "- none";
  return `# NHM2 Deeper Reformulation (${payload.generatedOn})

"${payload.boundaryStatement}"

## Comparison Contract
| field | value |
|---|---|
| laneUsed | ${payload.comparisonContract.laneUsed} |
| observer | ${payload.comparisonContract.observer} |
| foliation | ${payload.comparisonContract.foliation} |
| thetaDefinition | ${payload.comparisonContract.thetaDefinition} |
| fixedScalePolicy | ${payload.comparisonContract.fixedScalePolicy} |
| visualMetricSourceStage | ${payload.comparisonContract.visualMetricSourceStage} |
| exportDirectory | ${payload.exportDirectory} |

## Reformulation Verdict
| field | value |
|---|---|
| reformulationVerdict | ${payload.reformulationVerdict} |
| authoritativeMorphologyChangeObserved | ${payload.authoritativeMorphologyChangeObserved} |
| bestReformulationVariant | ${payload.bestReformulationVariant ?? "null"} |
| alcubierreLikeTransitionObserved | ${payload.alcubierreLikeTransitionObserved} |
| strongestMorphologyShift | ${payload.strongestMorphologyShift?.reformulation_id ?? "null"} / ${payload.strongestMorphologyShift?.movementClass ?? "null"} / ${payload.strongestMorphologyShift?.movementMagnitude ?? "null"} |
| recommendedNextAction | ${payload.recommendedNextAction} |

## Reformulation Comparisons
| reformulation_id | authoritativeMorphologyChanged | reformulationRealizationStatus | dropStage | movementBasis | movementClass | movementMagnitude | hypothesis | metricT00Ref | sourceReformulationMode | distance_to_nhm2 | distance_to_natario | distance_to_alcubierre | distance_to_flat | realizationNote | dominantShift | likelySubsystemImplication |
|---|---|---|---|---|---|---:|---|---|---|---:|---:|---:|---:|---|---|---|
${rows}

## Notes
${notes}
`;
};

export const renderNhm2DeeperReformulationDecisionMemo = (
  payload: Nhm2DeeperReformulationArtifact,
): string => `# NHM2 Deeper Reformulation Decision Memo (${payload.generatedOn})

## Comparison basis

- lane: \`${payload.comparisonContract.laneUsed}\`
- observer: \`${payload.comparisonContract.observer}\`
- foliation: \`${payload.comparisonContract.foliation}\`
- theta definition: \`${payload.comparisonContract.thetaDefinition}\`
- fixed-scale policy: ${payload.comparisonContract.fixedScalePolicy}
- visual metric source stage: \`${payload.comparisonContract.visualMetricSourceStage}\`

## Evidence chronology

1. Canonical controls validated the Lane A render contract.
2. Bounded tuning did not find an Alcubierre-like regime.
3. Realized local source/coupling redesigns remained Natario-like.
4. This deeper reformulation pass then tested model-form changes beyond those local redesigns.

## Reformulation conclusion

- reformulationVerdict: \`${payload.reformulationVerdict}\`
- authoritativeMorphologyChangeObserved: \`${payload.authoritativeMorphologyChangeObserved}\`
- bestReformulationVariant: \`${payload.bestReformulationVariant ?? "null"}\`
- alcubierreLikeTransitionObserved: \`${payload.alcubierreLikeTransitionObserved}\`
- strongestMorphologyShift: \`${payload.strongestMorphologyShift?.reformulation_id ?? "null"} / ${payload.strongestMorphologyShift?.movementClass ?? "null"} / ${payload.strongestMorphologyShift?.movementMagnitude ?? "null"}\`
- recommendedNextAction: ${payload.recommendedNextAction}

## Realized variants

${payload.reformulationComparisons
  .filter((entry) => entry.authoritativeMorphologyChanged)
  .map(
    (entry) =>
      `- ${entry.reformulation_id}: movement=${entry.movementClass}; magnitude=${entry.movementMagnitude ?? "null"}; sourceReformulationMode=${entry.sourceSelectors.sourceReformulationMode ?? "null"}; implication=${entry.likelySubsystemImplication}`,
  )
  .join("\n") || "- none"}

## Scope note

- This is a repo-local diagnostic reformulation pass under the canonical Lane A contract.
- It is not a physical-feasibility proof.
- It is not an exact theory-identity claim.
- Literature figures remain secondary comparators, not the primary benchmark.
`;

export const buildNhm2ParameterSweepArtifact = async (args: {
  baseUrl: string;
  payload: ProofPackPayload;
  canonicalCalibrationArtifact: WarpYorkCanonicalCalibrationArtifact;
  sourceAuditArtifactPath: string;
  canonicalCalibrationArtifactPath: string;
  ablationArtifactPath: string;
  canonicalCaseInputs: YorkFixedScaleInputCase[];
  nhm2MetricVolumeRef: HullMetricVolumeRefV1;
  diagnosticLane: YorkDiagnosticLane;
  exportDirectory: string;
  frameSize: { width: number; height: number };
}): Promise<Nhm2ParameterSweepArtifact> => {
  const baselineSelectors = readMetricVolumeRefSelectorBundle(args.nhm2MetricVolumeRef).selectors;
  const sweepDimensions = buildNhm2ParameterSweepPlan({
    baselineSelectors,
  });
  const baselineRunId: ParameterSweepRunId = "nhm2_sweep_baseline";
  const runSpecs: Array<{
    run_id: ParameterSweepRunId;
    label: string;
    varied_parameter: Nhm2ParameterSweepDimension["parameter_name"] | "baseline";
    varied_value: number | null;
    metricVolumeRef: HullMetricVolumeRefV1;
    selectors: Nhm2AblationSelectorRecord;
  }> = [];
  runSpecs.push({
    run_id: baselineRunId,
    label: "NHM2 sweep baseline",
    varied_parameter: "baseline",
    varied_value: null,
    metricVolumeRef: args.nhm2MetricVolumeRef,
    selectors: baselineSelectors,
  });
  for (const dimension of sweepDimensions) {
    for (const value of dimension.sweep_values) {
      const derived = buildDerivedMetricVolumeRef({
        baseUrl: args.baseUrl,
        baselineMetricVolumeRef: args.nhm2MetricVolumeRef,
        derivedSource: `york-sweep.${dimension.parameter_name}.${value}`,
        overrides: {
          [dimension.parameter_name]: value,
          requireCongruentSolve: false,
          requireNhm2CongruentFullSolve: false,
        } as Partial<Nhm2AblationSelectorRecord>,
      });
      runSpecs.push({
        run_id: `nhm2_sweep_${dimension.parameter_name}_${String(value).replace(/\./g, "_")}`,
        label: `NHM2 sweep ${dimension.parameter_name}=${value}`,
        varied_parameter: dimension.parameter_name,
        varied_value: value,
        metricVolumeRef: derived.metricVolumeRef,
        selectors: derived.selectors,
      });
    }
  }
  const derivedRuns = await Promise.all(
    runSpecs.map((entry) =>
      buildDerivedYorkComparisonCase({
        caseId: entry.run_id,
        label: entry.label,
        metricVolumeRef: entry.metricVolumeRef,
        diagnosticLane: args.diagnosticLane,
      }),
    ),
  );
  const canonicalById = new Map(args.canonicalCaseInputs.map((entry) => [entry.case_id, entry]));
  const nhm2Input = canonicalById.get("nhm2_certified");
  const natarioInput = canonicalById.get("natario_control");
  const alcubierreInput = canonicalById.get("alcubierre_control");
  if (!nhm2Input || !natarioInput || !alcubierreInput) {
    throw new Error("parameter_sweep_case_inputs_missing");
  }
  const zeroInput = buildSyntheticZeroCalibrationCase(nhm2Input);
  const comparisonInputs: CalibrationInputCase[] = [
    zeroInput,
    toCalibrationInputCase(alcubierreInput, "canonical_control", "proof_pack_case"),
    toCalibrationInputCase(natarioInput, "canonical_control", "proof_pack_case"),
    ...derivedRuns.map((entry) =>
      toCalibrationInputCase(entry.inputCase, "parameter_sweep", "parameter_sweep_case"),
    ),
  ];
  const viewPolicies = buildSharedComparisonViewPolicies({
    inputCases: comparisonInputs,
    frameSize: args.frameSize,
  });
  const renderedPanel = await renderComparisonPanelCases({
    inputCases: comparisonInputs,
    viewPolicies,
    exportDirectory: args.exportDirectory,
    frameSize: args.frameSize,
    collisionPrefix: "parameter-sweep",
  });
  const featuresById = new Map<CalibrationPanelCaseId, CaseClassificationFeatures>();
  for (const inputCase of comparisonInputs) {
    featuresById.set(
      inputCase.case_id,
      buildCalibrationClassificationFeatures({
        inputCase,
        viewPolicies,
      }),
    );
  }
  const natarioFeatures = featuresById.get("natario_control");
  const alcubierreFeatures = featuresById.get("alcubierre_control");
  const flatFeatures = featuresById.get("flat_space_zero_theta");
  const baselineFeatures = featuresById.get(baselineRunId);
  if (!natarioFeatures || !alcubierreFeatures || !flatFeatures || !baselineFeatures) {
    throw new Error("parameter_sweep_reference_features_missing");
  }
  const blockingFindings = [...renderedPanel.blockingFindings];
  const collisionRecords = [...renderedPanel.collisionRecords];
  const runs: Nhm2ParameterSweepRunRecord[] = [];
  const baselineDistanceToAlc = computeReferenceDistance({
    contract: args.payload.diagnosticContract,
    reference: alcubierreFeatures,
    target: baselineFeatures,
  }).distance;
  for (const runSpec of runSpecs) {
    const comparisonInput = comparisonInputs.find((entry) => entry.case_id === runSpec.run_id);
    if (!comparisonInput) throw new Error(`parameter_sweep_input_missing:${runSpec.run_id}`);
    const runFeatures = featuresById.get(runSpec.run_id);
    if (!runFeatures) throw new Error(`parameter_sweep_features_missing:${runSpec.run_id}`);
    const scoring = scoreNhm2AgainstReferenceControls({
      contract: args.payload.diagnosticContract,
      alcubierreFeatures,
      natarioFeatures,
      nhm2Features: runFeatures,
    });
    const distanceToFlat = computeReferenceDistance({
      contract: args.payload.diagnosticContract,
      reference: flatFeatures,
      target: runFeatures,
    }).distance;
    const vsNatario = await buildGenericComparisonPairMetric({
      pairId: `${runSpec.run_id}-vs-natario_control`,
      lhsCase: comparisonInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "natario_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "parameter-sweep-metric",
      rawControlDistance: scoring.distance_to_low_expansion_reference,
    });
    const vsAlcubierre = await buildGenericComparisonPairMetric({
      pairId: `${runSpec.run_id}-vs-alcubierre_control`,
      lhsCase: comparisonInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === "alcubierre_control")!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "parameter-sweep-metric",
      rawControlDistance: scoring.distance_to_alcubierre_reference,
    });
    const vsFlat = await buildGenericComparisonPairMetric({
      pairId: `${runSpec.run_id}-vs-flat_space_zero_theta`,
      lhsCase: comparisonInput,
      rhsCase: zeroInput,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "parameter-sweep-metric",
      rawControlDistance: distanceToFlat,
    });
    const vsBaseline = await buildGenericComparisonPairMetric({
      pairId: `${runSpec.run_id}-vs-${baselineRunId}`,
      lhsCase: comparisonInput,
      rhsCase: comparisonInputs.find((entry) => entry.case_id === baselineRunId)!,
      viewPolicies,
      renderedByCaseView: renderedPanel.renderedByCaseView,
      exportDirectory: args.exportDirectory,
      frameSize: args.frameSize,
      collisionPrefix: "parameter-sweep-metric",
      rawControlDistance: computeReferenceDistance({
        contract: args.payload.diagnosticContract,
        reference: baselineFeatures,
        target: runFeatures,
      }).distance,
    });
    blockingFindings.push(
      ...vsNatario.blockingFindings,
      ...vsAlcubierre.blockingFindings,
      ...vsFlat.blockingFindings,
      ...vsBaseline.blockingFindings,
    );
    collisionRecords.push(
      ...vsNatario.collisionRecords,
      ...vsAlcubierre.collisionRecords,
      ...vsFlat.collisionRecords,
      ...vsBaseline.collisionRecords,
    );
    const primaryView = renderedPanel.caseExportByKey.get(`${runSpec.run_id}:york-surface-3p1`);
    const morphologyClass = classifySweepRunMorphology({
      features: runFeatures,
      scoring,
      distanceToFlat,
    });
    runs.push({
      run_id: runSpec.run_id,
      label: runSpec.label,
      status: "completed",
      varied_parameter: runSpec.varied_parameter,
      varied_value: runSpec.varied_value,
      metricT00Ref: runSpec.selectors.metricT00Ref,
      metricT00Source: runSpec.selectors.metricT00Source,
      metricRefHash:
        derivedRuns.find((entry) => entry.case_id === runSpec.run_id)?.metricRefHash ?? null,
      metricVolumeRefUrl: runSpec.metricVolumeRef.url,
      selectors: runSpec.selectors,
      morphologyClass,
      classificationScore: scoring,
      theta_abs_max: primaryView?.theta_abs_max ?? null,
      signed_lobe_summary: primaryView?.signed_lobe_summary ?? null,
      positive_count: primaryView?.positive_count ?? null,
      negative_count: primaryView?.negative_count ?? null,
      near_zero_fraction:
        primaryView && primaryView.sample_count > 0
          ? primaryView.near_zero_count / primaryView.sample_count
          : null,
      shell_activity: runFeatures.shell_map_activity,
      distance_to_natario: scoring.distance_to_low_expansion_reference,
      distance_to_alcubierre: scoring.distance_to_alcubierre_reference,
      distance_to_flat: distanceToFlat,
      caseViews: renderedPanel.caseExports.find((entry) => entry.case_id === runSpec.run_id)?.views ?? [],
      pairwiseMetrics: {
        vs_natario: vsNatario.metric,
        vs_alcubierre: vsAlcubierre.metric,
        vs_flat: vsFlat.metric,
        vs_baseline: vsBaseline.metric,
      },
    });
  }
  const uniqueBlockingFindings = Array.from(new Set(blockingFindings));
  if (uniqueBlockingFindings.length > 0) {
    throw new Error(
      `parameter_sweep_export_integrity_failed:${uniqueBlockingFindings.join(",")}:${collisionRecords
        .map((entry) => `${entry.record_id}:${entry.finding_code}`)
        .join(",")}`,
    );
  }
  const bestNatario = [...runs]
    .filter((entry) => entry.morphologyClass === "natario_like_low_expansion")
    .sort(
      (lhs, rhs) =>
        (lhs.distance_to_natario ?? Number.POSITIVE_INFINITY) -
        (rhs.distance_to_natario ?? Number.POSITIVE_INFINITY),
    )[0] ?? null;
  const bestAlcubierre = [...runs]
    .filter((entry) => entry.morphologyClass === "alcubierre_like_signed_lobe")
    .sort(
      (lhs, rhs) =>
        (lhs.distance_to_alcubierre ?? Number.POSITIVE_INFINITY) -
        (rhs.distance_to_alcubierre ?? Number.POSITIVE_INFINITY),
    )[0] ?? null;
  const boundaryLike = [...runs]
    .filter(
      (entry) =>
        entry.distance_to_natario != null && entry.distance_to_alcubierre != null,
    )
    .sort(
      (lhs, rhs) =>
        Math.abs((lhs.distance_to_natario ?? 0) - (lhs.distance_to_alcubierre ?? 0)) -
        Math.abs((rhs.distance_to_natario ?? 0) - (rhs.distance_to_alcubierre ?? 0)),
    )[0] ?? null;
  const degenerateExample = [...runs]
    .filter((entry) => entry.morphologyClass === "flat_or_degenerate")
    .sort(
      (lhs, rhs) =>
        (lhs.distance_to_flat ?? Number.POSITIVE_INFINITY) -
        (rhs.distance_to_flat ?? Number.POSITIVE_INFINITY),
    )[0] ?? null;
  const parameterSensitivityRanking = sweepDimensions.map((dimension) => {
    const strongest = [...runs]
      .filter((entry) => entry.varied_parameter === dimension.parameter_name)
      .sort(
        (lhs, rhs) =>
          (baselineDistanceToAlc ?? Number.NEGATIVE_INFINITY) -
            (lhs.distance_to_alcubierre ?? Number.POSITIVE_INFINITY) <
          (baselineDistanceToAlc ?? Number.NEGATIVE_INFINITY) -
            (rhs.distance_to_alcubierre ?? Number.POSITIVE_INFINITY)
            ? 1
            : -1,
      )[0] ?? null;
    return {
      parameter_name: dimension.parameter_name,
      strongest_run_id: strongest?.run_id ?? null,
      strongest_movement_class: strongest?.morphologyClass ?? null,
      strongest_distance_gain_toward_alcubierre:
        strongest == null
          ? null
          : safeSubtract(baselineDistanceToAlc, strongest.distance_to_alcubierre),
    };
  });
  const dominantMorphologyDrivers = parameterSensitivityRanking
    .filter((entry) => (entry.strongest_distance_gain_toward_alcubierre ?? 0) > 0)
    .sort(
      (lhs, rhs) =>
        (rhs.strongest_distance_gain_toward_alcubierre ?? 0) -
        (lhs.strongest_distance_gain_toward_alcubierre ?? 0),
    )
    .map((entry) => entry.parameter_name)
    .slice(0, 3);
  const alcubierreLikeReachable: "yes" | "no" | "unclear" = bestAlcubierre
    ? "yes"
    : runs.length > 1
      ? "no"
      : "unclear";
  const sweepVerdict: Nhm2ParameterSweepArtifact["sweepVerdict"] =
    alcubierreLikeReachable === "yes"
      ? "alcubierre_like_reachable"
      : alcubierreLikeReachable === "no"
        ? "alcubierre_like_not_found"
        : "alcubierre_like_unclear";
  const bestRunClass =
    bestAlcubierre?.morphologyClass ??
    bestNatario?.morphologyClass ??
    boundaryLike?.morphologyClass ??
    null;
  const recommendedNextAction =
    alcubierreLikeReachable === "yes"
      ? "Focus follow-up tuning on the small region of parameter space that moved closest to the Alcubierre control while preserving the Lane A contract."
      : alcubierreLikeReachable === "no"
        ? "A bounded selector sweep did not reach the Alcubierre-like class; prioritize NHM2 source/coupling redesign over more blind tuning."
        : "Sweep evidence is too narrow to resolve reachability; expand the sweep only after reviewing ablation results.";
  const artifactBase: Nhm2ParameterSweepArtifact = {
    artifactType: "nhm2_parameter_sweep/v1",
    generatedOn: args.payload.generatedOn,
    generatedAt: new Date().toISOString(),
    boundaryStatement:
      "This bounded parameter sweep varies only active NHM2 brick selectors under the same authoritative Lane A contract used for canonical calibration and fixed-scale comparison.",
    sourceAuditArtifact: normalizePath(args.sourceAuditArtifactPath),
    canonicalCalibrationArtifactPath: normalizePath(args.canonicalCalibrationArtifactPath),
    ablationArtifactPath: normalizePath(args.ablationArtifactPath),
    exportDirectory: normalizePath(args.exportDirectory),
    comparisonContract: args.canonicalCalibrationArtifact.comparisonContract,
    sweepDimensions,
    baselineRunId,
    runs,
    representativeRunIds: {
      baseline: baselineRunId,
      best_natario_like: bestNatario?.run_id ?? null,
      best_alcubierre_like: bestAlcubierre?.run_id ?? null,
      boundary_like: boundaryLike?.run_id ?? null,
      degenerate_example: degenerateExample?.run_id ?? null,
    },
    parameterSensitivityRanking,
    sweepVerdict,
    bestRunClass,
    alcubierreLikeReachable,
    dominantMorphologyDrivers,
    recommendedNextAction,
    notes: [
      `baseline_distance_to_natario=${runs.find((entry) => entry.run_id === baselineRunId)?.distance_to_natario ?? "null"}`,
      `baseline_distance_to_alcubierre=${runs.find((entry) => entry.run_id === baselineRunId)?.distance_to_alcubierre ?? "null"}`,
      `visual_metric_source_stage=${args.canonicalCalibrationArtifact.comparisonContract.visualMetricSourceStage}`,
      "Parameter sweep runs are OAT perturbations around the current NHM2 selector bundle, not a model redesign.",
    ],
  };
  return {
    ...artifactBase,
    checksum: crypto
      .createHash("sha256")
      .update(stableStringify({ ...artifactBase, generatedAt: undefined, checksum: undefined }))
      .digest("hex"),
  };
};

export const renderNhm2ParameterSweepMarkdown = (
  payload: Nhm2ParameterSweepArtifact,
): string => {
  const dimensionRows = payload.sweepDimensions
    .map(
      (entry) =>
        `| ${entry.parameter_name} | ${entry.baseline_value} | ${entry.sweep_values.join(", ")} | ${entry.sampling_strategy} | ${entry.rationale} |`,
    )
    .join("\n");
  const runRows = payload.runs
    .map(
      (entry) =>
        `| ${entry.run_id} | ${entry.varied_parameter} | ${entry.varied_value ?? "baseline"} | ${entry.morphologyClass} | ${entry.distance_to_natario ?? "null"} | ${entry.distance_to_alcubierre ?? "null"} | ${entry.distance_to_flat ?? "null"} | ${entry.signed_lobe_summary ?? "null"} | ${entry.metricVolumeRefUrl ?? "null"} |`,
    )
    .join("\n");
  const notes = payload.notes.length
    ? payload.notes.map((entry) => `- ${entry}`).join("\n")
    : "- none";
  return `# NHM2 Parameter Sweep (${payload.generatedOn})

"${payload.boundaryStatement}"

## Comparison Contract
| field | value |
|---|---|
| laneUsed | ${payload.comparisonContract.laneUsed} |
| observer | ${payload.comparisonContract.observer} |
| foliation | ${payload.comparisonContract.foliation} |
| thetaDefinition | ${payload.comparisonContract.thetaDefinition} |
| fixedScalePolicy | ${payload.comparisonContract.fixedScalePolicy} |
| visualMetricSourceStage | ${payload.comparisonContract.visualMetricSourceStage} |
| exportDirectory | ${payload.exportDirectory} |

## Sweep Dimensions
| parameter_name | baseline_value | sweep_values | sampling_strategy | rationale |
|---|---:|---|---|---|
${dimensionRows}

## Runs
| run_id | varied_parameter | varied_value | morphologyClass | distance_to_natario | distance_to_alcubierre | distance_to_flat | signed_lobe_summary | metricVolumeRefUrl |
|---|---|---:|---|---:|---:|---:|---|---|
${runRows}

## Verdict
| field | value |
|---|---|
| sweepVerdict | ${payload.sweepVerdict} |
| bestRunClass | ${payload.bestRunClass ?? "null"} |
| alcubierreLikeReachable | ${payload.alcubierreLikeReachable} |
| dominantMorphologyDrivers | ${payload.dominantMorphologyDrivers.join(", ") || "none"} |
| recommendedNextAction | ${payload.recommendedNextAction} |

## Notes
${notes}
`;
};

